eInfo.ShowStatutes && charge.ChargeOffense.Statute --><roa-charge-data-column ng-if=\\"::roaSection.chargeInfo.ShowStatutes &amp;&amp; charge.ChargeOffense.Statute\\" label=\\"Statute\\" data-value=\\"G.S. 20-141(M)\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Statute\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      G.S. 20-141(M)\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::roaSection.chargeInfo.ShowStatutes && charge.ChargeOffense.Statute -->\\n        </td>\\n        <td>\\n          <!-- ngIf: ::charge.ChargeOffense.Degree --><roa-charge-data-column ng-if=\\"::charge.ChargeOffense.Degree\\" label=\\"Degree\\" data-value=\\"INF\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Degree\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      INF\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::charge.ChargeOffense.Degree -->\\n        </td>\\n        <td>\\n          <!-- ngIf: ::charge.OffenseDate --><roa-charge-data-column ng-if=\\"::charge.OffenseDate\\" label=\\"Offense Date\\" data-value=\\"10/11/2025\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Offense Date\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      10/11/2025\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::charge.OffenseDate -->\\n        </td>\\n        <td>\\n          <!-- ngIf: ::charge.FiledDate --><roa-charge-data-column ng-if=\\"::charge.FiledDate\\" label=\\"Filed Date\\" data-value=\\"10/14/2025\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Filed Date\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      10/14/2025\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::charge.FiledDate -->\\n        </td>\\n      </tr>\\n\\n      <tr hide-xs=\\"\\" hide-sm=\\"\\" class=\\"hide-sm hide-xs ng-scope\\">\\n        <td class=\\"roa-text-right\\">\\n          <!-- ngIf: ::charge.CurrChargeNum --><span ng-if=\\"::charge.CurrChargeNum\\" class=\\"ng-binding ng-scope\\">&nbsp;1.</span><!-- end ngIf: ::charge.CurrChargeNum -->\\n        </td>\\n        <td>\\n          <div>\\n            <span class=\\"ng-binding\\">FAILURE TO REDUCE SPEED</span>\\n            <!-- ngIf: ::charge.ChargeOffense.GOC -->\\n          </div>\\n        </td>\\n        <td>\\n          <!-- ngIf: ::roaSection.chargeInfo.ShowCitationNumbers && charge.CitationNumber --><roa-charge-data-column ng-if=\\"::roaSection.chargeInfo.ShowCitationNumbers &amp;&amp; charge.CitationNumber\\" label=\\"Citation\\" data-value=\\"73503H1\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Citation\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      73503H1\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::roaSection.chargeInfo.ShowCitationNumbers && charge.CitationNumber -->\\n        </td>\\n        <td>\\n          <!-- ngIf: ::roaSection.chargeInfo.ShowStatutes && charge.ChargeOffense.Statute --><roa-charge-data-column ng-if=\\"::roaSection.chargeInfo.ShowStatutes &amp;&amp; charge.ChargeOffense.Statute\\" label=\\"Statute\\" data-value=\\"G.S. 20-141(M)\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Statute\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      G.S. 20-141(M)\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::roaSection.chargeInfo.ShowStatutes && charge.ChargeOffense.Statute -->\\n        </td>\\n        <td>\\n          <!-- ngIf: ::charge.ChargeOffense.Degree --><roa-charge-data-column ng-if=\\"::charge.ChargeOffense.Degree\\" label=\\"Degree\\" data-value=\\"INF\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Degree\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      INF\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::charge.ChargeOffense.Degree -->\\n        </td>\\n        <td>\\n          <!-- ngIf: ::charge.OffenseDate --><roa-charge-data-column ng-if=\\"::charge.OffenseDate\\" label=\\"Offense Date\\" data-value=\\"10/11/2025\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Offense Date\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      10/11/2025\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::charge.OffenseDate -->\\n        </td>\\n        <td>\\n          <!-- ngIf: ::charge.FiledDate --><roa-charge-data-column ng-if=\\"::charge.FiledDate\\" label=\\"Filed Date\\" data-value=\\"10/14/2025\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Filed Date\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      10/14/2025\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::charge.FiledDate -->\\n        </td>\\n      </tr>\\n\\n      <!-- Additional Statutes -->\\n      <!-- ngRepeat: additionalStatute in ::charge.ChargeOffense.AdditionalStatutes track by $index -->\\n\\n      <tr class=\\"ng-scope\\">\\n        <td></td>\\n        <td colspan=\\"4\\">\\n          <div class=\\"roa-indent\\">\\n\\n            <!-- Disposition/Level of Sentence -->\\n            <!-- ngIf: ::charge.Disposition.length -->\\n\\n            <!-- Arrest, Rearrest, and Offense Reports -->\\n            <div>\\n\\n              <!-- Arrests -->\\n              <!-- ngIf: ::charge.Arrests.length -->\\n\\n              <!-- Rearrests -->\\n              <!-- ngIf: ::charge.Rearrests.length -->\\n\\n              <!-- Offense Reports -->\\n              <!-- ngIf: ::charge.FilingAgencyDescription || charge.OffenseReportControlNumber --><div ng-if=\\"::charge.FilingAgencyDescription || charge.OffenseReportControlNumber\\" class=\\"roa-pad-top ng-scope\\">\\n                <div>Offense Reports</div>\\n                <div class=\\"roa-indent-2\\">\\n                  <!-- ngIf: ::charge.OffenseReportControlNumber -->\\n                  <!-- ngIf: ::charge.FilingAgencyDescription --><div class=\\"roa-data ng-scope ng-isolate-scope\\" label=\\"Agency:\\" ng-if=\\"::charge.FilingAgencyDescription\\">\\n    <!-- ngIf: ::label --><div class=\\"roa-label roa-inline roa-align-top ng-binding ng-scope\\" ng-if=\\"::label\\" ng-bind=\\"::label\\">Agency:</div><!-- end ngIf: ::label -->\\n    <!-- ngIf: ::value -->\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude=\\"\\">\\n                    <div class=\\"ng-binding ng-scope\\">\\n                      State Highway Patrol Troop H District 5\\n                    </div>\\n                    <!-- ngRepeat: address in ::charge.FilingAgencyAddress --><!-- ngIf: ::charge.FilingAgencyAddress.length --><div ng-if=\\"::charge.FilingAgencyAddress.length\\" ng-repeat=\\"address in ::charge.FilingAgencyAddress\\" class=\\"ng-binding ng-scope\\">\\n                      12101 Mt. Holly-Huntersville Road\\n                    </div><!-- end ngIf: ::charge.FilingAgencyAddress.length --><!-- end ngRepeat: address in ::charge.FilingAgencyAddress --><!-- ngIf: ::charge.FilingAgencyAddress.length --><div ng-if=\\"::charge.FilingAgencyAddress.length\\" ng-repeat=\\"address in ::charge.FilingAgencyAddress\\" class=\\"ng-binding ng-scope\\">\\n                      Hunetersville, NC, 18078\\n                    </div><!-- end ngIf: ::charge.FilingAgencyAddress.length --><!-- end ngRepeat: address in ::charge.FilingAgencyAddress -->\\n                  </div>\\n  </div><!-- end ngIf: ::charge.FilingAgencyDescription -->\\n                </div>\\n              </div><!-- end ngIf: ::charge.FilingAgencyDescription || charge.OffenseReportControlNumber -->\\n\\n            </div>\\n\\n            <!-- ngIf: ::charge.ChargeOffense.AdditionalChargeComponentInstances.length --><div style=\\"padding-left:3rem;\\" ng-if=\\"::charge.ChargeOffense.AdditionalChargeComponentInstances.length\\" class=\\"print-padding ng-scope\\">\\n              <!-- ngRepeat: additionalChargeComponent in ::charge.ChargeOffense.AdditionalChargeComponentInstances --><div ng-repeat=\\"additionalChargeComponent in ::charge.ChargeOffense.AdditionalChargeComponentInstances\\" ng-switch=\\"\\" on=\\"additionalChargeComponent.AdditionalChargeComponentId\\" class=\\"ng-scope\\">\\n\\n                <!-- The Certify To DPS component (AddChargeComponentID='3') -->\\n                <!-- ngSwitchWhen: 3 -->\\n\\n                <!-- The Minnesota Offense Codes component (AddChargeComponentID='4') -->\\n                <!-- ngSwitchWhen: 4 -->\\n\\n                <!-- The DPS Group component (AddChargeComponentID='16') -->\\n                <!-- ngSwitchWhen: 16 -->\\n\\n                <!-- The Predatory Offender Registration component (AddChargeComponentID='17') -->\\n                <!-- ngSwitchWhen: 17 -->\\n\\n                <!-- The Targeted Misdemeanor component (AddChargeComponentID='18') -->\\n                <!-- ngSwitchWhen: 18 -->\\n\\n                <!-- The Wildlife fine calculation component (AddChargeComponentID='20') -->\\n                <!-- ngSwitchWhen: 20 -->\\n\\n                <!-- The Speeding Fine Calculation component - Flat Rate - MN (AddChargeComponentID='21') -->\\n                <!-- ngSwitchWhen: 21 -->\\n\\n                <!-- The Overweight fine calculation component (AddChargeComponentID='22') -->\\n                <!-- ngSwitchWhen: 22 -->\\n\\n                <!-- The State Share component (AddChargeComponentID='26') -->\\n                <!--The State Share label is removed in Jira ODY-259438 for MN.  A configuration option will likely be added\\n        to the persona case summary options in the future -->\\n                <!-- <span ng-switch-when=\\"26\\">\\n        State Share\\n      </span>-->\\n                <!-- The Sheriff's Contingency calculation component (AddChargeComponentID='27') -->\\n                <!-- ngSwitchWhen: 27 -->\\n\\n                <!-- The Address of Offense component (AddChargeComponentID='34') -->\\n                <!-- ngSwitchWhen: 34 -->\\n\\n                <!-- The Drug Type component (AddChargeComponentID='37') -->\\n                <!-- ngSwitchWhen: 37 -->\\n\\n                <!-- The Charge Qualifier -  Weapons component (AddChargeComponentID='41') -->\\n                <!-- ngSwitchWhen: 41 -->\\n\\n                <!-- The Charge Qualifier - Amount component (AddChargeComponentID='44') -->\\n                <!-- ngSwitchWhen: 44 -->\\n\\n                <!-- The DUI Group component (AddChargeComponentID='46') -->\\n                <!-- ngSwitchWhen: 46 -->\\n\\n                <!-- The Report To DNR component (AddChargeComponentID='48') -->\\n                <!-- ngSwitchWhen: 48 -->\\n\\n                <!-- The DA Charging Paragraph component (AddChargeComponentID='53') -->\\n                <!-- ngSwitchWhen: 53 -->\\n\\n                <!-- The DUI Group component (AddChargeComponentID='54') -->\\n                <!-- ngSwitchWhen: 54 -->\\n\\n                <!-- The Speeding Group component GA (AddChargeComponentID='55') -->\\n                <!-- ngSwitchWhen: 55 -->\\n\\n                <!-- The Speeding Fine Calculation component GA, FL (AddChargeComponentID='56') -->\\n                <!-- ngSwitchWhen: 56 -->\\n\\n                <!-- The Hot Check Fields component (AddChargeComponentID='58') -->\\n                <!-- ngSwitchWhen: 58 -->\\n\\n                <!-- The Overweight Fine Calculation (Rated/Actual) component (AddChargeComponentID='59') -->\\n                <!-- ngSwitchWhen: 59 -->\\n\\n                <!-- The Blood Alcohol Content component (AddChargeComponentID='60') -->\\n                <!-- ngSwitchWhen: 60 -->\\n\\n                <!-- The Predatory Offender component (AddChargeComponentID='61') -->\\n                <!-- ngSwitchWhen: 61 -->\\n\\n                <!-- The Address of Offense component (AddChargeComponentID='62') -->\\n                <!-- ngSwitchWhen: 62 -->\\n\\n                <!-- The Drug Amount component (AddChargeComponentID='63') -->\\n                <!-- ngSwitchWhen: 63 -->\\n\\n                <!-- The Blood Alcohol Content Status component (AddChargeComponentID='64') -->\\n                <!-- ngSwitchWhen: 64 -->\\n\\n                <!-- The Blood Alcohol Content Level component (AddChargeComponentID='65') -->\\n                <!-- ngSwitchWhen: 65 -->\\n\\n                <!-- The Speeding Fine Calculation component (AddChargeComponentID='66') -->\\n                <!-- ngSwitchWhen: 66 -->\\n\\n                <!-- The Send to DOT component (AddChargeComponentID='67') -->\\n                <!-- ngSwitchWhen: 67 -->\\n\\n                <!-- MN 3rd Violation Enhancement To Misd (AddChargeComponentID='68') -->\\n                <!-- ngSwitchWhen: 68 -->\\n\\n                <!-- NC Implied Consent -->\\n               <!-- ngIf: ::additionalChargeComponent.AdditionalChargeComponentCode == 'NCIMPLCON' -->\\n              </div><!-- end ngRepeat: additionalChargeComponent in ::charge.ChargeOffense.AdditionalChargeComponentInstances -->\\n            </div><!-- end ngIf: ::charge.ChargeOffense.AdditionalChargeComponentInstances.length -->\\n\\n            <!-- Original (of an amended) Charge -->\\n            <!-- ngIf: ::charge.OriginalChargeOffense -->\\n\\n            <!-- Charge Track and Sequence Numbers -->\\n            <!-- ngIf: ::roaSection.chargeInfo.ChargeTrackNumberLabel && charge.ChargeTrackingNumber -->\\n\\n            <!-- ngIf: ::roaSection.chargeInfo.ChargeSequenceNumberLabel && charge.ChargeSequenceNumber -->\\n\\n          </div>\\n        </td>\\n      </tr>\\n      <tr ng-repeat-end=\\"\\" class=\\"ng-scope\\"></tr><!-- end ngRepeat: charge in filteredCharges = (roaSection.chargeInfo.Charges | filter: { PartyId: partyConfig.PartyId }) -->\\n    </tbody><!-- end ngRepeat: partyConfig in ::roaSection.chargeInfo.PartyConfigs -->\\n  </table>\\n\\n</div><!-- end ngIf: ::roaSection.chargeInfo.ShowOffenses -->\\n\\n</ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: ::roaSection.relationsInfo.ShowRelations --><div class=\\"roa-subsection ng-scope\\" ng-if=\\"::roaSection.relationsInfo.ShowRelations\\">\\n\\n  <div class=\\"roa-subsection-heading\\">\\n    Related Cases\\n  </div>\\n\\n  <!-- ngIf: ::roaSection.relationsInfo.LeadCases.length -->\\n\\n  <!-- ngIf: ::roaSection.relationsInfo.SubordinateCases.length -->\\n\\n  <!-- ngIf: ::roaSection.relationsInfo.FamilyLeadCases.length -->\\n\\n  <!-- ngIf: ::roaSection.relationsInfo.OtherCases.length -->\\n</div><!-- end ngIf: ::roaSection.relationsInfo.ShowRelations -->\\n</ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: ::roaSection.lowerCourtCasesInfo.ShowLowerCourtCases -->\\n</ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: ::roaSection.dispositionInfo.ShowDispositions -->\\n</ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: ::roaSection.warrantInfo.ShowWarrants -->\\n</ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: ::roaSection.bondInfo.ShowBonds --></ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: data.Options.ShowGroundsForDivorce == '1' && roaSection.divorceInfo != null && roaSection.divorceInfo != undefined && roaSection.divorceInfo.GroundsForDivorce.length > 0 --></ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates -->\\n</div>\\n\\n</ng-include>\\n    </md-card-content>\\n  </md-card>\\n</section><!-- end ngIf: roaSection.showSection --></div><!-- end ngIf: ::data.roaSections.caseInformation -->\\n      <!-- ngIf: ::data.roaSections.assignmentInformation --><div ng-include-template=\\"Areas/RegisterOfActions/Views/ROA/Templates/RoA_Section_Template.html\\" ng-include-variables=\\"{roaSection: data.roaSections.assignmentInformation, data: data, $scope: this}\\" ng-if=\\"::data.roaSections.assignmentInformation\\" class=\\"ng-scope ng-isolate-scope\\" style=\\"\\"><!-- ngIf: roaSection.showSection --><section ng-if=\\"roaSection.showSection\\" class=\\"ng-scope\\">\\n  <md-card class=\\"no-print-section-border md-tyler-default-theme-theme\\">\\n    <md-toolbar class=\\"roa-section-header md-tyler-default-theme-theme\\" data-header-text=\\"Assignment Information\\" id=\\"assignment-info\\" ng-class=\\"::{'no-print-section-header': skipHeader}\\">\\n    <div class=\\"md-toolbar-tools\\">\\n      <!-- ngIf: $scope.selectedSection === $args.id -->\\n      <h1>\\n        <span class=\\"header-text ng-binding\\">Assignment Information</span>\\n      </h1>\\n    </div>\\n  </md-toolbar>\\n    <md-card-content class=\\"roa-section-content\\">\\n      <!-- In general, the sections will work like this:\\n      - Initial load: showSection = false. nothing shows (exception - basic case info always has showSection = true and sets loading = true to show an indicator)\\n      - Error on load: showSection = true, loading = false, error = error text. Section is shown with error text.\\n      - Load success, but no data: showSection = false. nothing shows\\n      - Data exists: showSection = true, loading = false, error = null.\\n      -->\\n      <!-- ngIf: roaSection.loading -->\\n      <!-- ngIf: roaSection.error -->\\n      <!-- ngInclude: undefined --><ng-include ng-show=\\"!roaSection.loading &amp;&amp; !roaSection.error\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + roaSection.template\\" class=\\"ng-scope\\" aria-hidden=\\"false\\" style=\\"\\"><div class=\\"ng-scope\\">\\n  <div layout-gt-sm=\\"row\\" class=\\"layout-gt-sm-row\\">\\n    <div flex=\\"10\\" class=\\"flex-10\\"></div>\\n    <div flex=\\"90\\" class=\\"flex-90\\">\\n\\n      <div class=\\"roa-text-bold\\">Current Case Assignment</div>\\n\\n\\n      <div class=\\"roa-data-table roa-pad-bottom\\">\\n        <div class=\\"roa-data ng-isolate-scope\\" label=\\"Case Number\\">\\n    <!-- ngIf: ::label --><div class=\\"roa-label roa-inline roa-align-top ng-binding ng-scope\\" ng-if=\\"::label\\" ng-bind=\\"::label\\">Case Number</div><!-- end ngIf: ::label -->\\n    <!-- ngIf: ::value -->\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude=\\"\\"><span class=\\"ng-binding ng-scope\\">\\n          25IF012559-590\\n        </span></div>\\n  </div>\\n\\n        <div class=\\"roa-data ng-isolate-scope\\" label=\\"Court\\">\\n    <!-- ngIf: ::label --><div class=\\"roa-label roa-inline roa-align-top ng-binding ng-scope\\" ng-if=\\"::label\\" ng-bind=\\"::label\\">Court</div><!-- end ngIf: ::label -->\\n    <!-- ngIf: ::value -->\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude=\\"\\"><span class=\\"ng-binding ng-scope\\">\\n          Mecklenburg District Court\\n        </span></div>\\n  </div>\\n\\n        <!-- ngIf: ::data.Options.CaseAssignmentTimestamp == '1' -->\\n\\n        <!-- ngIf: ::data.Options.CaseAssignmentTimestamp != '1' --><div class=\\"roa-data ng-scope ng-isolate-scope\\" label=\\"Date Assigned\\" ng-if=\\"::data.Options.CaseAssignmentTimestamp != '1'\\">\\n    <!-- ngIf: ::label --><div class=\\"roa-label roa-inline roa-align-top ng-binding ng-scope\\" ng-if=\\"::label\\" ng-bind=\\"::label\\">Date Assigned</div><!-- end ngIf: ::label -->\\n    <!-- ngIf: ::value -->\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude=\\"\\"><span class=\\"ng-binding ng-scope\\">\\n          10/14/2025\\n        </span></div>\\n  </div><!-- end ngIf: ::data.Options.CaseAssignmentTimestamp != '1' -->\\n\\n        <!-- ngIf: ::roaSection.assignmentInfo.CurrentCaseAssignment.JudicialOfficer -->\\n\\n        <!-- ngIf: ::roaSection.assignmentInfo.CurrentMagistrateAssignment.Description -->\\n      </div>\\n\\n      <!-- ngRepeat: assignment in ::roaSection.assignmentInfo.CaseAssignmentHistory -->\\n\\n    </div>\\n  </div>\\n\\n  <!-- ngRepeat: assignment in ::roaSection.assignmentInfo.MagistrateAssignmentHistory -->\\n\\n\\n  <!-- ngRepeat: officer in ::roaSection.assignmentInfo.Appellate.AppellateJudicialOfficerAssignments | orderBy:['Seniority', 'JudicialOfficerId.Description', 'AddedDate'] -->\\n\\n</div>\\n</ng-include>\\n    </md-card-content>\\n  </md-card>\\n</section><!-- end ngIf: roaSection.showSection --></div><!-- end ngIf: ::data.roaSections.assignmentInformation -->\\n      <!-- ngIf: ::data.roaSections.partySection --><div ng-include-template=\\"Areas/RegisterOfActions/Views/ROA/Templates/RoA_Section_Template.html\\" ng-include-variables=\\"{roaSection: data.roaSections.partySection, data: data, $scope: this}\\" ng-if=\\"::data.roaSections.partySection\\" class=\\"ng-scope ng-isolate-scope\\"><!-- ngIf: roaSection.showSection --><section ng-if=\\"roaSection.showSection\\" class=\\"ng-scope\\" style=\\"\\">\\n  <md-card class=\\"no-print-section-border md-tyler-default-theme-theme\\">\\n    <md-toolbar class=\\"roa-section-header md-tyler-default-theme-theme\\" data-header-text=\\"Party Information\\" id=\\"party-info\\" ng-class=\\"::{'no-print-section-header': skipHeader}\\">\\n    <div class=\\"md-toolbar-tools\\">\\n      <!-- ngIf: $scope.selectedSection === $args.id -->\\n      <h1>\\n        <span class=\\"header-text ng-binding\\">Party Information</span>\\n      </h1>\\n    </div>\\n  </md-toolbar>\\n    <md-card-content class=\\"roa-section-content\\">\\n      <!-- In general, the sections will work like this:\\n      - Initial load: showSection = false. nothing shows (exception - basic case info always has showSection = true and sets loading = true to show an indicator)\\n      - Error on load: showSection = true, loading = false, error = error text. Section is shown with error text.\\n      - Load success, but no data: showSection = false. nothing shows\\n      - Data exists: showSection = true, loading = false, error = null.\\n      -->\\n      <!-- ngIf: roaSection.loading -->\\n      <!-- ngIf: roaSection.error -->\\n      <!-- ngInclude: undefined --><ng-include ng-show=\\"!roaSection.loading &amp;&amp; !roaSection.error\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + roaSection.template\\" class=\\"ng-scope\\" aria-hidden=\\"false\\" style=\\"\\"><table class=\\"roa-table td-pad-5 ng-scope\\">\\n  <colgroup>\\n    <col style=\\"width:80px\\"> <!-- connection type -->\\n    <col> <!-- party info -->\\n    <col> <!-- attorney info -->\\n  </colgroup>\\n  <!-- ngRepeat: connectionType in roaSection.casePartyConnectionsTypes --><tbody ng-repeat=\\"connectionType in roaSection.casePartyConnectionsTypes\\" class=\\"ng-scope\\">\\n\\n  <!-- ngIf: ::$first && roaSection.partyInfo.ShowAttorneyHeader && roaSection.partyInfo.ShowOnlyLeadAttornies -->\\n  \\n  <!-- ngRepeat: party in ::roaSection.getPartiesByConnectionTypeId(connectionType.codeId) --><tr ng-repeat=\\"party in ::roaSection.getPartiesByConnectionTypeId(connectionType.codeId)\\" class=\\"roa-party-row roa-pad-b-10 ng-scope\\">\\n\\n    <td class=\\"roa-text-bold\\">\\n      <!-- ngIf: ::$first --><div ng-if=\\"::$first\\" class=\\"ng-binding ng-scope\\">State</div><!-- end ngIf: ::$first -->\\n    </td>\\n    <!-- ngIf: ::!(roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount)) -->\\n    <!-- ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) --><td ng-if=\\"::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount)\\" class=\\"ng-scope\\">\\n      <table class=\\"roa-table roa-inline\\">\\n        <tbody><tr>\\n          <!-- ngIf: ::party.PriorJailings -->\\n          <!-- ngIf: ::party.InJail -->\\n          <!-- ngIf: ::party.JailWeekenderIn -->\\n          <!-- ngIf: ::party.JailWeekenderOut -->\\n          <!-- ngIf: ::party.HasActiveWarrants && data.WarrantInformation.ShowWarrantHeaderIcon -->\\n          <td ng-class=\\"::roaSection.isInactive(party, connectionType.codeId) ? 'roa-text-italic' : 'roa-text-bold'\\" class=\\"ng-binding roa-text-bold\\">\\n            STATE OF NORTH CAROLINA \\n          </td>\\n        </tr>\\n      </tbody></table>\\n\\n      <!-- ngIf: ::party.AdditionalNames.length -->\\n\\n\\n      <!-- ngIf: ::party.PartyStyle -->\\n\\n      <!-- ngRepeat: address in ::party.Addresses --><!-- ngIf: ::party.Addresses.length --><div ng-if=\\"::party.Addresses.length\\" class=\\"roa-indent ng-scope\\" ng-repeat=\\"address in ::party.Addresses\\">\\n        <div ng-class=\\"party.CasePartyConnection.Inactive == 1 ? 'roa-text-italic' : ''\\">\\n    <!-- ngIf: ::address.ConfidentialAddress -->\\n    <!-- ngIf: ::!(address.ConfidentialAddress) --><div ng-if=\\"::!(address.ConfidentialAddress)\\" ng-switch=\\"address.AddressType\\" class=\\"ng-scope\\">\\n\\n      <!-- ngSwitchWhen: 0 -->\\n\\n      <!-- ngSwitchWhen: 1 -->\\n\\n      <!-- ngSwitchWhen: 2 --><div ng-switch-when=\\"2\\" class=\\"ng-scope\\">\\n        <!-- ngIf: ::address.AddressLine1 --><div ng-if=\\"::address.AddressLine1\\" class=\\"ng-binding ng-scope\\">\\n          State of North Carolina\\n        </div><!-- end ngIf: ::address.AddressLine1 -->\\n        <!-- ngIf: ::address.AddressLine2 -->\\n        <!-- ngIf: ::address.AddressLine3 -->\\n        <!-- ngIf: ::address.AddressLine4 -->\\n      </div><!-- end ngSwitchWhen: -->\\n    </div><!-- end ngIf: ::!(address.ConfidentialAddress) -->\\n  </div>\\n      </div><!-- end ngIf: ::party.Addresses.length --><!-- end ngRepeat: address in ::party.Addresses -->\\n\\n      <div class=\\"roa-indent\\" ng-class=\\"::roaSection.isInactive(party, connectionType.codeId) ? 'roa-text-italic' : ''\\">\\n        <!-- ngIf: ::party.Race --><div ng-if=\\"::party.Race\\" class=\\"ng-binding ng-scope\\">\\n          Other\\n        </div><!-- end ngIf: ::party.Race -->\\n\\n        <!-- ngIf: ::party.Gender -->\\n\\n        <div>\\n          <!-- ngIf: ::party.Height && !party.IsAUSCulture -->\\n\\n          <!-- ngIf: ::party.Height && party.IsAUSCulture -->\\n\\n          <!-- ngIf: ::party.Weight && !party.IsAUSCulture -->\\n\\n          <!-- ngIf: ::party.Weight && party.IsAUSCulture -->\\n        </div>\\n\\n        <div>\\n          <!-- ngIf: ::party.DateOfBirth -->\\n\\n          <!-- ngIf: ::party.DateOfDeath -->\\n\\n          <!-- ngIf: ::$scope.greaterThan(party.Age, 0) -->\\n        </div>\\n\\n\\n        <div>\\n          <!-- ngIf: ::party.DriversLicenseState || party.DriversLicenseNumber -->\\n          <!-- ngIf: ::party.StateIdentificationNumber -->\\n        </div>\\n\\n      </div>\\n\\n\\n      <div ng-class=\\"::party.RemovedReason ? 'roa-text-italic' : ''\\" class=\\"roa-indent\\">\\n        <!-- ngIf: ::party.RemovedDate -->\\n        <!-- ngIf: ::party.RemovedReason -->\\n      </div>\\n\\n      <!-- ngIf: ::party.OtherAgencies.length -->\\n\\n    </td><!-- end ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) -->\\n\\n    <!-- ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) --><td ng-if=\\"::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount)\\" class=\\"ng-scope\\">\\n      <!-- ngRepeat: attorney in ::party.CasePartyAttorneys -->\\n    </td><!-- end ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) -->\\n\\n\\n  </tr><!-- end ngRepeat: party in ::roaSection.getPartiesByConnectionTypeId(connectionType.codeId) -->\\n\\n\\n  </tbody><!-- end ngRepeat: connectionType in roaSection.casePartyConnectionsTypes --><tbody ng-repeat=\\"connectionType in roaSection.casePartyConnectionsTypes\\" class=\\"ng-scope\\">\\n\\n  <!-- ngIf: ::$first && roaSection.partyInfo.ShowAttorneyHeader && roaSection.partyInfo.ShowOnlyLeadAttornies -->\\n  \\n  <!-- ngRepeat: party in ::roaSection.getPartiesByConnectionTypeId(connectionType.codeId) --><tr ng-repeat=\\"party in ::roaSection.getPartiesByConnectionTypeId(connectionType.codeId)\\" class=\\"roa-party-row roa-pad-b-10 ng-scope\\">\\n\\n    <td class=\\"roa-text-bold\\">\\n      <!-- ngIf: ::$first --><div ng-if=\\"::$first\\" class=\\"ng-binding ng-scope\\">Defendant</div><!-- end ngIf: ::$first -->\\n    </td>\\n    <!-- ngIf: ::!(roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount)) -->\\n    <!-- ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) --><td ng-if=\\"::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount)\\" class=\\"ng-scope\\">\\n      <table class=\\"roa-table roa-inline\\">\\n        <tbody><tr>\\n          <!-- ngIf: ::party.PriorJailings -->\\n          <!-- ngIf: ::party.InJail -->\\n          <!-- ngIf: ::party.JailWeekenderIn -->\\n          <!-- ngIf: ::party.JailWeekenderOut -->\\n          <!-- ngIf: ::party.HasActiveWarrants && data.WarrantInformation.ShowWarrantHeaderIcon -->\\n          <td ng-class=\\"::roaSection.isInactive(party, connectionType.codeId) ? 'roa-text-italic' : 'roa-text-bold'\\" class=\\"ng-binding roa-text-bold\\">\\n            ARMSTRONG, DYLIN ROBERT JEFFRY \\n          </td>\\n        </tr>\\n      </tbody></table>\\n\\n      <!-- ngIf: ::party.AdditionalNames.length -->\\n\\n\\n      <!-- ngIf: ::party.PartyStyle -->\\n\\n      <!-- ngRepeat: address in ::party.Addresses --><!-- ngIf: ::party.Addresses.length --><div ng-if=\\"::party.Addresses.length\\" class=\\"roa-indent ng-scope\\" ng-repeat=\\"address in ::party.Addresses\\">\\n        <div ng-class=\\"party.CasePartyConnection.Inactive == 1 ? 'roa-text-italic' : ''\\">\\n    <!-- ngIf: ::address.ConfidentialAddress -->\\n    <!-- ngIf: ::!(address.ConfidentialAddress) --><div ng-if=\\"::!(address.ConfidentialAddress)\\" ng-switch=\\"address.AddressType\\" class=\\"ng-scope\\">\\n\\n      <!-- ngSwitchWhen: 0 -->\\n\\n      <!-- ngSwitchWhen: 1 --><div ng-switch-when=\\"1\\" class=\\"ng-scope\\">\\n        <!-- ngIf: ::address.AddressLine1 --><div ng-if=\\"::address.AddressLine1\\" class=\\"ng-binding ng-scope\\">\\n          BB 274 RM 207 COURTHOUSE BAY\\n        </div><!-- end ngIf: ::address.AddressLine1 -->\\n        <!-- ngIf: ::address.AddressLine2 -->\\n        <!-- ngIf: ::address.AddressLine3 -->\\n        <div>\\n          <!-- ngIf: ::address.City --><span ng-if=\\"::address.City\\" class=\\"ng-binding ng-scope\\">CAMP LEJEUNE,</span><!-- end ngIf: ::address.City -->\\n          <span class=\\"ng-binding\\">NC</span>\\n          <span class=\\"ng-binding\\">28542</span>\\n        </div>\\n      </div><!-- end ngSwitchWhen: -->\\n\\n      <!-- ngSwitchWhen: 2 -->\\n    </div><!-- end ngIf: ::!(address.ConfidentialAddress) -->\\n  </div>\\n      </div><!-- end ngIf: ::party.Addresses.length --><!-- end ngRepeat: address in ::party.Addresses -->\\n\\n      <div class=\\"roa-indent\\" ng-class=\\"::roaSection.isInactive(party, connectionType.codeId) ? 'roa-text-italic' : ''\\">\\n        <!-- ngIf: ::party.Race --><div ng-if=\\"::party.Race\\" class=\\"ng-binding ng-scope\\">\\n          White\\n        </div><!-- end ngIf: ::party.Race -->\\n\\n        <!-- ngIf: ::party.Gender --><div ng-if=\\"::party.Gender\\" class=\\"ng-binding ng-scope\\">\\n          Male\\n        </div><!-- end ngIf: ::party.Gender -->\\n\\n        <div>\\n          <!-- ngIf: ::party.Height && !party.IsAUSCulture --><div class=\\"roa-inline roa-data ng-scope ng-isolate-scope\\" label=\\"Height:\\" ng-if=\\"::party.Height &amp;&amp; !party.IsAUSCulture\\">\\n    <!-- ngIf: ::label --><div class=\\"roa-label roa-inline roa-align-top ng-binding ng-scope\\" ng-if=\\"::label\\" ng-bind=\\"::label\\">Height:</div><!-- end ngIf: ::label -->\\n    <!-- ngIf: ::value -->\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude=\\"\\">\\n            <span class=\\"ng-binding ng-scope\\">5′</span>\\n            <span class=\\"ng-binding ng-scope\\">8″</span>\\n          </div>\\n  </div><!-- end ngIf: ::party.Height && !party.IsAUSCulture -->\\n\\n          <!-- ngIf: ::party.Height && party.IsAUSCulture -->\\n\\n          <!-- ngIf: ::party.Weight && !party.IsAUSCulture -->\\n\\n          <!-- ngIf: ::party.Weight && party.IsAUSCulture -->\\n        </div>\\n\\n        <div>\\n          <!-- ngIf: ::party.DateOfBirth -->\\n\\n          <!-- ngIf: ::party.DateOfDeath -->\\n\\n          <!-- ngIf: ::$scope.greaterThan(party.Age, 0) -->\\n        </div>\\n\\n\\n        <div>\\n          <!-- ngIf: ::party.DriversLicenseState || party.DriversLicenseNumber -->\\n          <!-- ngIf: ::party.StateIdentificationNumber -->\\n        </div>\\n\\n      </div>\\n\\n\\n      <div ng-class=\\"::party.RemovedReason ? 'roa-text-italic' : ''\\" class=\\"roa-indent\\">\\n        <!-- ngIf: ::party.RemovedDate -->\\n        <!-- ngIf: ::party.RemovedReason -->\\n      </div>\\n\\n      <!-- ngIf: ::party.OtherAgencies.length -->\\n\\n    </td><!-- end ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) -->\\n\\n    <!-- ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) --><td ng-if=\\"::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount)\\" class=\\"ng-scope\\">\\n      <!-- ngRepeat: attorney in ::party.CasePartyAttorneys -->\\n    </td><!-- end ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) -->\\n\\n\\n  </tr><!-- end ngRepeat: party in ::roaSection.getPartiesByConnectionTypeId(connectionType.codeId) -->\\n\\n\\n  </tbody><!-- end ngRepeat: connectionType in roaSection.casePartyConnectionsTypes --><tbody ng-repeat=\\"connectionType in roaSection.casePartyConnectionsTypes\\" class=\\"ng-scope\\">\\n\\n  <!-- ngIf: ::$first && roaSection.partyInfo.ShowAttorneyHeader && roaSection.partyInfo.ShowOnlyLeadAttornies -->\\n  \\n  <!-- ngRepeat: party in ::roaSection.getPartiesByConnectionTypeId(connectionType.codeId) --><tr ng-repeat=\\"party in ::roaSection.getPartiesByConnectionTypeId(connectionType.codeId)\\" class=\\"roa-party-row roa-pad-b-10 ng-scope\\">\\n\\n    <td class=\\"roa-text-bold\\">\\n      <!-- ngIf: ::$first --><div ng-if=\\"::$first\\" class=\\"ng-binding ng-scope\\">Complainant</div><!-- end ngIf: ::$first -->\\n    </td>\\n    <!-- ngIf: ::!(roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount)) -->\\n    <!-- ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) --><td ng-if=\\"::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount)\\" class=\\"ng-scope\\">\\n      <table class=\\"roa-table roa-inline\\">\\n        <tbody><tr>\\n          <!-- ngIf: ::party.PriorJailings -->\\n          <!-- ngIf: ::party.InJail -->\\n          <!-- ngIf: ::party.JailWeekenderIn -->\\n          <!-- ngIf: ::party.JailWeekenderOut -->\\n          <!-- ngIf: ::party.HasActiveWarrants && data.WarrantInformation.ShowWarrantHeaderIcon -->\\n          <td ng-class=\\"::roaSection.isInactive(party, connectionType.codeId) ? 'roa-text-italic' : 'roa-text-bold'\\" class=\\"ng-binding roa-text-bold\\">\\n            BROWN, ERIK \\n          </td>\\n        </tr>\\n      </tbody></table>\\n\\n      <!-- ngIf: ::party.AdditionalNames.length -->\\n\\n\\n      <!-- ngIf: ::party.PartyStyle -->\\n\\n      <!-- ngRepeat: address in ::party.Addresses -->\\n\\n      <div class=\\"roa-indent\\" ng-class=\\"::roaSection.isInactive(party, connectionType.codeId) ? 'roa-text-italic' : ''\\">\\n        <!-- ngIf: ::party.Race -->\\n\\n        <!-- ngIf: ::party.Gender -->\\n\\n        <div>\\n          <!-- ngIf: ::party.Height && !party.IsAUSCulture -->\\n\\n          <!-- ngIf: ::party.Height && party.IsAUSCulture -->\\n\\n          <!-- ngIf: ::party.Weight && !party.IsAUSCulture -->\\n\\n          <!-- ngIf: ::party.Weight && party.IsAUSCulture -->\\n        </div>\\n\\n        <div>\\n          <!-- ngIf: ::party.DateOfBirth -->\\n\\n          <!-- ngIf: ::party.DateOfDeath -->\\n\\n          <!-- ngIf: ::$scope.greaterThan(party.Age, 0) -->\\n        </div>\\n\\n\\n        <div>\\n          <!-- ngIf: ::party.DriversLicenseState || party.DriversLicenseNumber -->\\n          <!-- ngIf: ::party.StateIdentificationNumber -->\\n        </div>\\n\\n      </div>\\n\\n\\n      <div ng-class=\\"::party.RemovedReason ? 'roa-text-italic' : ''\\" class=\\"roa-indent\\">\\n        <!-- ngIf: ::party.RemovedDate -->\\n        <!-- ngIf: ::party.RemovedReason -->\\n      </div>\\n\\n      <!-- ngIf: ::party.OtherAgencies.length -->\\n\\n    </td><!-- end ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) -->\\n\\n    <!-- ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) --><td ng-if=\\"::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount)\\" class=\\"ng-scope\\">\\n      <!-- ngRepeat: attorney in ::party.CasePartyAttorneys -->\\n    </td><!-- end ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) -->\\n\\n\\n  </tr><!-- end ngRepeat: party in ::roaSection.getPartiesByConnectionTypeId(connectionType.codeId) -->\\n\\n\\n  </tbody><!-- end ngRepeat: connectionType in roaSection.casePartyConnectionsTypes -->\\n\\n</table>\\n\\n<div class=\\"ng-scope\\">\\n  <!-- ngIf: roaSection.enablePaging -->\\n</div>\\n</ng-include>\\n    </md-card-content>\\n  </md-card>\\n</section><!-- end ngIf: roaSection.showSection --></div><!-- end ngIf: ::data.roaSections.partySection -->\\n      <!-- ngIf: ::data.roaSections.dispositionEvents && data.Options.DispFirst === '1' -->\\n      <!-- ngIf: ::data.roaSections.causesSection -->\\n      <!-- ngIf: ::data.roaSections.caseEvents --><div ng-include-template=\\"Areas/RegisterOfActions/Views/ROA/Templates/RoA_Section_Template.html\\" ng-include-variables=\\"{roaSection: data.roaSections.caseEvents, data: data, $scope: this}\\" ng-if=\\"::data.roaSections.caseEvents\\" class=\\"ng-scope ng-isolate-scope\\"><!-- ngIf: roaSection.showSection --><section ng-if=\\"roaSection.showSection\\" class=\\"ng-scope\\" style=\\"\\">\\n  <md-card class=\\"no-print-section-border md-tyler-default-theme-theme\\">\\n    <md-toolbar class=\\"roa-section-header md-tyler-default-theme-theme\\" data-header-text=\\"Case Events\\" id=\\"case-events\\" ng-class=\\"::{'no-print-section-header': skipHeader}\\">\\n    <div class=\\"md-toolbar-tools\\">\\n      <!-- ngIf: $scope.selectedSection === $args.id -->\\n      <h1>\\n        <span class=\\"header-text ng-binding\\">Case Events</span>\\n      </h1>\\n    </div>\\n  </md-toolbar>\\n    <md-card-content class=\\"roa-section-content\\">\\n      <!-- In general, the sections will work like this:\\n      - Initial load: showSection = false. nothing shows (exception - basic case info always has showSection = true and sets loading = true to show an indicator)\\n      - Error on load: showSection = true, loading = false, error = error text. Section is shown with error text.\\n      - Load success, but no data: showSection = false. nothing shows\\n      - Data exists: showSection = true, loading = false, error = null.\\n      -->\\n      <!-- ngIf: roaSection.loading -->\\n      <!-- ngIf: roaSection.error -->\\n      <!-- ngInclude: undefined --><ng-include ng-show=\\"!roaSection.loading &amp;&amp; !roaSection.error\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + roaSection.template\\" class=\\"ng-scope\\" aria-hidden=\\"false\\" style=\\"\\"><md-content layout=\\"column\\" class=\\"print-prevent-split ng-scope md-tyler-default-theme-theme layout-column\\">\\n  <!-- ngRepeat: event in roaSection.eventInfo.Events --><div class=\\"roa-pad-0 roa-event-info ng-scope roa-event-info-event\\" ng-show=\\"::roaSection.eventInfo\\" ng-repeat=\\"event in roaSection.eventInfo.Events\\" ng-class=\\"::'roa-event-info-' + $scope.camelCaseToDash(event.Type || 'undefined')\\" aria-hidden=\\"false\\">\\n\\n    <div ng-style=\\"::$scope.getCustomCss(event