 ngSwitchWhen: V -->\\n                <!-- ngSwitchWhen: A -->\\n                <!-- ngSwitchWhen: P -->\\n                <!-- ngSwitchWhen: I -->\\n              </span>\\n            </div>\\n\\n            <div class=\\"roa-column-one-third\\">\\n              <!-- ngIf: ::transBalance.TypeKey.CodeID == 'P' -->\\n            </div>\\n\\n            <div class=\\"roa-column-one-third\\">\\n              <!-- ngIf: $scope.greaterThan(transBalance.PayorID,0) -->\\n              <!-- ngIf: transBalance.PayorID === 0 --><span ng-if=\\"transBalance.PayorID === 0\\" class=\\"ng-binding ng-scope\\">\\n                \\n              </span><!-- end ngIf: transBalance.PayorID === 0 -->\\n            </div>\\n          </div>\\n\\n          <div class=\\"roa-text-right\\">\\n            <span ng-switch=\\"\\" on=\\"::transBalance.TypeKey.CodeID\\">\\n              <!-- ngSwitchWhen: C --><span ng-switch-when=\\"C\\" class=\\"ng-binding ng-scope\\">\\n                191.00\\n              </span><!-- end ngSwitchWhen: -->\\n              <!-- ngSwitchWhen: CR -->\\n              <!-- ngSwitchWhen: RED -->\\n              <!-- ngSwitchWhen: V -->\\n              <!-- ngSwitchWhen: A -->\\n              <!-- ngSwitchWhen: P -->\\n              <!-- ngSwitchWhen: I -->\\n            </span>\\n          </div>\\n        </div><!-- end ngRepeat: transBalance in ::fee.CaseFeeParty.TransBalances.TransBalances --><div ng-repeat=\\"transBalance in ::fee.CaseFeeParty.TransBalances.TransBalances\\" ng-init=\\"::(adjustmentAmount = (0 + transBalance.ChgAmt - transBalance.PayAmt - transBalance.CreditAmt))\\" class=\\"roa-finance-row ng-scope\\">\\n          <div class=\\"ng-binding\\">03/23/2026</div>\\n          <div>\\n            <div class=\\"roa-column-one-third\\">\\n              <span ng-switch=\\"\\" on=\\"::transBalance.TypeKey.CodeID\\">\\n                <!-- ngSwitchWhen: C --><span ng-switch-when=\\"C\\" class=\\"ng-scope\\">Transaction Assessment</span><!-- end ngSwitchWhen: -->\\n                <!-- ngSwitchWhen: CR -->\\n                <!-- ngSwitchWhen: RED -->\\n                <!-- ngSwitchWhen: V -->\\n                <!-- ngSwitchWhen: A -->\\n                <!-- ngSwitchWhen: P -->\\n                <!-- ngSwitchWhen: I -->\\n              </span>\\n            </div>\\n\\n            <div class=\\"roa-column-one-third\\">\\n              <!-- ngIf: ::transBalance.TypeKey.CodeID == 'P' -->\\n            </div>\\n\\n            <div class=\\"roa-column-one-third\\">\\n              <!-- ngIf: $scope.greaterThan(transBalance.PayorID,0) -->\\n              <!-- ngIf: transBalance.PayorID === 0 --><span ng-if=\\"transBalance.PayorID === 0\\" class=\\"ng-binding ng-scope\\">\\n                \\n              </span><!-- end ngIf: transBalance.PayorID === 0 -->\\n            </div>\\n          </div>\\n\\n          <div class=\\"roa-text-right\\">\\n            <span ng-switch=\\"\\" on=\\"::transBalance.TypeKey.CodeID\\">\\n              <!-- ngSwitchWhen: C --><span ng-switch-when=\\"C\\" class=\\"ng-binding ng-scope\\">\\n                200.00\\n              </span><!-- end ngSwitchWhen: -->\\n              <!-- ngSwitchWhen: CR -->\\n              <!-- ngSwitchWhen: RED -->\\n              <!-- ngSwitchWhen: V -->\\n              <!-- ngSwitchWhen: A -->\\n              <!-- ngSwitchWhen: P -->\\n              <!-- ngSwitchWhen: I -->\\n            </span>\\n          </div>\\n        </div><!-- end ngRepeat: transBalance in ::fee.CaseFeeParty.TransBalances.TransBalances -->\\n      </div>\\n\\n    </div><!-- end ngRepeat: fee in ::roaSection.financialInfo.CaseFees -->\\n\\n  </div><!-- end ngIf: ::roaSection.financialInfo.ShowFinancialSummaryCaseFees -->\\n\\n\\n  <!-- ngIf: ::roaSection.financialInfo.ShowFinancialSummaryRegister -->\\n\\n</div>\\n</ng-include>\\n    </md-card-content>\\n  </md-card>\\n</section><!-- end ngIf: roaSection.showSection --></div><!-- end ngIf: ::data.roaSections.financialSummarySection