ctionVisible() -->\\n              <!-- ngIf: !showAllDataActionVisible() --><button ng-if=\\"!showAllDataActionVisible()\\" ng-click=\\"generatePdf();\\" class=\\"roa-action-button ng-scope\\" tabindex=\\"0\\">\\n                <md-icon md-font-icon=\\"mdi-printer\\" class=\\"mdi pull-right roa-menunav-icon ng-isolate-scope md-tyler-default-theme-theme md-font mdi-printer material-icons\\" aria-label=\\"Print\\">\\n                  \\n                </md-icon>\\n              </button><!-- end ngIf: !showAllDataActionVisible() -->\\n              <!-- ngIf: showAllDataActionVisible() -->\\n              <button href=\\"javascript:window.print()\\" ng-show=\\"false\\" class=\\"roa-action-button ng-hide\\" tabindex=\\"0\\" aria-hidden=\\"true\\">\\n                <md-icon md-font-icon=\\"mdi-printer\\" class=\\"mdi pull-right roa-menunav-icon ng-isolate-scope md-tyler-default-theme-theme md-font mdi-printer material-icons\\" aria-hidden=\\"true\\"></md-icon>\\n              </button>\\n              <button onclick=\\"window.open((document.location + '').replace('portalembed', ''))\\" class=\\"roa-open-in-new-tab roa-action-button\\" tabindex=\\"0\\">\\n                <md-icon md-font-icon=\\"mdi-open-in-new\\" class=\\"mdi pull-right roa-menunav-icon ng-isolate-scope md-tyler-default-theme-theme md-font mdi-open-in-new material-icons\\" aria-hidden=\\"true\\"></md-icon>\\n              </button>\\n            </div><!-- end ngIf: loadCount === 0 -->\\n          </div>\\n        </div>\\n      </div>\\n\\n    </md-toolbar>\\n\\n\\n    <!-- ngIf: ::!error.hasError --><md-content flex=\\"\\" id=\\"roa-content\\" ng-if=\\"::!error.hasError\\" md-scroll-y=\\"\\" class=\\"no-print-scroll ng-scope md-tyler-default-theme-theme flex\\" data-mapping-enabled=\\"true\\" data-mapping-id=\\"roa-content\\">\\n\\n      <!-- ngIf: ::data.roaSections.caseSummary --><div ng-include-template=\\"Areas/RegisterOfActions/Views/ROA/Templates/RoA_Section_Template.html\\" ng-include-variables=\\"{roaSection: data.roaSections.caseSummary, data: data, skipHeader: true, $scope: this}\\" ng-if=\\"::data.roaSections.caseSummary\\" class=\\"ng-scope ng-isolate-scope\\"><!-- ngIf: roaSection.showSection --><section ng-if=\\"roaSection.showSection\\" class=\\"ng-scope\\" style=\\"\\">\\n  <md-card class=\\"no-print-section-border md-tyler-default-theme-theme\\">\\n    <md-toolbar class=\\"roa-section-header md-tyler-default-theme-theme no-print-section-header\\" data-header-text=\\"Case Summary\\" id=\\"header-info\\" ng-class=\\"::{'no-print-section-header': skipHeader}\\">\\n    <div class=\\"md-toolbar-tools\\">\\n      <!-- ngIf: $scope.selectedSection === $args.id --><md-icon ng-if=\\"$scope.selectedSection === $args.id\\" md-font-icon=\\"mdi-arrow-right-bold\\" class=\\"mdi roa-selected-section-icon ng-scope ng-isolate-scope md-tyler-default-theme-theme md-font mdi-arrow-right-bold material-icons\\" aria-hidden=\\"true\\"></md-icon><!-- end ngIf: $scope.selectedSection === $args.id -->\\n      <h1>\\n        <span class=\\"header-text ng-binding\\">Case Summary</span>\\n      </h1>\\n    </div>\\n  </md-toolbar>\\n    <md-card-content class=\\"roa-section-content\\">\\n      <!-- In general, the sections will work like this:\\n      - Initial load: showSection = false. nothing shows (exception - basic case info always has showSection = true and sets loading = true to show an indicator)\\n      - Error on load: showSection = true, loading = false, error = error text. Section is shown with error text.\\n      - Load success, but no data: showSection = false. nothing shows\\n      - Data exists: showSection = true, loading = false, error = null.\\n      -->\\n      <!-- ngIf: roaSection.loading -->\\n      <!-- ngIf: roaSection.error -->\\n      <!-- ngInclude: undefined --><ng-include ng-show=\\"!roaSection.loading &amp;&amp; !roaSection.error\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + roaSection.template\\" class=\\"ng-scope\\" aria-hidden=\\"false\\" style=\\"\\">\\n\\n\\n<div id=\\"roa-header\\" class=\\"ng-scope\\">\\n\\n  <div class=\\"ng-binding\\">\\n    Mecklenburg District Court\\n  </div>\\n\\n  <div class=\\"roa-header-title ng-binding\\">\\n    Case Summary\\n  </div>\\n\\n  <div>\\n    <!-- ngIf: ::roaSection.headerInfo.IsCaseSecureGroup --> <span> Case\\n    No. </span> <span class=\\"ng-binding\\"> 25IF012559-590 </span>\\n  </div>\\n</div>\\n\\n<div layout=\\"row\\" class=\\"roa-header-columns ng-scope layout-row\\">\\n  <div flex=\\"50\\" class=\\"flex-50\\">\\n    <div>\\n      <!-- ngIf: ::data.WarrantInformation.ShowWarrantHeaderIcon -->\\n    </div>\\n    <div>\\n        <span class=\\"roa-text-bold ng-binding\\"> STATE OF NORTH CAROLINA VS DYLIN ROBERT JEFFRY ARMSTRONG </span>\\n    </div>\\n  </div>\\n\\n  <div flex=\\"50\\" class=\\"flex-50\\">\\n\\n    <div label=\\"Location\\" class=\\"ng-isolate-scope\\">\\n    <div class=\\"roa-header-sect-row hide-xs layout-row\\" hide-xs=\\"\\" layout=\\"row\\">\\n      <div flex=\\"\\" class=\\"roa-label ng-binding flex\\">\\n        Location:\\n      </div>\\n      <div flex=\\"\\" class=\\"roa-value flex\\" ng-transclude=\\"\\"><span class=\\"ng-binding ng-scope\\">\\n      Mecklenburg District Court\\n    </span></div>\\n    </div>\\n    <div class=\\"roa-header-sect-row hide-gt-xs layout-row\\" hide-gt-xs=\\"\\" layout=\\"row\\">\\n      <div flex=\\"\\" style=\\"text-align: left\\" class=\\"roa-label ng-binding flex\\">\\n        Location\\n      </div>\\n    </div>\\n    <div class=\\"roa-header-sect-row hide-gt-xs layout-row\\" hide-gt-xs=\\"\\" layout=\\"row\\">\\n      <div flex=\\"\\" class=\\"roa-value flex\\" ng-transclude=\\"\\"><span class=\\"ng-binding ng-scope\\">\\n      Mecklenburg District Court\\n    </span></div>\\n    </div>\\n\\n  </div>\\n\\n    <!-- ngIf: ::roaSection.headerInfo.Judge -->\\n\\n    <!-- ngIf: ::roaSection.assignmentInfo.CurrentMagistrateAssignment.Description -->\\n\\n   