essThan($index, roaSection.maxPartyCount) -->\\n\\n    <!-- ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) --><td ng-if=\\"::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount)\\" class=\\"ng-scope\\">\\n      <!-- ngRepeat: attorney in ::party.CasePartyAttorneys -->\\n    </td><!-- end ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) -->\\n\\n\\n  </tr><!-- end ngRepeat: party in ::roaSection.getPartiesByConnectionTypeId(connectionType.codeId) -->\\n\\n\\n  </tbody><!-- end ngRepeat: connectionType in roaSection.casePartyConnectionsTypes --><tbody ng-repeat=\\"connectionType in roaSection.casePartyConnectionsTypes\\" class=\\"ng-scope\\">\\n\\n  <!-- ngIf: ::$first && roaSection.partyInfo.ShowAttorneyHeader && roaSection.partyInfo.ShowOnlyLeadAttornies -->\\n  \\n  <!-- ngRepeat: party in ::roaSection.getPartiesByConnectionTypeId(connectionType.codeId) --><tr ng-repeat=\\"party in ::roaSection.getPartiesByConnectionTypeId(connectionType.codeId)\\" class=\\"roa-party-row roa-pad-b-10 ng-scope\\">\\n\\n    <td class=\\"roa-text-bold\\">\\n      <!-- ngIf: ::$first --><div ng-if=\\"::$first\\" class=\\"ng-binding ng-scope\\">Complainant</div><!-- end ngIf: ::$first -->\\n    </td>\\n    <!-- ngIf: ::!(roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount)) -->\\n    <!-- ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) --><td ng-if=\\"::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount)\\" class=\\"ng-scope\\">\\n      <table class=\\"roa-table roa-inline\\">\\n        <tbody><tr>\\n          <!-- ngIf: ::party.PriorJailings -->\\n          <!-- ngIf: ::party.InJail -->\\n          <!-- ngIf: ::party.JailWeekenderIn -->\\n          <!-- ngIf: ::party.JailWeekenderOut -->\\n          <!-- ngIf: ::party.HasActiveWarrants && data.WarrantInformation.ShowWarrantHeaderIcon -->\\n          <td ng-class=\\"::roaSection.isInactive(party, connectionType.codeId) ? 'roa-text-italic' : 'roa-text-bold'\\" class=\\"ng-binding roa-text-bold\\">\\n            BROWN, ERIK \\n          </td>\\n        </tr>\\n      </tbody></table>\\n\\n      <!-- ngIf: ::party.AdditionalNames.length -->\\n\\n\\n      <!-- ngIf: ::party.PartyStyle -->\\n\\n      <!-- ngRepeat: address in ::party.Addresses -->\\n\\n      <div class=\\"roa-indent\\" ng-class=\\"::roaSection.isInactive(party, connectionType.codeId) ? 'roa-text-italic' : ''\\">\\n        <!-- ngIf: ::party.Race -->\\n\\n        <!-- ngIf: ::party.Gender -->\\n\\n        <div>\\n          <!-- ngIf: ::party.Height && !party.IsAUSCulture -->\\n\\n          <!-- ngIf: ::party.Height && party.IsAUSCulture -->\\n\\n          <!-- ngIf: ::party.Weight && !party.IsAUSCulture -->\\n\\n          <!-- ngIf: ::party.Weight && party.IsAUSCulture -->\\n        </div>\\n\\n        <div>\\n          <!-- ngIf: ::party.DateOfBirth -->\\n\\n          <!-- ngIf: ::party.DateOfDeath -->\\n\\n          <!-- ngIf: ::$scope.greaterThan(party.Age, 0) -->\\n        </div>\\n\\n\\n        <div>\\n          <!-- ngIf: ::party.DriversLicenseState || party.DriversLicenseNumber -->\\n          <!-- ngIf: ::party.StateIdentificationNumber -->\\n        </div>\\n\\n      </div>\\n\\n\\n      <div ng-class=\\"::party.RemovedReason ? 'roa-text-italic' : ''\\" class=\\"roa-indent\\">\\n        <!-- ngIf: ::party.RemovedDate -->\\n        <!-- ngIf: ::party.RemovedReason -->\\n      </div>\\n\\n      <!-- ngIf: ::party.OtherAgencies.length -->\\n\\n    </td><!-- end ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) -->\\n\\n    <!-- ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) --><td ng-if=\\"::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount)\\" class=\\"ng-scope\\">\\n      <!-- ngRepeat: attorney in ::party.CasePartyAttorneys -->\\n    </td><!-- end ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) -->\\n\\n\\n  </tr><!-- end ngRepeat: party in ::roaSection.getPartiesByConnectionTypeId(connectionType.codeId) -->\\n\\n\\n  </tbody><!-- end ngRepeat: connectionType in roaSection.casePartyConnectionsTypes -->\\n\\n</table>\\n\\n<div class=\\"ng-scope\\">\\n  <!-- ngIf: roaSection.enablePaging -->\\n</div>\\n</ng-include>\\n    </md-card-content>\\n  </md-card>\\n</section><!-- end ngIf: roaSection.showSection --></div><!-- end ngIf: ::data.roaSections.partySection -->\\n      <!-- ngIf: ::data.roaSections.dispositionEvents && data.Options.DispFirst === '1' -->\\n      <!-- ngIf: ::data.roaSections.causesSection -->\\n      <!-- ngIf: ::data.roaSections.caseEvents --><div ng-include-template=\\"Areas/RegisterOfActions/Views/ROA/Templates/RoA_Section_Template.html\\" ng-include-variables=\\"{roaSection: data.roaSections.caseEvents, data: data, $scope: this}\\" ng-if=\\"::data.roaSections.caseEvents\\" class=\\"ng-scope ng-isolate-scope\\"><!-- ngIf: roaSection.showSection --><section ng-if=\\"roaSection.showSection\\" class=\\"ng-scope\\" style=\\"\\">\\n  <md-card class=\\"no-print-section-border md-tyler-default-theme-theme\\">\\n    <md-toolbar class=\\"roa-section-header md-tyler-default-theme-theme\\" data-header-text=\\"Case Events\\" id=\\"case-events\\" ng-class=\\"::{'no-print-section-header': skipHeader}\\">\\n    <div class=\\"md-toolbar-tools\\">\\n      <!-- ngIf: $scope.selectedSection === $args.id -->\\n      <h1>\\n        <span class=\\"header-text ng-binding\\">Case Events</span>\\n      </h1>\\n    </div>\\n  </md-toolbar>\\n    <md-card-content class=\\"roa-section-content\\">\\n      <!-- In general, the sections will work like this:\\n      - Initial load: showSection = false. nothing shows (exception - basic case info always has showSection = true and sets loading = true to show an indicator)\\n      - Error on load: showSection = true, loading = false, error = error text. Section is shown with error text.\\n      - Load success, but no data: showSection = false. nothing shows\\n      - Data exists: showSection = true, loading = false, error = null.\\n      -->\\n      <!-- ngIf: roaSection.loading -->\\n      <!-- ngIf: roaSection.error -->\\n      <!-- ngInclude: undefined --><ng-include ng-show=\\"!roaSection.loading &amp;&amp; !roaSection.error\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + roaSection.template\\" class=\\"ng-scope\\" aria-hidden=\\"false\\" style=\\"\\"><md-content layout=\\"column\\" class=\\"print-prevent-split ng-scope md-tyler-default-theme-theme layout-column\\">\\n  <!-- ngRepeat: event in roaSection.eventInfo.Events --><div class=\\"roa-pad-0 roa-event-info ng-scope roa-event-info-event\\" ng-show=\\"::roaSection.eventInfo\\" ng-repeat=\\"event in roaSection.eventInfo.Events\\" ng-class=\\"::'roa-event-info-' + $scope.camelCaseToDash(event.Type || 'undefined')\\" aria-hidden=\\"false\\">\\n\\n    <div ng-style=\\"::$scope.getCustomCss(event)\\" style=\\"margin-left: 0px;\\">\\n      <div class=\\"roa-pad-bottom roa-event-event\\" ng-class=\\"::$scope.getClassForEventTemplate(event)\\">\\n        <!-- ngInclude: undefined --><ng-include src=\\"::$scope.getEventTemplate(event)\\" ng-init=\\"hearingEvent = null; minuteEvent = false;\\" class=\\"ng-scope\\" style=\\"\\"><div data-rem-class=\\"roa-event-row\\" ng-class=\\"::{'roa-text-strike':event.Event.IsDeleted}\\" class=\\"ng-scope\\">\\n\\n  <!-- ngIf: ::!minuteEvent --><div class=\\"roa-inline roa-align-top roa-event-date-col ng-scope\\" ng-if=\\"::!minuteEvent\\" style=\\"min-width:11rem\\">\\n    <div ng-transclude=\\"\\" ng-class=\\"::{'roa-text-strike': event.Event.IsDeleted}\\"><span class=\\"ng-binding ng-scope\\">\\n    03/23/2026\\n  </span></div>\\n  </div><!-- end ngIf: ::!minuteEvent -->\\n  <!-- ngIf: ::minuteEvent -->\\n\\n  <div 