 /><label for=\\"chkDoNotShowAgain\\">Do not show me this message again.</label>\\n      <p class=\\"roa-warning-paragraph\\">\\n        Please select one of the following options.\\n      </p>\\n      <div class=\\"roa-text-center\\">\\n        <md-button ng-click=\\"closeDialog(true)\\">{{::print ? 'Print All' : 'Expand'}}</md-button>\\n        <md-button ng-click=\\"closeDialog(false)\\">Cancel</md-button>\\n      </div>\\n    </md-card-content>\\n\\n  </md-dialog>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-section-toolbar.template\\" class=\\"ng-scope\\">\\n  <md-toolbar class=\\"roa-section-header\\">\\n    <div class=\\"md-toolbar-tools\\">\\n      <md-icon ng-if=\\"$scope.selectedSection === $args.id\\"\\n               md-font-icon=\\"mdi-arrow-right-bold\\"\\n               class=\\"mdi roa-selected-section-icon\\"></md-icon>\\n      <h1>\\n        <span class=\\"header-text\\">{{$args.headerText}}</span>\\n      </h1>\\n    </div>\\n  </md-toolbar>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-header-data.template\\" class=\\"ng-scope\\">\\n  <div>\\n    <div class=\\"roa-header-sect-row\\" hide-xs layout=\\"row\\">\\n      <div flex class=\\"roa-label\\">\\n        {{label}}:\\n      </div>\\n      <div flex class=\\"roa-value\\" ng-transclude>\\n      </div>\\n    </div>\\n    <div class=\\"roa-header-sect-row\\" hide-gt-xs layout=\\"row\\">\\n      <div flex style=\\"text-align: left\\" class=\\"roa-label\\">\\n        {{label}}\\n      </div>\\n    </div>\\n    <div class=\\"roa-header-sect-row\\" hide-gt-xs layout=\\"row\\" >\\n      <div flex class=\\"roa-value\\" ng-transclude>\\n      </div>\\n    </div>\\n\\n  </div>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-data.template\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-data\\">\\n    <div class=\\"roa-label roa-inline roa-align-top\\" ng-if=\\"::label\\" ng-bind=\\"::label\\"></div>\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-if=\\"::value\\" ng-bind=\\"::value\\"></div>\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude></div>\\n  </div>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-charge-data-column.template\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold\\" hide-gt-sm>\\n      {{$args.label}}\\n    </div>\\n    <div>\\n      {{$args.value}}\\n    </div>\\n  </div>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-event-date.template\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-event-date-col\\">\\n    <div ng-transclude ng-class=\\"::{'roa-text-strike': event.Event.IsDeleted}\\">\\n    </div>\\n  </div>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-event-timestamp-create.template\\" class=\\"ng-scope\\">\\n  <div ng-if=\\"::data.Options.ShowTimestampCreate == '1'\\">\\n    <roa-data  label=\\"Created:\\">\\n      {{::event.TimestampCreateIso8601 | date: $scope.dateFormat.Date + ' h:mm a'}}\\n    </roa-data>\\n  </div>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-event-index.template\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-event-index\\">\\n    <div ng-if=\\"::data.Options.Index == '1'\\">\\n      <span ng-if=\\"::event.Event.EventVolume\\">Vol./Book {{::event.Event.EventVolume}}{{::event.Event.EventPage ? ',' : ''}}</span>\\n      <span ng-if=\\"::event.Event.EventVolume && event.Event.EventPage\\"><br /></span>\\n\\n      <span ng-if=\\"::event.Event.EventPage\\">Page {{::event.Event.EventPage}}{{::event.Event.NumberOfPages ? ', ' : ''}}</span>\\n      <span ng-if=\\"::event.Event.NumberOfPages\\">{{::event.Event.NumberOfPages}} pages</span>\\n\\n      <ng-transclude></ng-transclude>\\n    </div>\\n  </div>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-party-address.template\\" class=\\"ng-scope\\">\\n  <div ng-class=\\"party.CasePartyConnection.Inactive == 1 ? 'roa-text-italic' : ''\\">\\n    <div ng-if=\\"::address.ConfidentialAddress\\">\\n      ** Confidential Address **\\n    </div>\\n    <div ng-if=\\"::!(address.ConfidentialAddress)\\" ng-switch=\\"address.AddressType\\">\\n\\n      <div ng-switch-when=\\"0\\">\\n        <div ng-if=\\"::address.Block || address.PrefixDirection || address.Street || address.AddressSuffixKey || address.PostfixDirection\\">\\n          <span>{{::address.Block}}</span>\\n          <span>{{::address.PrefixDirection}}</span>\\n          <span>{{::address.Street}}</span>\\n          <span>{{::address.AddressSuffixKey}}</span>\\n          <span>{{::address.PostfixDirection}}</span>\\n        </div>\\n        <div ng-if=\\"::address.UnitKey\\">\\n          <span>{{::address.UnitKey}}</span>\\n          <span>{{::address.UnitNumber}}</span>\\n        </div>\\n        <div>\\n          <span ng-if=\\"::address.City\\">{{::address.City}},</span>\\n          <span>{{::address.State}}</span>\\n          <span>{{::address.PostalCode}}</span>\\n        </div>\\n      </div>\\n\\n      <div ng-switch-when=\\"1\\">\\n        <div ng-if=\\"::address.AddressLine1\\">\\n          {{::address.AddressLine1}}\\n        </div>\\n        <div ng-if=\\"::address.AddressLine2\\">\\n          {{::address.AddressLine2}}\\n        </div>\\n        <div ng-if=\\"::address.AddressLine3\\">\\n          {{::address.AddressLine3}}\\n        </div>\\n        <div>\\n          <span ng-if=\\"::address.City\\">{{::address.City}},</span>\\n          <span>{{::address.State}}</span>\\n          <span>{{::address.PostalCode}}</span>\\n        </div>\\n      </div>\\n\\n      <div ng-switch-when=\\"2\\">\\n        <div ng-if=\\"::address.AddressLine1\\">\\n          {{::address.AddressLine1}}\\n        </div>\\n        <div ng-if=\\"::address.AddressLine2\\">\\n          {{::address.AddressLine2}}\\n        </div>\\n        <div ng-if=\\"::address.AddressLine3\\">\\n          {{::address.AddressLine3}}\\n        </div>\\n        <div ng-if=\\"::address.AddressLine4\\">\\n          {{::address.AddressLine4}}\\n        </div>\\n      </div>\\n    </div>\\n  </div>\\n\\n</script>\\n</div>\\n<div class=\\"cfp-hotkeys-container fade ng-scope\\" ng-class=\\"{in: helpVisible}\\" style=\\"display: none;\\"><div class=\\"cfp-hotkeys\\"><!-- ngIf: !header --><h4 class=\\"cfp-hotkeys-title ng-binding ng-scope\\" ng-if=\\"!header\\">Keyboard Shortcuts:</h4><!-- end ngIf: !header --><!-- ngIf: header --><table><tbody><!-- ngRepeat: hotkey in hotkeys | filter:{ description: '!$$undefined$$' } --><tr ng-repeat=\\"hotkey in hotkeys | filter:{ description: '!$$undefined$$' }\\" class=\\"ng-scope\\"><td class=\\"cfp-hotkeys-keys\\"><!-- ngRepeat: key in hotkey.format() track by $index --><span ng-repeat=\\"key in hotkey.format() track by $index\\" class=\\"cfp-hotkeys-key ng-binding ng-scope\\">?</span><!-- end ngRepeat: key in hotkey.format() track by $index --></td><td class=\\"cfp-hotkeys-text ng-binding\\">Show / hide this help menu</td></tr><!-- end ngRepeat: hotkey in hotkeys | filter:{ description: '!$$undefined$$' } --></tbody></table><!-- ngIf: footer --><div class=\\"cfp-hotkeys-close\\" ng-click=\\"toggleCheatSheet()\\" role=\\"button\\" tabindex=\\"0\\">×</div></div></div></div>\\n\\n\\n  <!-- center for IE9 since it ignores bootstrap 3 -->\\n<center class=\\"no-print\\">\\n\\n  <!-- use noscript and also keep outside of controller to avoid flash in Safari and IE (can't use ng-cloak because there is no js it won't uncloak-->\\n  <noscript>\\n    <span class=\\"nojs-content\\">\\n      <h2>JavaScript must be enabled in order for you to use this application.</h2>\\n      <p>However, it seems JavaScript is either disabled or not supported by your browser.</p>\\n      <p>To use this application, enable JavaScript by changing your browser options, then try again.</p>\\n    </span>\\n  </noscript>\\n\\n  <span class=\\"nocookies-content\\">\\n    <h2>Cookies must be allowed.</h2>\\n    <p>Your browser is currently set to block cookies. Your browser must allow cookies be