div><!-- end ngIf: ::roaSection.headerInfo.AppearBy -->\\n\\n    <!-- ngRepeat: historyItem in ::roaSection.headerInfo.CaseNumberHistory -->\\n\\n    <!-- ngRepeat: crossRef in ::roaSection.headerInfo.CrossReferenceNumbers -->\\n\\n    <!-- ngRepeat: timeStd in ::roaSection.headerInfo.TimeStandardInstances | filter : {HideTargetDate: false} -->\\n\\n  </div>\\n</div>\\n\\n</ng-include>\\n    </md-card-content>\\n  </md-card>\\n</section><!-- end ngIf: roaSection.showSection --></div><!-- end ngIf: ::data.roaSections.caseSummary -->\\n      <!-- ngIf: ::data.roaSections.caseInformation --><div ng-include-template=\\"Areas/RegisterOfActions/Views/ROA/Templates/RoA_Section_Template.html\\" ng-include-variables=\\"{roaSection: data.roaSections.caseInformation, data: data, $scope: this}\\" ng-if=\\"::data.roaSections.caseInformation\\" class=\\"ng-scope ng-isolate-scope\\"><!-- ngIf: roaSection.showSection --><section ng-if=\\"roaSection.showSection\\" class=\\"ng-scope\\" style=\\"\\">\\n  <md-card class=\\"no-print-section-border md-tyler-default-theme-theme\\">\\n    <md-toolbar class=\\"roa-section-header md-tyler-default-theme-theme\\" data-header-text=\\"Case Information\\" id=\\"case-info\\" ng-class=\\"::{'no-print-section-header': skipHeader}\\">\\n    <div class=\\"md-toolbar-tools\\">\\n      <!-- ngIf: $scope.selectedSection === $args.id -->\\n      <h1>\\n        <span class=\\"header-text ng-binding\\">Case Information</span>\\n      </h1>\\n    </div>\\n  </md-toolbar>\\n    <md-card-content class=\\"roa-section-content\\">\\n      <!-- In general, the sections will work like this:\\n      - Initial load: showSection = false. nothing shows (exception - basic case info always has showSection = true and sets loading = true to show an indicator)\\n      - Error on load: showSection = true, loading = false, error = error text. Section is shown with error text.\\n      - Load success, but no data: showSection = false. nothing shows\\n      - Data exists: showSection = true, loading = false, error = null.\\n      -->\\n      <!-- ngIf: roaSection.loading -->\\n      <!-- ngIf: roaSection.error -->\\n      <!-- ngInclude: undefined --><ng-include ng-show=\\"!roaSection.loading &amp;&amp; !roaSection.error\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + roaSection.template\\" class=\\"ng-scope\\" aria-hidden=\\"false\\" style=\\"\\"><div style=\\"display: inline-block; float:right;\\" class=\\"ng-scope\\">\\n  <!-- ngInclude: undefined --><ng-include flex-gt-sm=\\"\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + roaSection.roaCaseInfoInfoTemplate\\" class=\\"ng-scope flex-gt-sm\\" style=\\"\\"><!-- Using tables to support IE10 -->\\n<div style=\\"min-width: 260px;\\" class=\\"ng-scope\\">\\n  <table class=\\"roa-caseinfo-info-rows\\">\\n    <colgroup>\\n      <col style=\\"width:30%\\">\\n      <col style=\\"width:70%\\">\\n    </colgroup>\\n    <tbody>\\n      <!-- ngIf: ::roaSection.caseInfo.CaseType.Description --><tr ng-if=\\"::roaSection.caseInfo.CaseType.Description\\" class=\\"ng-scope\\">\\n        <td class=\\"roa-label\\">\\n          Case&nbsp;Type:\\n        </td>\\n        <td class=\\"roa-value ng-binding\\">\\n          Infraction\\n        </td>\\n      </tr><!-- end ngIf: ::roaSection.caseInfo.CaseType.Description -->\\n      <!-- ngIf: ::roaSection.caseInfo.CaseSubType.Description -->\\n      <!-- ngIf: ::roaSection.caseInfo.CaseStatuses.length --><tr ng-if=\\"::roaSection.caseInfo.CaseStatuses.length\\" class=\\"ng-scope\\">\\n        <td class=\\"roa-label\\">\\n          Case&nbsp;Status:\\n        </td>\\n        <td class=\\"roa-value\\">\\n          <!-- ngRepeat: status in ::roaSection.caseInfo.CaseStatuses --><div ng-repeat=\\"status in ::roaSection.caseInfo.CaseStatuses\\" class=\\"ng-scope\\">\\n            <div ng-class=\\"{'roa-text-bold':$first}\\" class=\\"roa-text-bold\\">\\n              <span class=\\"ng-binding\\">10/14/2025</span>\\n              <span>&nbsp;</span>\\n              <span class=\\"ng-binding\\">Pending</span>\\n            </div>\\n            <!-- ngIf: ::roaSection.caseInfo.ShowCaseStatusComments -->\\n          </div><!-- end ngRepeat: status in ::roaSection.caseInfo.CaseStatuses -->\\n        </td>\\n      </tr><!-- end ngIf: ::roaSection.caseInfo.CaseStatuses.length -->\\n      <!-- ngIf: ::roaSection.caseInfo.CaseFlags.length -->\\n      <!-- ngIf: data.Options.ShowSeparationDate == '1' && roaSection.divorceInfo != null && roaSection.divorceInfo != undefined && roaSection.divorceInfo.SeparationDates.length > 0 -->\\n    </tbody>\\n  </table>\\n</div></ng-include>\\n</div>\\n<div hide-gt-sm=\\"\\" style=\\"clear:both\\" class=\\"hide-gt-sm ng-scope\\"></div>\\n<div class=\\"ng-scope\\">\\n  <!-- ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\" style=\\"\\"><!-- ngIf: ::roaSection.causeInfo.ShowCauses --></ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\" style=\\"\\"><!-- ngIf: ::roaSection.chargeInfo.ShowOffenses --><div class=\\"roa-subsection ng-scope\\" ng-if=\\"::roaSection.chargeInfo.ShowOffenses\\" style=\\"\\">\\n\\n  <!--\\n  <div ng-if=\\"roaSection.chargeInfo.PartyConfigs.length\\">\\n    <div ng-if=\\"(roaSection.chargeInfo.Charges | filter: { PartyId: partyConfig.PartyId }).length\\">\\n      <div class=\\"roa-subsection-heading\\">\\n        Charges\\n      </div>\\n    </div>\\n  </div>\\n  -->\\n\\n  <table class=\\"roa-table roa-responsive-table roa-cellspacing-horizontal\\">\\n    <thead>\\n    <tr>\\n      <th colspan=\\"2\\">\\n        Offense\\n      </th>\\n      <th>\\n        <!-- ngIf: roaSection.chargeInfo.ShowCitationNumbers --><span hide-xs=\\"\\" hide-sm=\\"\\" ng-if=\\"roaSection.chargeInfo.ShowCitationNumbers\\" class=\\"hide-sm hide-xs ng-scope\\">\\n          Citation\\n        </span><!-- end ngIf: roaSection.chargeInfo.ShowCitationNumbers -->\\n      </th>\\n      <th>\\n        <!-- ngIf: roaSection.chargeInfo.ShowStatutes --><span hide-xs=\\"\\" hide-sm=\\"\\" ng-if=\\"roaSection.chargeInfo.ShowStatutes\\" class=\\"hide-sm hide-xs ng-scope\\">\\n          Statute\\n        </span><!-- end ngIf: roaSection.chargeInfo.ShowStatutes -->\\n      </th>\\n      <th>\\n        <span hide-xs=\\"\\" hide-sm=\\"\\" class=\\"hide-sm hide-xs\\">\\n          Degree\\n        </span>\\n      </th>\\n      <th>\\n        <span hide-xs=\\"\\" hide-sm=\\"\\" class=\\"hide-sm hide-xs\\">\\n          Offense Date\\n        </span>\\n      </th>\\n            <th>\\n        <span hide-xs=\\"\\" hide-sm=\\"\\" class=\\"hide-sm hide-xs\\">\\n          Filed Date\\n        </span>\\n      </th>\\n    </tr>\\n    </thead>\\n\\n    <!-- ngRepeat: partyConfig in ::roaSection.chargeInfo.PartyConfigs --><tbody ng-repeat=\\"partyConfig in ::roaSection.chargeInfo.PartyConfigs\\" class=\\"ng-scope\\">\\n      <!-- ngIf: ::roaSection.chargeInfo.ShowPartyNames -->\\n      <!-- ngRepeat: charge in filteredCharges = (roaSection.chargeInfo.Charges | filter: { PartyId: partyConfig.PartyId }) --><tr ng-repeat-start=\\"charge in filteredCharges = (roaSection.chargeInfo.Charges | filter: { PartyId: partyConfig.PartyId })\\" class=\\"ng-scope\\"></tr>\\n      <!-- ngIf: ::partyConfig.ShowJurisdicationLabels -->\\n\\n      <tr hide-gt-sm=\\"\\" class=\\"hide-gt-sm ng-scope\\">\\n        <td class=\\"roa-text-right\\">\\n          <!-- ngIf: ::charge.CurrChargeNum --><span ng-if=\\"::charge.CurrChargeNum\\" class=\\"ng-binding ng-scope\\">\\n            1.\\n          </span><!-- end ngIf: ::charge.CurrChargeNum -->\\n        </td>\\n        <td colspan=\\"5\\">\\n          <div>\\n            <span class=\\"ng-binding\\">FAILURE TO REDUCE SPEED</span>\\n            <!-- ngIf: ::charge.ChargeOffense.GOC -->\\n          </div>\\n        </td>\\n      </tr>\\n      <tr hide-gt-sm=\\"\\" class=\\"hide-gt-sm ng-scope\\">\\n        <td></td>\\n        <td></td>\\n        <td>\\n          <!-- todo fixme convert to better template -->\\n          <!-- ngIf: ::roaSection.chargeInfo.ShowCitationNumbers && charge.CitationNumber --><roa-charge-data-column ng-if=\\"::roaSection.chargeInfo.ShowCitationNumbers &amp;&amp; charge.CitationNumber\\" label=\\"Citation\\" data-value=\\"73503H1\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Citation\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      73503H1\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::roaSection.chargeInfo.ShowCitationNumbers && charge.CitationNumber -->\\n        </td>\\n        <td>\\n          <!-- ngIf: ::roaSection.chargeInfo.ShowStatutes && charge.ChargeOffense.Statute --><roa-charge-data-column ng-if=\\"::roaSection.chargeInfo.ShowStatutes &amp;&amp; charge.ChargeOffense.Statute\\" label=\\"Statute\\" data-value=\\"G.S. 20-141(M)\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Statute\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      G.S. 20-141(M)\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::roaSection.chargeInfo.ShowStatutes && charge.ChargeOffense.Statute -->\\n        </td>\\n        <td>\\n          <!-- ngIf: ::charge.ChargeOffense.Degree --><roa-charge-data-column ng-if=\\"::charge.ChargeOffense.Degree\\" label=\\"Degree\\" data-value=\\"INF\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Degree\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      INF\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::charge.ChargeOffense.Degree -->\\n        </td>\\n        <td>\\n          <!-- ngIf: ::charge.OffenseDate --><roa-charge-data-column ng-if=\\"::charge.OffenseDate\\" label=\\"Offense Date\\" data-value=\\"10/11/2025\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Offense Date\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      10/11/2025\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::charge.OffenseDate -->\\n        </td>\\n        <td>\\n          <!-- ngIf: ::charge.FiledDate --><roa-charge-data-column ng-if=\\"::charge.FiledDate\\" label=\\"Filed Date\\" data-value=\\"10/14/2025\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Filed Date\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      10/14/2025\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::charge.FiledDate -->\\n        </td>\\n      </tr>\\n\\n      <tr hide-xs=\\"\\" hide-sm=\\"\\" class=\\"hide-sm hide-xs ng-scope\\">\\n        <td class=\\"roa-text-right\\">\\n          <!-- ngIf: ::charge.CurrChargeNum --><span ng-if=\\"::charge.CurrChargeNum\\" class=\\"ng-binding ng-scope\\">&nbsp;1.</span><!-- end ngIf: ::charge.CurrChargeNum -->\\n        </td>\\n        <td>\\n          <div>\\n            <span class=\\"ng-binding\\">FAILURE TO REDUCE SPEED</span>\\n            <!-- ngIf: ::charge.ChargeOffense.GOC -->\\n          </div>\\n        </td>\\n        <td>\\n          <!-- ngIf: ::roaSection.chargeInfo.ShowCitationNumbers && charge.CitationNumber --><roa-charge-data-column ng-if=\\"::roaSection.chargeInfo.ShowCitationNumbers &amp;&amp; charge.CitationNumber\\" label=\\"Citation\\" data-value=\\"73503H1\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Citation\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      73503H1\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::roaSection.chargeInfo.ShowCitationNumbers && charge.CitationNumber -->\\n        </td>\\n        <td>\\n          <!-- ngIf: ::roaSection.chargeInfo.ShowStatutes && charge.ChargeOffense.Statute --><roa-charge-data-column ng-if=\\"::roaSection.chargeInfo.ShowStatutes &amp;&amp; charge.ChargeOffense.Statute\\" label=\\"Statute\\" data-value=\\"G.S. 20-141(M)\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Statute\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      G.S. 20-141(M)\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::roaSection.chargeInfo.ShowStatutes && charge.ChargeOffense.Statute -->\\n        </td>\\n        <td>\\n          <!-- ngIf: ::charge.ChargeOffense.Degree --><roa-charge-data-column ng-if=\\"::charge.ChargeOffense.Degree\\" label=\\"Degree\\" data-value=\\"INF\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Degree\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      INF\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::charge.ChargeOffense.Degree -->\\n        </td>\\n        <td>\\n          <!-- ngIf: ::charge.OffenseDate --><roa-charge-data-column ng-if=\\"::charge.OffenseDate\\" label=\\"Offense Date\\" data-value=\\"10/11/2025\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Offense Date\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      10/11/2025\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::charge.OffenseDate -->\\n        </td>\\n        <td>\\n          <!-- ngIf: ::charge.FiledDate --><roa-charge-data-column ng-if=\\"::charge.FiledDate\\" label=\\"Filed Date\\" data-value=\\"10/14/2025\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold hide-gt-sm ng-binding\\" hide-gt-sm=\\"\\">\\n      Filed Date\\n    </div>\\n    <div class=\\"ng-binding\\">\\n      10/14/2025\\n    </div>\\n  </div>\\n</roa-charge-data-column><!-- end ngIf: ::charge.FiledDate -->\\n        </td>\\n      </tr>\\n\\n      <!-- Additional Statutes -->\\n      <!-- ngRepeat: additionalStatute in ::charge.ChargeOffense.AdditionalStatutes track by $index -->\\n\\n      <tr class=\\"ng-scope\\">\\n        <td></td>\\n        <td colspan=\\"4\\">\\n          <div class=\\"roa-indent\\">\\n\\n            <!-- Disposition/Level of Sentence -->\\n            <!-- ngIf: ::charge.Disposition.length -->\\n\\n            <!-- Arrest, Rearrest, and Offense Reports -->\\n            <div>\\n\\n              <!-- Arrests -->\\n              <!-- ngIf: ::charge.Arrests.length -->\\n\\n              <!-- Rearrests -->\\n              <!-- ngIf: ::charge.Rearrests.length -->\\n\\n              <!-- Offense Reports -->\\n              <!-- ngIf: ::charge.FilingAgencyDescription || charge.OffenseReportControlNumber --><div ng-if=\\"::charge.FilingAgencyDescription || charge.OffenseReportControlNumber\\" class=\\"roa-pad-top ng-scope\\">\\n                <div>Offense Reports</div>\\n                <div class=\\"roa-indent-2\\">\\n                  <!-- ngIf: ::charge.OffenseReportControlNumber -->\\n                  <!-- ngIf: ::charge.FilingAgencyDescription --><div class=\\"roa-data ng-scope ng-isolate-scope\\" label=\\"Agency:\\" ng-if=\\"::charge.FilingAgencyDescription\\">\\n    <!-- ngIf: ::label --><div class=\\"roa-label roa-inline roa-align-top ng-binding ng-scope\\" ng-if=\\"::label\\" ng-bind=\\"::label\\">Agency:</div><!-- end ngIf: ::label -->\\n    <!-- ngIf: ::value -->\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude=\\"\\">\\n                    <div class=\\"ng-binding ng-scope\\">\\n                      State Highway Patrol Troop H District 5\\n                    </div>\\n                    <!-- ngRepeat: address in ::charge.FilingAgencyAddress --><!-- ngIf: ::charge.FilingAgencyAddress.length --><div ng-if=\\"::charge.FilingAgencyAddress.length\\" ng-repeat=\\"address in ::charge.FilingAgencyAddress\\" class=\\"ng-binding ng-scope\\">\\n                      12101 Mt. Holly-Huntersville Road\\n                    </div><!-- end ngIf: ::charge.FilingAgencyAddress.length --><!-- end ngRepeat: address in ::charge.FilingAgencyAddress --><!-- ngIf: ::charge.FilingAgencyAddress.length --><div ng-if=\\"::charge.FilingAgencyAddress.length\\" ng-repeat=\\"address in ::charge.FilingAgencyAddress\\" class=\\"ng-binding ng-scope\\">\\n                      Hunetersville, NC, 18078\\n                    </div><!-- end ngIf: ::charge.FilingAgencyAddress.length --><!-- end ngRepeat: address in ::charge.FilingAgencyAddress -->\\n                  </div>\\n  </div><!-- end ngIf: ::charge.FilingAgencyDescription -->\\n                </div>\\n              </div><!-- end ngIf: ::charge.FilingAgencyDescription || charge.OffenseReportControlNumber -->\\n\\n            </div>\\n\\n            <!-- ngIf: ::charge.ChargeOffense.AdditionalChargeComponentInstances.length --><div style=\\"padding-left:3rem;\\" ng-if=\\"::charge.ChargeOffense.AdditionalChargeComponentInstances.length\\" class=\\"print-padding ng-scope\\">\\n              <!-- ngRepeat: additionalChargeComponent in ::charge.ChargeOffense.AdditionalChargeComponentInstances --><div ng-repeat=\\"additionalChargeComponent in ::charge.ChargeOffense.AdditionalChargeComponentInstances\\" ng-switch=\\"\\" on=\\"additionalChargeComponent.AdditionalChargeComponentId\\" class=\\"ng-scope\\">\\n\\n                <!-- The Certify To DPS component (AddChargeComponentID='3') -->\\n                <!-- ngSwitchWhen: 3 -->\\n\\n                <!-- The Minnesota Offense Codes component (AddChargeComponentID='4') -->\\n                <!-- ngSwitchWhen: 4 -->\\n\\n                <!-- The DPS Group component (AddChargeComponentID='16') -->\\n                <!-- ngSwitchWhen: 16 -->\\n\\n                <!-- The Predatory Offender Registration component (AddChargeComponentID='17') -->\\n                <!-- ngSwitchWhen: 17 -->\\n\\n                <!-- The Targeted Misdemeanor component (AddChargeComponentID='18') -->\\n                <!-- ngSwitchWhen: 18 -->\\n\\n                <!-- The Wildlife fine calculation component (AddChargeComponentID='20') -->\\n                <!-- ngSwitchWhen: 20 -->\\n\\n                <!-- The Speeding Fine Calculation component - Flat Rate - MN (AddChargeComponentID='21') -->\\n                <!-- ngSwitchWhen: 21 -->\\n\\n                <!-- The Overweight fine calculation component (AddChargeComponentID='22') -->\\n                <!-- ngSwitchWhen: 22 -->\\n\\n                <!-- The State Share component (AddChargeComponentID='26') -->\\n                <!--The State Share label is removed in Jira ODY-259438 for MN.  A configuration option will likely be added\\n        to the persona case summary options in the future -->\\n                <!-- <span ng-switch-when=\\"26\\">\\n        State Share\\n      </span>-->\\n                <!-- The Sheriff's Contingency calculation component (AddChargeComponentID='27') -->\\n                <!-- ngSwitchWhen: 27 -->\\n\\n                <!-- The Address of Offense component (AddChargeComponentID='34') -->\\n                <!-- ngSwitchWhen: 34 -->\\n\\n                <!-- The Drug Type component (AddChargeComponentID='37') -->\\n                <!-- ngSwitchWhen: 37 -->\\n\\n                <!-- The Charge Qualifier -  Weapons component (AddChargeComponentID='41') -->\\n                <!-- ngSwitchWhen: 41 -->\\n\\n                <!-- The Charge Qualifier - Amount component (AddChargeComponentID='44') -->\\n                <!-- ngSwitchWhen: 44 -->\\n\\n                <!-- The DUI Group component (AddChargeComponentID='46') -->\\n                <!-- ngSwitchWhen: 46 -->\\n\\n                <!-- The Report To DNR component (AddChargeComponentID='48') -->\\n                <!-- ngSwitchWhen: 48 -->\\n\\n                <!-- The DA Charging Paragraph component (AddChargeComponentID='53') -->\\n                <!-- ngSwitchWhen: 53 -->\\n\\n                <!-- The DUI Group component (AddChargeComponentID='54') -->\\n                <!-- ngSwitchWhen: 54 -->\\n\\n                <!-- The Speeding Group component GA (AddChargeComponentID='55') -->\\n                <!-- ngSwitchWhen: 55 -->\\n\\n                <!-- The Speeding Fine Calculation component GA, FL (AddChargeComponentID='56') -->\\n                <!-- ngSwitchWhen: 56 -->\\n\\n                <!-- The Hot Check Fields component (AddChargeComponentID='58') -->\\n                <!-- ngSwitchWhen: 58 -->\\n\\n                <!-- The Overweight Fine Calculation (Rated/Actual) component (AddChargeComponentID='59') -->\\n                <!-- ngSwitchWhen: 59 -->\\n\\n                <!-- The Blood Alcohol Content component (AddChargeComponentID='60') -->\\n                <!-- ngSwitchWhen: 60 -->\\n\\n                <!-- The Predatory Offender component (AddChargeComponentID='61') -->\\n                <!-- ngSwitchWhen: 61 -->\\n\\n                <!-- The Address of Offense component (AddChargeComponentID='62') -->\\n                <!-- ngSwitchWhen: 62 -->\\n\\n                <!-- The Drug Amount component (AddChargeComponentID='63') -->\\n                <!-- ngSwitchWhen: 63 -->\\n\\n                <!-- The Blood Alcohol Content Status component (AddChargeComponentID='64') -->\\n                <!-- ngSwitchWhen: 64 -->\\n\\n                <!-- The Blood Alcohol Content Level component (AddChargeComponentID='65') -->\\n                <!-- ngSwitchWhen: 65 -->\\n\\n                <!-- The Speeding Fine Calculation component (AddChargeComponentID='66') -->\\n                <!-- ngSwitchWhen: 66 -->\\n\\n                <!-- The Send to DOT component (AddChargeComponentID='67') -->\\n                <!-- ngSwitchWhen: 67 -->\\n\\n                <!-- MN 3rd Violation Enhancement To Misd (AddChargeComponentID='68') -->\\n                <!-- ngSwitchWhen: 68 -->\\n\\n                <!-- NC Implied Consent -->\\n               <!-- ngIf: ::additionalChargeComponent.AdditionalChargeComponentCode == 'NCIMPLCON' -->\\n              </div><!-- end ngRepeat: additionalChargeComponent in ::charge.ChargeOffense.AdditionalChargeComponentInstances -->\\n            </div><!-- end ngIf: ::charge.ChargeOffense.AdditionalChargeComponentInstances.length -->\\n\\n            <!-- Original (of an amended) Charge -->\\n            <!-- ngIf: ::charge.OriginalChargeOffense -->\\n\\n            <!-- Charge Track and Sequence Numbers -->\\n            <!-- ngIf: ::roaSection.chargeInfo.ChargeTrackNumberLabel && charge.ChargeTrackingNumber -->\\n\\n            <!-- ngIf: ::roaSection.chargeInfo.ChargeSequenceNumberLabel && charge.ChargeSequenceNumber -->\\n\\n          </div>\\n        </td>\\n      </tr>\\n      <tr ng-repeat-end=\\"\\" class=\\"ng-scope\\"></tr><!-- end ngRepeat: charge in filteredCharges = (roaSection.chargeInfo.Charges | filter: { PartyId: partyConfig.PartyId }) -->\\n    </tbody><!-- end ngRepeat: partyConfig in ::roaSection.chargeInfo.PartyConfigs -->\\n  </table>\\n\\n</div><!-- end ngIf: ::roaSection.chargeInfo.ShowOffenses -->\\n\\n</ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: ::roaSection.