 to show an indicator)\\n      - Error on load: showSection = true, loading = false, error = error text. Section is shown with error text.\\n      - Load success, but no data: showSection = false. nothing shows\\n      - Data exists: showSection = true, loading = false, error = null.\\n      -->\\n      <!-- ngIf: roaSection.loading -->\\n      <!-- ngIf: roaSection.error -->\\n      <!-- ngInclude: undefined --><ng-include ng-show=\\"!roaSection.loading &amp;&amp; !roaSection.error\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + roaSection.template\\" class=\\"ng-scope\\" aria-hidden=\\"false\\" style=\\"\\"><md-content layout=\\"column\\" class=\\"print-prevent-split ng-scope md-tyler-default-theme-theme layout-column\\">\\n  <!-- ngRepeat: event in roaSection.eventInfo.Events --><div class=\\"roa-pad-0 roa-event-info ng-scope roa-event-info-event\\" ng-show=\\"::roaSection.eventInfo\\" ng-repeat=\\"event in roaSection.eventInfo.Events\\" ng-class=\\"::'roa-event-info-' + $scope.camelCaseToDash(event.Type || 'undefined')\\" aria-hidden=\\"false\\">\\n\\n    <div ng-style=\\"::$scope.getCustomCss(event)\\" style=\\"margin-left: 0px;\\">\\n      <div class=\\"roa-pad-bottom roa-event-event\\" ng-class=\\"::$scope.getClassForEventTemplate(event)\\">\\n        <!-- ngInclude: undefined --><ng-include src=\\"::$scope.getEventTemplate(event)\\" ng-init=\\"hearingEvent = null; minuteEvent = false;\\" class=\\"ng-scope\\" style=\\"\\"><div data-rem-class=\\"roa-event-row\\" ng-class=\\"::{'roa-text-strike':event.Event.IsDeleted}\\" class=\\"ng-scope\\">\\n\\n  <!-- ngIf: ::!minuteEvent --><div class=\\"roa-inline roa-align-top roa-event-date-col ng-scope\\" ng-if=\\"::!minuteEvent\\" style=\\"min-width:11rem\\">\\n    <div ng-transclude=\\"\\" ng-class=\\"::{'roa-text-strike': event.Event.IsDeleted}\\"><span class=\\"ng-binding ng-scope\\">\\n    03/23/2026\\n  </span></div>\\n  </div><!-- end ngIf: ::!minuteEvent -->\\n  <!-- ngIf: ::minut