ovided';\\n} catch(e) {}\\n\\n// Helper to clean whitespace\\nconst clean = (v) => {\\n  if (Array.isArray(v)) v = v[0];\\n  return (v || '').replace(/\\\\s+/g, ' ').trim();\\n};\\n\\n// These fields return arrays because multiple parties exist on the page\\n// Party order: [0]=State, [1]=Defendant, [2]=Complainant\\nconst names   = Array.isArray(d.defendant_name)         ? d.defendant_name         : [d.defendant_name];\\nconst cityArr = Array.isArray(d.defendant_city_state_zip) ? d.defendant_city_state_zip : [];\\nconst agencyAddrArr = Array.isArray(d.filing_agency_address) ? d.filing_agency_address : [];\\nconst citations = Array.isArray(d.citation_number)      ? d.citation_number        : [d.citation_number];\\n\\nconst defendant  = (names[1] || names[0] || '').replace(/\\\\s+/g,' ').trim();\\nconst complainant = (names[2] || '').replace(/\\\\s+/g,' ').trim();\\n\\n// City/State/ZIP — filter blanks, join\\nconst cityStateZip = cityArr\\n  .filter(v => v && v.trim())\\n  .map(v => v.trim())\\n  .join(' ')\\n  .replace(/\\\\s+/g,' ')\\n  .trim();\\n\\nconst agencyAddr = agencyAddrArr\\n  .filter(v => v && v.trim())\\n  .map(v => v.trim())\\n  .join(', ');\\n\\nconst citationStr = citations\\n  .filter(v => v && v.trim())\\n  .map(v => v.trim())\\n  .join(', ');\\n\\nreturn [{\\n  json: {\\n    'Case Number':           clean(d.case_number),\\n    'Court':                 clean(d.court_name),\\n    'Case Title':            clean(d.case_title),\\n    'Filed Date':            clean(d.filed_date),\\n    'Appear By Date':        clean(d.appear_by_date),\\n    'Case Type':             clean(d.case_type),\\n    'Case Status':           clean(d.case_status),\\n    'Defendant Name':        defendant,\\n    'Complainant':           complainant,\\n    'Address Line 1':        clean(d.defendant_address_line1),\\n    'City / State / ZIP':    cityStateZip,\\n    'Offense':               clean(d.offense),\\n    'Citation Number':       citationStr,\\n    'Statute':               c