      <div class=\\"roa-pad-bottom roa-event-event\\" ng-class=\\"::$scope.getClassForEventTemplate(event)\\">\\n        <!-- ngInclude: undefined --><ng-include src=\\"::$scope.getEventTemplate(event)\\" ng-init=\\"hearingEvent = null; minuteEvent = false;\\" class=\\"ng-scope\\" style=\\"\\"><div data-rem-class=\\"roa-event-row\\" ng-class=\\"::{'roa-text-strike':event.Event.IsDeleted}\\" class=\\"ng-scope\\">\\n\\n  <!-- ngIf: ::!minuteEvent --><div class=\\"roa-inline roa-align-top roa-event-date-col ng-scope\\" ng-if=\\"::!minuteEvent\\" style=\\"min-width:11rem\\">\\n    <div ng-transclude=\\"\\" ng-class=\\"::{'roa-text-strike': event.Event.IsDeleted}\\"><span class=\\"ng-binding ng-scope\\">\\n    03/23/2026\\n  </span></div>\\n  </div><!-- end ngIf: ::!minuteEvent -->\\n  <!-- ngIf: ::minuteEvent -->\\n\\n  <div data-rem-class=\\"roa-event-content\\" class=\\"roa-inline roa-align-top\\" style=\\"min-width:calc(100% - 24rem)\\">\\n\\n    <div>\\n      <div>\\n\\n        <roa-documents><!-- ngIf: ::$scope.greaterThan(event.DocumentCount,0) --></roa-documents>\\n\\n        <!--TODO(UI): Review where lead event image shows -->\\n        <!-- ngIf: ::event.Event.FromLead -->\\n\\n\\n        <!-- ngIf: ::(data.Options.EventCmnt == '1' || event.Event.TypeId.Word == 'HSA')\\n         && data.Options.CaseEventCommentsBelowDesc == '0'\\n         && event.Event.Comment -->\\n\\n        <div class=\\"roa-data ng-isolate-scope\\" label=\\"Failure to Appear\\">\\n    <!-- ngIf: ::label --><div class=\\"roa-label roa-inline roa-align-top ng-binding ng-scope\\" ng-if=\\"::label\\" ng-bind=\\"::label\\">Failure to Appear</div><!-- end ngIf: ::label -->\\n    <!-- ngIf: ::value -->\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude=\\"\\">\\n          <!-- ngIf: ::event.Event.JudgeId.Description -->\\n        </div>\\n  </div>\\n\\n        <!-- ngIf: ::(data.Options.EventCmnt == '1' || event.Event.TypeId.Word == 'HSA')\\n         && data.Options.CaseEventCo