\\n        <span class=\\"header-text ng-binding\\">Financial Information</span>\\n      </h1>\\n    </div>\\n  </md-toolbar>\\n    <md-card-content class=\\"roa-section-content\\">\\n      <!-- In general, the sections will work like this:\\n      - Initial load: showSection = false. nothing shows (exception - basic case info always has showSection = true and sets loading = true to show an indicator)\\n      - Error on load: showSection = true, loading = false, error = error text. Section is shown with error text.\\n      - Load success, but no data: showSection = false. nothing shows\\n      - Data exists: showSection = true, loading = false, error = null.\\n      -->\\n      <!-- ngIf: roaSection.loading -->\\n      <!-- ngIf: roaSection.error -->\\n      <!-- ngInclude: undefined --><ng-include ng-show=\\"!roaSection.loading &amp;&amp; !roaSection.error\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + roaSection.template\\" class=\\"ng-scope\\" aria-hidden=\\"false\\" style=\\"\\"><div class=\\"print-font-size-medium ng-scope\\">\\n  <!-- ngIf: ::roaSection.financialInfo.ShowFinancialSummaryCaseFees --><div ng-if=\\"::roaSection.financialInfo.ShowFinancialSummaryCaseFees\\" class=\\"roa-finance-case-fees ng-scope\\">\\n\\n    <!-- ngRepeat: fee in ::roaSection.financialInfo.CaseFees --><div class=\\"roa-finance-fee roa-pad-bottom ng-scope\\" ng-repeat=\\"fee in ::roaSection.financialInfo.CaseFees\\">\\n\\n      <!-- ngIf: ::fee.ShowCategory -->\\n\\n      <div class=\\"roa-finance-row\\">\\n        <div></div>\\n        <div>\\n          <span class=\\"roa-text-bold ng-binding\\">\\n            Defendant\\n          </span>\\n          <span class=\\"roa-indent-2 ng-binding\\">\\n            ARMSTRONG, DYLIN ROBERT JEFFRY\\n          </span>\\n        </div>\\n      </div>\\n\\n      <div class=\\"roa-finance-row\\">\\n        <div></div>\\n        <div>\\n          Total Financial Assessment\\n        </div>\\n        <div class=\\"roa-text-right ng-binding\\">\\n          441.00\\n        </div>\\n      </div>\\n\\n      <!-- ngIf: ::fee.CaseFeeParty.Restitution !== null -->\\n\\n      <div class=\\"roa-finance-row\\">\\n        <div></div>\\n        <div>\\n          Total Payments and Credits\\n        </div>\\n        <div class=\\"roa-text-right ng-binding\\">\\n          0.00\\n        </div>\\n      </div>\\n\\n      <div class=\\"roa-finance-row roa-text-bold\\">\\n        <div></div>\\n        <div class=\\"ng-binding\\">\\n          Balance Due as of 05/01/2026\\n        </div>\\n        <div class=\\"roa-text-right\\">\\n          <!-- ngIf: ::!$scope.lessThan(fee.CaseFeeParty.Balance,0) --><span ng-if=\\"::!$scope.lessThan(fee.CaseFeeParty.Balance,0)\\" class=\\"ng-binding ng-scope\\">\\n            441.00\\n          </span><!-- end ngIf: ::!$scope.lessThan(fee.CaseFeeParty.Balance,0) -->\\n          <!-- ngIf: ::$scope.lessThan(fee.CaseFeeParty.Balance,0) -->\\n        </div>\\n      </div>\\n\\n      <div class=\\"roa-pad-bottom roa-pad-top\\">\\n        <!-- ngRepeat: transBalance in ::fee.CaseFeeParty.TransBalances.TransBalances --><div ng-repeat=\\"transBalance in ::fee.CaseFeeParty.TransBalances.TransBalances\\" ng-init=\\"::(adjustmentAmount = (0 + transBalance.ChgAmt - transBalance.PayAmt - transBalance.CreditAmt))\\" class=\\"roa-finance-row ng-scope\\">\\n          <div class=\\"ng-binding\\">10/14/2025</div>\\n          <div>\\n            <div class=\\"roa-column-one-third\\">\\n              <span ng-switch=\\"\\" on=\\"::transBalance.TypeKey.CodeID\\">\\n                <!-- ngSwitchWhen: C --><span ng-switch-when=\\"C\\" class=\\"ng-scope\\">Transaction Assessment</span><!-- end ngSwitchWhen: -->\\n                <!-- ngSwitchWhen: CR -->\\n                <!-- ngSwitchWhen: RED -->\\n                <!-- ngSwitchWhen: V -->\\n                <!-- ngSwitchWhen: A -->\\n                <!-- ngSwitchWhen: P -->\\n                <!-- ngSwitchWhen: I -->\\n         