\n    <!-- ngIf: ::roaSection.headerInfo.IsCaseSecureGroup --> <span> Case\\n    No. </span> <span class=\\"ng-binding\\"> 25IF012559-590 </span>\\n  </div>\\n</div>\\n\\n<div layout=\\"row\\" class=\\"roa-header-columns ng-scope layout-row\\">\\n  <div flex=\\"50\\" class=\\"flex-50\\">\\n    <div>\\n      <!-- ngIf: ::data.WarrantInformation.ShowWarrantHeaderIcon -->\\n    </div>\\n    <div>\\n        <span class=\\"roa-text-bold ng-binding\\"> STATE OF NORTH CAROLINA VS DYLIN ROBERT JEFFRY ARMSTRONG </span>\\n    </div>\\n  </div>\\n\\n  <div flex=\\"50\\" class=\\"flex-50\\">\\n\\n    <div label=\\"Location\\" class=\\"ng-isolate-scope\\">\\n    <div class=\\"roa-header-sect-row hide-xs layout-row\\" hide-xs=\\"\\" layout=\\"row\\">\\n      <div flex=\\"\\" class=\\"roa-label ng-binding flex\\">\\n        Location:\\n      </div>\\n      <div flex=\\"\\" class=\\"roa-value flex\\" ng-transclude=\\"\\"><span class=\\"ng-binding ng-scope\\">\\n      Mecklenburg District Court\\n    </span></div>\\n    </div>\\n    <div class=\\"roa-header-sect-row hide-gt-xs layout-row\\" hide-gt-xs=\\"\\" layout=\\"row\\">\\n      <div flex=\\"\\" style=\\"text-align: left\\" class=\\"roa-label ng-binding flex\\">\\n        Location\\n      </div>\\n    </div>\\n    <div class=\\"roa-header-sect-row hide-gt-xs layout-row\\" hide-gt-xs=\\"\\" layout=\\"row\\">\\n      <div flex=\\"\\" class=\\"roa-value flex\\" ng-transclude=\\"\\"><span class=\\"ng-binding ng-scope\\">\\n      Mecklenburg District Court\\n    </span></div>\\n    </div>\\n\\n  </div>\\n\\n    <!-- ngIf: ::roaSection.headerInfo.Judge -->\\n\\n    <!-- ngIf: ::roaSection.assignmentInfo.CurrentMagistrateAssignment.Description -->\\n\\n    <div label=\\"Filed on\\" class=\\"ng-isolate-scope\\">\\n    <div class=\\"roa-header-sect-row hide-xs layout-row\\" hide-xs=\\"\\" layout=\\"row\\">\\n      <div flex=\\"\\" class=\\"roa-label ng-binding flex\\">\\n        Filed on:\\n      </div>\\n      <div flex=\\"\\" class=\\