-- end ngIf: ::data.roaSections.dispositionEvents && data.Options.DispFirst !== '1' -->\\n      <!-- ngIf: ::data.roaSections.hearingsSection --><div ng-include-template=\\"Areas/RegisterOfActions/Views/ROA/Templates/RoA_Section_Template.html\\" ng-include-variables=\\"{roaSection: data.roaSections.hearingsSection, data: data, $scope: this}\\" ng-if=\\"::data.roaSections.hearingsSection\\" class=\\"ng-scope ng-isolate-scope\\"><!-- ngIf: roaSection.showSection --><section ng-if=\\"roaSection.showSection\\" class=\\"ng-scope\\" style=\\"\\">\\n  <md-card class=\\"no-print-section-border md-tyler-default-theme-theme\\">\\n    <md-toolbar class=\\"roa-section-header md-tyler-default-theme-theme\\" data-header-text=\\"Hearings\\" id=\\"hearings\\" ng-class=\\"::{'no-print-section-header': skipHeader}\\">\\n    <div class=\\"md-toolbar-tools\\">\\n      <!-- ngIf: $scope.selectedSection === $args.id -->\\n      <h1>\\n        <span class=\\"header-text ng-binding\\">Hearings</span>\\n      </h1>\\n    </div>\\n  </md-toolbar>\\n    <md-card-content class=\\"roa-section-content\\">\\n      <!-- In general, the sections will work like this:\\n      - Initial load: showSection = false. nothing shows (exception - basic case info always has showSection = true and sets loading = true to show an indicator)\\n      - Error on load: showSection = true, loading = false, error = error text. Section is shown with error text.\\n      - Load success, but no data: showSection = false. nothing shows\\n      - Data exists: showSection = true, loading = false, error = null.\\n      -->\\n      <!-- ngIf: roaSection.loading -->\\n      <!-- ngIf: roaSection.error -->\\n      <!-- ngInclude: undefined --><ng-include ng-show=\\"!roaSection.loading &amp;&amp; !roaSection.error\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + roaSection.template\\" class=\\"ng-scope\\" aria-hidden=\\"false\\" style=\\"\\"><md-content layout=\\"column\\" class=\\"print-prevent-split ng-scope md-tyler-default-theme-theme layout-column\\">\\n  <!-- ngRepeat: event in roaSection.hearingInfo.Hearings --><div class=\\"roa-pad-0 roa-event-info ng-scope roa-event-info-hearing-event\\" ng-show=\\"::roaSection.hearingInfo\\" ng-repeat=\\"event in roaSection.hearingInfo.Hearings\\" ng-class=\\"::'roa-event-info-' + $scope.camelCaseToDash(event.Type || 'undefined')\\" aria-hidden=\\"false\\">\\n\\n    <div ng-style=\\"::$scope.getCustomCss(event)\\" style=\\"margin-left: 0px;\\">\\n      <div class=\\"roa-pad-bottom roa-event-hearing-event\\" ng-class=\\"::$scope.getClassForEventTemplate(event)\\">\\n        <!-- ngInclude: undefined --><ng-include src=\\"::$scope.getEventTemplate(event)\\" ng-init=\\"hearingEvent = null; minuteEvent = false;\\" class=\\"ng-scope\\" style=\\"\\"><div class=\\"roa-event-row ng-scope\\">\\n\\n  <!-- ngIf: ::!minuteEvent --><div class=\\"roa-event-date-col ng-scope\\" ng-if=\\"::!minuteEvent\\" id=\\"Event_1312070278\\">\\n    <div ng-transclude=\\"\\" ng-class=\\"::{'roa-text-strike': event.Event.IsDeleted}\\">\\n    <!-- ngIf: ::event.SortEventDate == '1' -->\\n    <!-- ngIf: ::event.SortEventDate != '1' --><span ng-if=\\"::event.SortEventDate != '1'\\" class=\\"ng-binding ng-scope\\">\\n      03/02/2026\\n    </span><!-- end ngIf: ::event.SortEventDate != '1' -->\\n  </div>\\n  </div><!-- end ngIf: ::!minuteEvent -->\\n\\n  <div class=\\"roa-event-content\\" ng-class=\\"::{'roa-text-stike' : event.Event.IsDeleted }\\">\\n    <div>\\n      <roa-documents><!-- ngIf: ::$scope.greaterThan(event.DocumentCount,0) --></roa-documents>\\n\\n      <!--TODO(UI): Review where lead event image shows -->\\n      <span title=\\"This event was added on the Lead case after consolidation.\\" ng-show=\\"::event.Event.FromLead\\" aria-hidden=\\"true\\" class=\\"ng-hide\\">\\n        <img class=\\"roa-icon\\" src=\\"Content/images/Shared.gif\\">\\n      </span>\\n\\n      <!-- ngIf: ::event.ActiveSettingsCount == 0 -->\\n\\n      <span class=\\"roa-text-bold ng-binding\\">\\n        Disposition Hearing\\n      </span>\\n\\n      <!-- ngIf: ::event.HearingTime --><span ng-if=\\"::event.HearingTime\\" class=\\"roa-indent ng-scope\\">\\n        <!-- ngIf: ::isMinutesSection && event.Event.Setting && event.Event.Setting.Date -->\\n        <!-- ngIf: ::!isMinutesSection --><span ng-if=\\"::!isMinutesSection\\" class=\\"ng-scope\\">\\n          <span class=\\"ng-binding\\">(8:45 AM)</span>\\n        </span><!-- end ngIf: ::!isMinutesSection -->\\n      </span><!-- end ngIf: ::event.HearingTime -->\\n\\n      <!-- ngIf: ::event.JudgeOrMagistrate -->\\n    </div>\\n\\n\\n    <!-- ngIf: ::data.Options.EventCmnt == '1' && data.Options.CaseEventCommentsBelowDesc == '1' --><div ng-if=\\"::data.Options.EventCmnt == '1' &amp;&amp; data.Options.CaseEventCommentsBelowDesc == '1'\\" class=\\"roa-indent-2 roa-text-italic ng-binding ng-scope\\">\\n      \\n    </div><!-- end ngIf: ::data.Options.EventCmnt == '1' && data.Options.CaseEventCommentsBelowDesc == '1' -->\\n\\n\\n\\n    <!-- ngIf: ::event.HearingDate2DateRange -->\\n\\n\\n    <!-- ngRepeat: resource in ::event.CalendarResources --><!-- ngIf: ::event.CalendarResources.length --><div ng-if=\\"::event.CalendarResources.length\\" ng-repeat=\\"resource in ::event.CalendarResources\\" class=\\"roa-indent-2 ng-binding ng-scope\\">\\n      Resource: Location  590-1130 Mecklenburg Co. Courthouse, Courtroom 1130\\n    </div><!-- end ngIf: ::event.CalendarResources.length --><!-- end ngRepeat: resource in ::event.CalendarResources -->\\n\\n\\n    <!-- ngIf: ::event.ParentEvents.length && data.Options.RelatedEventView != '1' -->\\n\\n    <!-- ngIf: ::data.Options.EventCmnt == '1' && data.Options.CaseEventCommentsBelowDesc == '0' -->\\n\\n    <!--TODO(UI): Review setting indentation -->\\n    <!-- ngRepeat: setting in ::event.CancelOrRescheduleSettings -->\\n\\n    <!-- MINUTES BEGIN -->\\n    <!--TODO(UI): Move setting and event retrieval to code to match sorting in Ody -->\\n    <!-- ngRepeat: minuteSetting in ::event.MinutesData | orderBy:'-SettingId' --><!-- ngIf: ::!isMinutesSection && data.Options.ShowMinutesDetails == '1' --><section class=\\"roa-indent-2 ng-scope\\" ng-repeat=\\"minuteSetting in ::event.MinutesData | orderBy:'-SettingId'\\" ng-if=\\"::!isMinutesSection &amp;&amp; data.Options.ShowMinutesDetails == '1'\\">\\n      <span class=\\"no-print-padding roa-text-bold\\" style=\\"padding-top:.5rem;\\">\\n        MINUTES -\\n        <!-- ngRepeat: mse in ::event.Event.Settings | filter: {SettingId: minuteSetting.SettingId} --><span ng-repeat=\\"mse in ::event.Event.Settings | filter: {SettingId: minuteSetting.SettingId}\\" class=\\"ng-binding ng-scope\\">\\n          03/02/2026\\n        </span><!-- end ngRepeat: mse in ::event.Event.Settings | filter: {SettingId: minuteSetting.SettingId} -->\\n      </span>\\n\\n      <div>\\n\\n        <!-- ngRepeat: minuteEvent in minuteSetting.MinutesEvents --><!-- ngIf: ::data.Options.ShowMinutesDetails == '1' && !isMinutesSection && !(minuteEvent.Type == 'JudgmentEvent' && data.Options.ShowAmendHists == '1') --><div ng-repeat=\\"minuteEvent in minuteSetting.MinutesEvents\\" ng-if=\\"::data.Options.ShowMinutesDetails == '1' &amp;&amp; !isMinutesSection &amp;&amp; !(minuteEvent.Type == 'JudgmentEvent' &amp;&amp; data.Options.ShowAmendHists == '1')\\" ng-init=\\"hearingEvent = event; event = roaSection.getEvent(minuteEvent.EventId); isMinutesSection = true;\\" class=\\"ng-scope\\">\\n          <!-- ngInclude: undefined --><ng-include src=\\"::$scope.getEventTemplate(event)\\" flex-sm=\\"100\\" flex-md=\\"100\\" flex-lg=\\"100\\" flex-gt-lg=\\"100\\" class=\\"ng-scope flex-sm-100 flex-md-100 flex-lg-100 flex-gt-lg-100\\" style=\\"\\"><div data-rem-class=\\"roa-event-row\\" ng-class=\\"::{'roa-text-strike':event.Event.IsDeleted}\\" class=\\"ng-scope\\">\\n\\n  <!-- ngIf: ::!minuteEvent -->\\n  <!-- ngIf: ::minuteEvent --><div class=\\"roa-inline roa-align-top roa-event-date-col ng-scope\\" ng-if=\\"::minuteEvent\\" style=\\"min-width:11rem\\">\\n    <div ng-transclude=\\"\\" ng-class=\\"::{'roa-text-strike': event.Event.IsDeleted}\\">\\n    <!-- ngIf: ::hearingEvent.Event.Setting.Date != event.Event.Date --><div ng-if=\\"::hearingEvent.Event.Setting.Date != event.Event.Date\\" ng-style=\\"{'margin-left': $scope.getMinuteEventLeftMarginOffset(hearingEvent.EventId)}\\" class=\\"ng-binding ng-scope\\" style=\\"margin-left: -110px;\\">\\n        03/03/2026\\n    </div><!-- end ngIf: ::hearingEvent.Event.Setting.Date != event.Event.Date -->\\n  </div>\\n  </div><!-- end ngIf: ::minuteEvent -->\\n\\n  <div data-rem-class=\\"roa-event-content\\" class=\\"roa-inline roa-align-top\\" style=\\"min-width:calc(100% - 24rem)\\">\\n\\n    <div>\\n      <div>\\n\\n        <roa-documents><!-- ngIf: ::$scope.greaterThan(event.DocumentCount,0) --></roa-documents>\\n\\n        <!--TODO(UI): Review where lead event image shows -->\\n        <!-- ngIf: ::event.Event.FromLead -->\\n\\n\\n        <!-- ngIf: ::(data.Options.EventCmnt == '1' || event.Event.TypeId.Word == 'HSA')\\n         && data.Options.CaseEventCommentsBelowDesc == '0'\\n         && event.Event.Comment -->\\n\\n        <div class=\\"roa-data ng-isolate-scope\\" label=\\"Called and Failed\\">\\n    <!-- ngIf: ::label --><div class=\\"roa-label roa-inline roa-align-top ng-binding ng-scope\\" ng-if=\\"::label\\" ng-bind=\\"::label\\">Called and Failed</div><!-- end ngIf: ::label -->\\n    <!-- ngIf: ::value -->\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude=\\"\\">\\n          <!-- ngIf: ::event.Event.JudgeId.Description --><span ng-if=\\"::event.Event.JudgeId.Description\\" class=\\"roa-indent ng-scope\\">\\n            (Judicial Officer: <span ng-bind=\\"::event.Event.JudgeId.Description\\" class=\\"ng-binding\\">JENKINS, TARITA M</span>)\\n          </span><!-- end ngIf: ::event.Event.JudgeId.Description -->\\n        </div>\\n  </div>\\n\\n        <!-- ngIf: ::(data.Options.EventCmnt == '1' || event.Event.TypeId.Word == 'HSA')\\n         && data.Options.CaseEventCommentsBelowDesc == '1'\\n         && event.Event.Comment -->\\n\\n      </div>\\n\\n      <!-- ngIf: ::event.Event.Date2 -->\\n\\n      <!-- ngIf: ::event.Event.InstrumentNumber -->\\n\\n      <!-- ngIf: ::event.Event.FilerTypeCode -->\\n\\n      <!-- ngIf: ::event.Event.Partys.length -->\\n\\n      <!-- ngIf: ::data.Options.IncludeChargeDescriptions ==  '1' --><div ng-if=\\"::data.Options.IncludeChargeDescriptions ==  '1'\\" class=\\"ng-scope\\">\\n        <!-- ngIf: ::event.Charges.length -->\\n        <div class=\\"roa-indent\\">\\n          <table class=\\"roa-table\\">\\n            <tbody><!-- ngRepeat: charge in ::event.Charges -->\\n          </tbody></table>\\n        </div>\\n      </div><!-- end ngIf: ::data.Options.IncludeChargeDescriptions ==  '1' -->\\n      <!-- ngIf: ::data.Options.IncludeChargeDescriptions !=  '1' -->\\n      <!-- ngIf: ::event.Causes.length -->\\n\\n\\n      <!-- ngIf: ::data.Options.OCMDisplayEventAmount == '1' && event.Event.EventAmount -->\\n\\n      <!-- ngIf: ::data.Options.ShowTimestampCreate == '1' --><div ng-if=\\"::data.Options.ShowTimestampCreate == '1'\\" class=\\"roa-indent-2 ng-scope\\">\\n    <div class=\\"roa-data ng-isolate-scope\\" label=\\"Created:\\">\\n    <!-- ngIf: ::label --><div class=\\"roa-label roa-inline roa-align-top ng-binding ng-scope\\" ng-if=\\"::label\\" ng-bind=\\"::label\\">Created:</div><!-- end ngIf: ::label -->\\n    <!-- ngIf: ::value -->\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude=\\"\\"><span class=\\"ng-binding ng-scope\\">\\n      03/03/2026 3:38 PM\\n    </span></div>\\n  </div>\\n  </div><!-- end ngIf: ::data.Options.ShowTimestampCreate == '1' -->\\n      <!-- ngIf: ::event.DocumentLoadFailureMessage -->\\n\\n\\n      <!-- ngIf: ::data.Options.ShowNotifications ==  '1' -->\\n    </div>\\n\\n  <div ng-class=\\"::$scope.checkEventDiffPriorsClass(event, 0)\\" data-rem-class=\\"roa-event-content-2\\" class=\\"roa-inline roa-align-top\\" style=\\"min-width:11rem\\">\\n\\n    <!-- ngIf: ::data.Options.DocIndex == '1' && event.Event.DocumentIndex --><div ng-if=\\"::data.Options.DocIndex == '1' &amp;&amp; event.Event.DocumentIndex\\" class=\\"ng-binding ng-scope\\">\\n      Index #\\n      3\\n    </div><!-- end ngIf: ::data.Options.DocIndex == '1' && event.Event.DocumentIndex -->\\n\\n  </div>\\n\\n</div>\\n</div></ng-include>\\n        </div><!-- end ngIf: ::data.Options.ShowMinutesDetails == '1' && !isMinutesSection && !(minuteEvent.Type == 'JudgmentEvent' && data.Options.ShowAmendHists == '1') --><!-- end ngRepeat: minuteEvent in minuteSetting.MinutesEvents -->\\n      </div>\\n\\n      <!-- ngRepeat: minuteWarrant in ::minuteSetting.MinutesWarrants -->\\n\\n\\n      <!-- ngRepeat: evtSetting in ::event.Event.Settings | filter: { SettingId: minuteSetting.SettingId } --><div ng-repeat=\\"evtSetting in ::event.Event.Settings | filter: { SettingId: minuteSetting.SettingId }\\" class=\\"ng-scope\\">\\n        <!-- | filter: { SettingId: minuteSetting.SettingId }\\"> -->\\n        <!-- ngIf: ::evtSetting.ResultId.Description --><span ng-if=\\"::evtSetting.ResultId.Description\\" class=\\"ng-binding ng-scope\\">\\n          Called &amp; Failed;\\n        </span><!-- end ngIf: ::evtSetting.ResultId.Description -->\\n        <!-- ngIf: ::evtSetting.Comment -->\\n      </div><!-- end ngRepeat: evtSetting in ::event.Event.Settings | filter: { SettingId: minuteSetting.SettingId } -->\\n\\n      <!-- ngIf: ::data.Options.ShowJournalEntryDetails == '1'\\n         && $scope.hasValue(minuteSetting.MinutesJournals) && minuteSetting.MinutesJournals.length -->\\n\\n      <!-- ngIf: ::data.Options.Causes == '1' -->\\n      \\n      <!-- Since placements are not paged, we can be guaranteed that the data will exist from the Placements load. -->\\n      <!-- ngRepeat: minutePlacement in ::minuteSetting.MinutesPlacements -->\\n\\n      <!-- ngIf: ::minuteSetting.MinutesPartyConnections.length && data.Options.ShowPartiesPresent == '1' -->\\n\\n\\n\\n\\n    </section><!-- end ngIf: ::!isMinutesSection && data.Options.ShowMinutesDetails == '1' --><!-- end ngRepeat: minuteSetting in ::event.MinutesData | orderBy:'-SettingId' -->\\n\\n    <!-- MINUTES END -->\\n\\n    <div class=\\"roa-indent-2\\">\\n      <!-- ngIf: ::data.Options.ShowResultCodes == '1' && event.Event.Setting.ResultId.Description --><div class=\\"roa-text-italic roa-indent-2 ng-binding ng-scope\\" ng-if=\\"::data.Options.ShowResultCodes == '1' &amp;&amp; event.Event.Setting.ResultId.Description\\">\\n        Called &amp; Failed\\n      </div><!-- end ngIf: ::data.Options.ShowResultCodes == '1' && event.Event.Setting.ResultId.Description -->\\n\\n      <!--div layout=\\"row\\" flex class=\\"roa-text-italic roa-indent-2\\"\\n           ng-if=\\"::event.Event.Setting.PartiesPresentV1.length && data.Options.ShowPartiesPresent == '1'\\">\\n        <div flex=\\"none\\">Parties Present:&nbsp;</div>\\n        <div flex>\\n          <div ng-repeat=\\"partyPresent in event.Event.Setting.PartiesPresentV1\\">\\n            <div ng-repeat=\\"attorneyPresent in partyPresent.PartyPresentAttorneys\\">\\n              <div layout=\\"row\\" ng-if=\\"::attorneyPresent.FormattedName\\">\\n                <span flex=\\"25\\">{{attorneyPresent.CasePartyConnection.ExtendedConnectionId.Description}}</span>\\n                <span>{{attorneyPresent.FormattedName}}</span>\\n              </div>\\n            </div>\\n            <div layout=\\"row\\" ng-if=\\"::partyPresent.FormattedName\\">\\n              <span flex=\\"25\\">{{partyPresent.CasePartyConnection.ExtendedConnectionId.Description}}</span>\\n              <span>{{partyPresent.FormattedName}}</span>\\n            </div>\\n          </div>\\n        </div>\\n      </div-->\\n\\n      <!-- ngRepeat: minuteEvent in ::roaSection.eventInfo | filter: { Type: 'HearingEvent', MinutesSettingHearingEventId: event.EventId, MinutesSettingSettingId: minuteSetting.SettingId } -->\\n      <!-- ngIf: ::data.Options.ShowMinutesDetails == '1' && !isMinutesSection --><div ng-if=\\"::data.Options.ShowMinutesDetails == '1' &amp;&amp; !isMinutesSection\\" class=\\"ng-scope\\">\\n\\n        <!-- ngRepeat: minuteEvent in ::roaSection.eventInfo | filter: { Type: 'HearingEvent', MinutesSettingHearingEventId: event.EventId, MinutesSettingSettingId: minuteSetting.SettingId } -->\\n      </div><!-- end ngIf: ::data.Options.ShowMinutesDetails == '1' && !isMinutesSection -->\\n\\n      <!-- ngIf: ::event.HearingChargeNumbers -->\\n\\n      <!-- ngIf: ::event.ActiveSettingsCount == 0 && event.Event.CanceledReasonId.Description -->\\n    </div>\\n    <!-- ngIf: ::data.Options.ShowTimestampCreate == '1' --><div ng-if=\\"::data.Options.ShowTimestampCreate == '1'\\" class=\\"ng-scope\\">\\n    <div class=\\"roa-data ng-isolate-scope\\" label=\\"Created:\\">\\n    <!-- ngIf: ::label --><div class=\\"roa-label roa-inline roa-align-top ng-binding ng-scope\\" ng-if=\\"::label\\" ng-bind=\\"::label\\">Created:</div><!-- end ngIf: ::label -->\\n    <!-- ngIf: ::value -->\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude=\\"\\"><span class=\\"ng-binding ng-scope\\">\\n      01/01/0001 12:00 AM\\n    </span></div>\\n  </div>\\n  </div><!-- end ngIf: ::data.Options.ShowTimestampCreate == '1' -->\\n\\n  </div>\\n\\n\\n\\n</div>\\n</ng-include>\\n      </div>\\n    </div>\\n  </div><!-- end ngRepeat: event in roaSection.hearingInfo.Hearings -->\\n\\n  <!-- Several of the documented attributes do nothing. I think this is using an old version of bootstrap.\\n  If we end up updating the web app template, use tt-pagination instead. -->\\n  <!-- ngIf: roaSection.enablePaging -->\\n</md-content>\\n</ng-include>\\n    </md-card-content>\\n  </md-card>\\n</section><!-- end ngIf: roaSection.showSection --></div><!-- end ngIf: ::data.roaSections.hearingsSection -->\\n      <!-- ngIf: ::data.roaSections.hearingNoticesSectio