            <!-- The Sheriff's Contingency calculation component (AddChargeComponentID='27') -->\\n                <!-- ngSwitchWhen: 27 -->\\n\\n                <!-- The Address of Offense component (AddChargeComponentID='34') -->\\n                <!-- ngSwitchWhen: 34 -->\\n\\n                <!-- The Drug Type component (AddChargeComponentID='37') -->\\n                <!-- ngSwitchWhen: 37 -->\\n\\n                <!-- The Charge Qualifier -  Weapons component (AddChargeComponentID='41') -->\\n                <!-- ngSwitchWhen: 41 -->\\n\\n                <!-- The Charge Qualifier - Amount component (AddChargeComponentID='44') -->\\n                <!-- ngSwitchWhen: 44 -->\\n\\n                <!-- The DUI Group component (AddChargeComponentID='46') -->\\n                <!-- ngSwitchWhen: 46 -->\\n\\n                <!-- The Report To DNR component (AddChargeComponentID='48') -->\\n                <!-- ngSwitchWhen: 48 -->\\n\\n                <!-- The DA Charging Paragraph component (AddChargeComponentID='53') -->\\n                <!-- ngSwitchWhen: 53 -->\\n\\n                <!-- The DUI Group component (AddChargeComponentID='54') -->\\n                <!-- ngSwitchWhen: 54 -->\\n\\n                <!-- The Speeding Group component GA (AddChargeComponentID='55') -->\\n                <!-- ngSwitchWhen: 55 -->\\n\\n                <!-- The Speeding Fine Calculation component GA, FL (AddChargeComponentID='56') -->\\n                <!-- ngSwitchWhen: 56 -->\\n\\n                <!-- The Hot Check Fields component (AddChargeComponentID='58') -->\\n                <!-- ngSwitchWhen: 58 -->\\n\\n                <!-- The Overweight Fine Calculation (Rated/Actual) component (AddChargeComponentID='59') -->\\n                <!-- ngSwitchWhen: 59 -->\\n\\n                <!-- The Blood Alcohol Content component (AddChargeComponentID='60') -->\\n                <!-- ngSwitchWhen: 60 -->\\n\\n                <!-- The Predatory Offender component (AddChargeComponentID='61') -->\\n                <!-- ngSwitchWhen: 61 -->\\n\\n                <!-- The Address of Offense component (AddChargeComponentID='62') -->\\n                <!-- ngSwitchWhen: 62 -->\\n\\n                <!-- The Drug Amount component (AddChargeComponentID='63') -->\\n                <!-- ngSwitchWhen: 63 -->\\n\\n                <!-- The Blood Alcohol Content Status component (AddChargeComponentID='64') -->\\n                <!-- ngSwitchWhen: 64 -->\\n\\n                <!-- The Blood Alcohol Content Level component (AddChargeComponentID='65') -->\\n                <!-- ngSwitchWhen: 65 -->\\n\\n                <!-- The Speeding Fine Calculation component (AddChargeComponentID='66') -->\\n                <!-- ngSwitchWhen: 66 -->\\n\\n                <!-- The Send to DOT component (AddChargeComponentID='67') -->\\n                <!-- ngSwitchWhen: 67 -->\\n\\n                <!-- MN 3rd Violation Enhancement To Misd (AddChargeComponentID='68') -->\\n                <!-- ngSwitchWhen: 68 -->\\n\\n                <!-- NC Implied Consent -->\\n               <!-- ngIf: ::additionalChargeComponent.AdditionalChargeComponentCode == 'NCIMPLCON' -->\\n              </div><!-- end ngRepeat: additionalChargeComponent in ::charge.ChargeOffense.AdditionalChargeComponentInstances -->\\n            </div><!-- end ngIf: ::charge.ChargeOffense.AdditionalChargeComponentInstances.length -->\\n\\n            <!-- Original (of an amended) Charge -->\\n            <!-- ngIf: ::charge.OriginalChargeOffense -->\\n\\n            <!-- Charge Track and Sequence Numbers -->\\n            <!-- ngIf: ::roaSection.chargeInfo.ChargeTrackNumberLabel && charge.ChargeTrackingNumber -->\\n\\n            <!-- ngIf: ::roaSection.chargeInfo.ChargeSequenceNumberLabel && charge.ChargeSequenceNumber -->\\n\\n          </div>\\n        </td>\\n      </tr>\\n      <tr ng-repeat-end=\\"\\" class=\\"ng-scope\\"></tr><!-- end ngRepeat: charge in filteredCharges = (roaSection.chargeInfo.Charges | filter: { PartyId: partyConfig.PartyId }) -->\\n    </tbody><!-- end ngRepeat: partyConfig in ::roaSection.chargeInfo.PartyConfigs -->\\n  </table>\\n\\n</div><!-- end ngIf: ::roaSection.chargeInfo.ShowOffenses -->\\n\\n</ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: ::roaSection.relationsInfo.ShowRelations --><div class=\\"roa-subsection ng-scope\\" ng-if=\\"::roaSection.relationsInfo.ShowRelations\\">\\n\\n  <div class=\\"roa-subsection-heading\\">\\n    Related Cases\\n  </div>\\n\\n  <!-- ngIf: ::roaSection.relationsInfo.LeadCases.length -->\\n\\n  <!-- ngIf: ::roaSection.relationsInfo.SubordinateCases.length -->\\n\\n  <!-- ngIf: ::roaSection.relationsInfo.FamilyLeadCases.length -->\\n\\n  <!-- ngIf: ::roaSection.relationsInfo.OtherCases.length -->\\n</div><!-- end ngIf: ::roaSection.relationsInfo.ShowRelations -->\\n</ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: ::roaSection.lowerCourtCasesInfo.ShowLowerCourtCases -->\\n</ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: ::roaSection.dispositionInfo.ShowDispositions -->\\n</ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: ::roaSection.warrantInfo.ShowWarrants -->\\n</ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: ::roaSection.bondInfo.ShowBonds --></ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: data.Options.ShowGroundsForDivorce == '1' && roaSection.divorceInfo != null && roaSection.divorceInfo != undefined && roaSection.divorceInfo.GroundsForDivorce.length > 0 --></ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates -->\\n</div>\\n\\n</ng-include>\\n    </md-card-content>\\n  </md-card>\\n</section><!-- end ngIf: roaSection.showSection --></div><!-- end ngIf: ::data.roaSections.caseInformation -->\\n      <!-- ngIf: ::data.roaSections.assignmentInformation --><div ng-include-template=\\"Areas/RegisterOfActions/Views/ROA/Templates/RoA_Section_Template.html\\" ng-include-variables=\\"{roaSection: data.roaSections.assignmentInformation, data: data, $scope: this}\\" ng-if=\\"::data.roaSections.assignmentInformation\\" class=\\"ng-scope ng-isolate-scope\\" style=\\"\\"><!-- ngIf: roaSection.showSection --><section ng-if=\\"roaSection.showSection\\" class=\\"ng-scope\\">\\n  <md-card class=\\"no-print-section-border md-tyler-default-theme-theme\\">\\n    <md-toolbar class=\\"roa-section-header md-tyler-default-theme-theme\\" data-header-text=\\"Assignment Information\\" id=\\"assignment-info\\" ng-class=\\"::{'no-print-section-header': skipHeader}\\">\\n    <div class=\\"md-toolbar-tools\\">\\n      <!-- ngIf: $scope.selectedSection === $args.id -->\\n      <h1>\\n        <span class=\\"header-text ng-binding\\">Assignment Information</span>\\n      </h1>\\n    </div>\\n  </md-toolbar>\\n    <md-card-content class=\\"roa-section-content\\">\\n      <!-- In general, the sections will work like this:\\n      - Initial load: showSection = false. nothing shows (exception - basic case info always has showSection = true and sets loading = true to show an indicator)\\n      - Error on load: showSection = true, loading = false, error = error text. Section is shown with error text.\\n      - Load success, but no data: showSection = false. nothing shows\\n      - Data exists: showSection = true, loading = false, error = null.\\n      -->\\n      <!-- ngIf: roaSection.loading -->\\n      <!-- ngIf: roaSection.error -->\\n      <!-- ngInclude: undefined --><ng-include ng-show=\\"!roaSection.loading &amp;&amp; !roaSection.error\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + roaSection.template\\" class=\\"ng-scope\\" aria-hidden=\\"false\\" style=\\"\\"><div class=\\"ng-scope\\">\\n  <div layout-gt-sm=\\"row\\" class=\\"layout-gt-sm-row\\">\\n    <div flex=\\"10\\" class=\\"flex-10\\"></div>\\n    <div flex=\\"90\\" class=\\"flex-90\\">\\n\\n      <div class=\\"roa-text-bold\\">Current Case Assignment</div>\\n\\n\\n      <div class=\\"roa-data-table roa-pad-bottom\\">\\n        <div class=\\"roa-data ng-isolate-scope\\" label=\\"Case Number\\">\\n    <!-- ngIf: ::label --><div class=\\"roa-label roa-inline roa-align-top ng-binding ng-scope\\" ng-if=\\"::label\\" ng-bind=\\"::label\\">Case Number</div><!-- end ngIf: ::label -->\\n    <!-- ngIf: ::value -->\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude=\\"\\"><span class=\\"ng-binding ng-scope\\">\\n          25IF012559-590\\n        </span></div>\\n  </div>\\n\\n        <div class=\\"