op ng-binding ng-scope\\" ng-if=\\"::label\\" ng-bind=\\"::label\\">Created:</div><!-- end ngIf: ::label -->\\n    <!-- ngIf: ::value -->\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude=\\"\\"><span class=\\"ng-binding ng-scope\\">\\n      01/01/0001 12:00 AM\\n    </span></div>\\n  </div>\\n  </div><!-- end ngIf: ::data.Options.ShowTimestampCreate == '1' -->\\n\\n  </div>\\n\\n\\n\\n</div>\\n</ng-include>\\n      </div>\\n    </div>\\n  </div><!-- end ngRepeat: event in roaSection.hearingInfo.Hearings -->\\n\\n  <!-- Several of the documented attributes do nothing. I think this is using an old version of bootstrap.\\n  If we end up updating the web app template, use tt-pagination instead. -->\\n  <!-- ngIf: roaSection.enablePaging -->\\n</md-content>\\n</ng-include>\\n    </md-card-content>\\n  </md-card>\\n</section><!-- end ngIf: roaSection.showSection --></div><!-- end ngIf: ::data.roaSections.hearingsSection -->\\n      <!-- ngIf: ::data.roaSections.hearingNoticesSection -->\\n      <!-- ngIf: ::data.roaSections.conditionsSection --><div ng-include-template=\\"Areas/RegisterOfActions/Views/ROA/Templates/RoA_Section_Template.html\\" ng-include-variables=\\"{roaSection: data.roaSections.conditionsSection, data: data, $scope: this}\\" ng-if=\\"::data.roaSections.conditionsSection\\" class=\\"ng-scope ng-isolate-scope\\"><!-- ngIf: roaSection.showSection --></div><!-- end ngIf: ::data.roaSections.conditionsSection -->\\n      <!-- ngIf: ::data.roaSections.serviceEventsSection --><div ng-include-template=\\"Areas/RegisterOfActions/Views/ROA/Templates/RoA_Section_Template.html\\" ng-include-variables=\\"{roaSection: data.roaSections.serviceEventsSection, data: data, $scope: this}\\" ng-if=\\"::data.roaSections.serviceEventsSection\\" class=\\"ng-scope ng-isolate-scope\\"><!-- ngIf: roaSection.showSection --></div><!-- end ngIf: ::data.roaSections.serviceEventsSection -->\\n      <!-- ngIf: ::data.roaSections.bondSettingsSection --><div ng-include-template=\\"Areas/RegisterOfActions/Views/ROA/Templates/RoA_Section_Template.html\\" ng-include-variables=\\"{roaSection: data.roaSections.bondSettingsSection, data: data, $scope: this}\\" ng-if=\\"::data.roaSections.bondSettingsSection\\" class=\\"ng-scope ng-isolate-scope\\"><!-- ngIf: roaSection.showSection --></div><!-- end ngIf: ::data.roaSections.bondSettingsSection -->\\n      <!-- ngIf: ::data.roaSections.combinedEvents -->\\n      <!-- ngIf: ::data.roaSections.timeStandardSummarySection -->\\n      <!-- ngIf: ::data.roaSections.placementSection --><div ng-include-template=\\"Areas/RegisterOfActions/Views/ROA/Templates/RoA_Section_Template.html\\" ng-include-variables=\\"{roaSection: data.roaSections.placementSection, data: data, $scope: this}\\" ng-if=\\"::data.roaSections.placementSection\\" class=\\"ng-scope ng-isolate-scope\\"><!-- ngIf: roaSection.showSection --></div><!-- end ngIf: ::data.roaSections.placementSection -->\\n      <!-- ngIf: ::data.roaSections.otherDocumentsSection -->\\n      <!-- ngIf: ::data.roaSections.financialSummarySection --><div ng-include-template=\\"Areas/RegisterOfActions/Views/ROA/Templates/RoA_Section_Template.html\\" ng-include-variables=\\"{roaSection: data.roaSections.financialSummarySection, data: data, $scope: this}\\" ng-if=\\"::data.roaSections.financialSummarySection\\" class=\\"ng-scope ng-isolate-scope\\"><!-- ngIf: roaSection.showSection --><section ng-if=\\"roaSection.showSection\\" class=\\"ng-scope\\" style=\\"\\">\\n  <md-card class=\\"no-print-section-border md-tyler-default-theme-theme\\">\\n    <md-toolbar class=\\"roa-section-header md-tyler-default-theme-theme\\" data-header-text=\\"Financial Information\\" id=\\"financial-info\\" ng-class=\\"::{'no-print-section-header': skipHeader}\\">\\n    <div class=\\"md-toolbar-tools\\">\\n      <!-- ngIf: $scope.selectedSection === $args.id -->\\n      <h1>\\n        <span class=\\"header-text ng-binding\\">Financial Information</span>\\n      </h1>\\n    </div>\\n  </md-toolbar>\\n    <md-card-content class=\\"roa-section-content\\">\\n      <!-- In general, the sections will work like this:\\n      - Initial load: showSection = false. nothing shows (exception - basic case info always has showSection = true and sets loading = true to show an indicator)\\n      - Error on load: showSection = true, loading = false, error = error text. Section is shown with error text.\\n      - Load success, but no data: showSection = false. nothing shows\\n      - Data exists: showSection = true, loading = false, error = null.\\n      -->\\n      <!-- ngIf: roaSection.loading -->\\n      <!-- ngIf: roaSection.error -->\\n      <!-- ngInclude: undefined --><ng-include ng-show=\\"!roaSection.loading &amp;&amp; !roaSection.error\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + roaSection.template\\" class=\\"ng-scope\\" aria-hidden=\\"false\\" style=\\"\\"><div class=\\"print-font-size-medium ng-scope\\">\\n  <!-- ngIf: ::roaSection.financialInfo.ShowFinancialSummaryCaseFees --><div ng-if=\\"::roaSection.financialInfo.ShowFinancialSummaryCaseFees\\" class=\\"roa-finance-case-fees ng-scope\\">\\n\\n    <!-- ngRepeat: fee in ::roaSection.financialInfo.CaseFees --><div class=\\"roa-finance-fee roa-pad-bottom ng-scope\\" ng-repeat=\\"fee in ::roaSection.financialInfo.CaseFees\\">\\n\\n      <!-- ngIf: ::fee.ShowCategory -->\\n\\n      <div class=\\"roa-finance-row\\">\\n        <div></div>\\n        <div>\\n          <span class=\\"roa-text-bold ng-binding\\">\\n            Defendant\\n          </span>\\n          <span class=\\"roa-indent-2 ng-binding\\">\\n            ARMSTRONG, DYLIN ROBERT JEFFRY\\n          </span>\\n        </div>\\n      </div>\\n\\n      <div class=\\"roa-finance-row\\">\\n        <div></div>\\n        <div>\\n          Total Financial Assessment\\n        </div>\\n        <div class=\\"roa-text-right ng-binding\\">\\n          441.00\\n        </div>\\n      </div>\\n\\n      <!-- ngIf: ::fee.CaseFeeParty.Restitution !== null -->\\n\\n      <div class=\\"roa-finance-row\\">\\n        <div></div>\\n        <div>\\n          Total Payments and Credits\\n        </div>\\n        <div class=\\"roa-text-right ng-binding\\">\\n          0.00\\n        </div>\\n      </div>\\n\\n      <div class=\\"roa-finance-row roa-text-bold\\">\\n        <div></div>\\n        <div class=\\"ng-binding\\">\\n          Balance Due as of 05/01/2026\\n        </div>\\n        <div class=\\"roa-text-right\\">\\n          <!-- ngIf: ::!$scope.lessThan(fee.CaseFeeParty.Balance,0) --><span ng-if=\\"::!$scope.lessThan(fee.CaseFeeParty.Balance,0)\\" class=\\"ng-binding ng-scope\\">\\n            441.00\\n          </span><!-- end ngIf: ::!$scope.lessThan(fee.CaseFeeParty.Balance,0) -->\\n          <!-- ngIf: ::$scope.lessThan(fee.CaseFeeParty.Balance,0) -->\\n        </div>\\n      </div>\\n\\n      <div class=\\"roa-pad-bottom roa-pad-top\\">\\n        <!-- ngRepeat: transBalance in ::fee.CaseFeeParty.TransBalances.TransBalances --><div ng-repeat=\\"transBalance in ::fee.CaseFeeParty.TransBalances.TransBalances\\" ng-init=\\"::(adjustmentAmount = (0 + transBalance.ChgAmt - transBalance.PayAmt - transBalance.CreditAmt))\\" class=\\"roa-finance-row ng-scope\\">\\n          <div class=\\"ng-binding\\">10/14/2025</div>\\n          <div>\\n            <div class=\\"roa-column-one-third\\">\\n              <span ng-switch=\\"\\" on=\\"::transBalance.TypeKey.CodeID\\">\\n                <!-- ngSwitchWhen: C --><span ng-switch-when=\\"C\\" class=\\"ng-scope\\">Transaction Assessment</span><!-- end ngSwitchWhen: -->\\n                <!-- ngSwitchWhen: CR -->\\n                <!-- ngSwitchWhen: RED -->\\n                <!-- ngSwitchWhen: V -->\\n                <!-- ngSwitchWhen: A -->\\n                <!-- ngSwitchWhen: P -->\\n                <!-- ngSwitchWhen: I -->\\n              </span>\\n            </div>\\n\\n            <div class=\\"roa-column-one-third\\">\\n              <!-- ngIf: ::transBalance.TypeKey.CodeID == 'P' -->\\n            </div>\\n\\n            <div class=\\"roa-column-one-third\\">\\n              <!-- ngIf: $scope.greaterThan(transBalance.PayorID,0) -->\\n              <!-- ngIf: transBalance.PayorID === 0 --><span ng-if=\\"transBalance.PayorID === 0\\" class=\\"ng-binding ng-scope\\">\\n                \\n              </span><!-- end ngIf: transBalance.PayorID === 0 -->\\n            </div>\\n          </div>\\n\\n          <div class=\\"roa-text-right\\">\\n            <span ng-switch=\\"\\" on=\\"::transBalance.TypeKey.CodeID\\">\\n              <!-- ngSwitchWhen: C --><span ng-switch-when=\\"C\\" class=\\"ng-binding ng-scope\\">\\n                50.00\\n              </span><!-- end ngSwitchWhen: -->\\n              <!-- ngSwitchWhen: CR -->\\n              <!-- ngSwitchWhen: RED -->\\n              <!-- ngSwitchWhen: V -->\\n              <!-- ngSwitchWhen: A -->\\n              <!-- ngSwitchWhen: P -->\\n              <!-- ngSwitchWhen: I -->\\n            </span>\\n          </div>\\n        </div><!-- end ngRepeat: transBalance in ::fee.CaseFeeParty.TransBalances.TransBalances --><div ng-repeat=\\"transBalance in ::fee.CaseFeeParty.TransBalances.TransBalances\\" ng-init=\\"::(adjustmentAmount = (0 + transBalance.ChgAmt - transBalance.PayAmt - transBalance.CreditAmt))\\" class=\\"roa-finance-row ng-scope\\">\\n          <div class=\\"ng-binding\\">10/14/2025</div>\\n          <div>\\n            <div class=\\"roa-column-one-third\\">\\n              <span ng-switch=\\"\\" on=\\"::transBalance.TypeKey.CodeID\\">\\n                <!-- ngSwitchWhen: C --><span ng-switch-when=\\"C\\" class=\\"ng-scope\\">Transaction Assessment</span><!-- end ngSwitchWhen: -->\\n                <!-- ngSwitchWhen: CR -->\\n                <!-- ngSwitchWhen: RED -->\\n                <!-- ngSwitchWhen: V -->\\n                <!-- ngSwitchWhen: A -->\\n                <!-- ngSwitchWhen: P -->\\n                <!-- ngSwitchWhen: I -->\\n              </span>\\n            </div>\\n\\n            <div class=\\"roa-column-one-third\\">\\n              <!-- ngIf: ::transBalance.TypeKey.CodeID == 'P' -->\\n            </div>\\n\\n            <div class=\\"roa-column-one-third\\">\\n              <!-- ngIf: $scope.greaterThan(transBalance.PayorID,0) -->\\n              <!-- ngIf: transBalance.PayorID === 0 --><span ng-if=\\"transBalance.PayorID === 0\\" class=\\"ng-binding ng-scope\\">\\n                \\n              </span><!-- end ngIf: transBalance.PayorID === 0 -->\\n            </div>\\n          </div>\\n\\n          <div class=\\"roa-text-right\\">\\n            <span ng-switch=\\"\\" on=\\"::transBalance.TypeKey.CodeID\\">\\n              <!-- ngSwitchWhen: C --><span ng-switch-when=\\"C\\" class=\\"ng-binding ng-scope\\">\\n                191.00\\n              </span><!-- end ngSwitchWhen: -->\\n              <!-- ngSwitchWhen: CR -->\\n              <!-- ngSwitchWhen: RED -->\\n              <!-- ngSwitchWhen: V -->\\n              <!-- ngSwitchWhen: A -->\\n              <!-- ngSwitchWhen: P -->\\n              <!-- ngSwitchWhen: I -->\\n            </span>\\n          </div>\\n        </div><!-- end ngRepeat: transBalance in ::fee.CaseFeeParty.TransBalances.TransBalances --><div ng-repeat=\\"transBalance in ::fee.CaseFeeParty.TransBalances.TransBalances\\" ng-init=\\"::(adjustmentAmount = (0 + transBalance.ChgAmt - transBalance.PayAmt - transBalance.CreditAmt))\\" class=\\"roa-finance-row ng-scope\\">\\n          <div class=\\"ng-binding\\">03/23/2026</div>\\n          <div>\\n            <div class=\\"roa-column-one-third\\">\\n              <span ng-switch=\\"\\" on=\\"::transBalance.TypeKey.CodeID\\">\\n                <!-- ngSwitchWhen: C --><span ng-switch-when=\\"C\\" class=\\"ng-scope\\">Transaction Assessment</span><!-- end ngSwitchWhen: -->\\n                <!-- ngSwitchWhen: CR -->\\n                <!-- ngSwitchWhen: RED -->\\n                <!-- ngSwitchWhen: V -->\\n                <!-- ngSwitchWhen: A -->\\n                <!-- ngSwitchWhen: P -->\\n                <!-- ngSwitchWhen: I -->\\n              </span>\\n            </div>\\n\\n            <div class=\\"roa-column-one-third\\">\\n              <!-- ngIf: ::transBalance.TypeKey.CodeID == 'P' -->\\n            </div>\\n\\n            <div class=\\"roa-column-one-third\\">\\n              <!-- ngIf: $scope.greaterThan(transBalance.PayorID,0) -->\\n              <!-- ngIf: transBalance.PayorID === 0 --><span ng-if=\\"transBalance.PayorID === 0\\" class=\\"ng-binding ng-scope\\">\\n                \\n              </span><!-- end ngIf: transBalance.PayorID === 0 -->\\n            </div>\\n          </div>\\n\\n          <div class=\\"roa-text-right\\">\\n            <span ng-switch=\\"\\" on=\\"::transBalance.TypeKey.CodeID\\">\\n              <!-- ngSwitchWhen: C --><span ng-switch-when=\\"C\\" class=\\"ng-binding ng-scope\\">\\n                200.00\\n              </span><!-- end ngSwitchWhen: -->\\n              <!-- ngSwitchWhen: CR -->\\n              <!-- ngSwitchWhen: RED -->\\n              <!-- ngSwitchWhen: V -->\\n              <!-- ngSwitchWhen: A -->\\n              <!-- ngSwitchWhen: P -->\\n              <!-- ngSwitchWhen: I -->\\n            </span>\\n          </div>\\n        </div><!-- end ngRepeat: transBalance in ::fee.CaseFeeParty.TransBalances.TransBalances -->\\n      </div>\\n\\n    </div><!-- end ngRepeat: fee in ::roaSection.financialInfo.CaseFees -->\\n\\n  </div><!-- end ngIf: ::roaSection.financialInfo.ShowFinancialSummaryCaseFees -->\\n\\n\\n  <!-- ngIf: ::roaSection.financialInfo.ShowFinancialSummaryRegister -->\\n\\n</div>\\n</ng-include>\\n    </md-card-content>\\n  </md-card>\\n</section><!-- end ngIf: roaSection.showSection --></div><!-- end ngIf: ::data.roaSections.financialSummarySection -->\\n      <!-- TODO: other sections here -->\\n\\n      <!-- ngInclude: undefined --><ng-include src=\\"::virtualDirectory +'Views/Shared/Footer.html'\\" flex=\\"100\\" layout=\\"row\\" class=\\"no-print ng-scope layout-row flex-100\\" style=\\"\\"><footer role=\\"contentinfo\\" flex=\\"\\" layout=\\"row\\" class=\\"ng-scope layout-row flex\\">\\n  <div show-sm=\\"\\" hide-gt-sm=\\"\\" layout-padding=\\"\\" layout-wrap=\\"\\" flex=\\"\\" class=\\"hide-gt-sm layout-padding layout-wrap show-sm flex\\">\\n    <div style=\\"margin-bottom:0.5rem;\\">\\n      <img class=\\"pull-left noprint\\" ng-src=\\"/app/RegisterOfActions/Content/tylerui/images/empowered.png\\" src=\\"/app/RegisterOfActions/Content/tylerui/images/empowered.png\\">\\n    </div>\\n    <div>\\n      <small class=\\"pull-left noprint ng-binding\\">© 2026 Tyler Technologies, Inc. | All Rights Reserved</small>\\n      <br>\\n      <small class=\\"pull-left noprint ng-binding\\">Version: 1.0.0.2608</small>\\n    </div>\\n  </div>\\n  <div layout=\\"row\\" hide-xs=\\"\\" hide-sm=\\"\\" layout-padding=\\"\\" layout-wrap=\\"\\" flex=\\"\\" class=\\"hide-sm hide-xs layout-padding layout-wrap layout-row flex\\">\\n    <div flex-sm=\\"100\\" flex-gt-sm=\\"50\\" class=\\"flex-sm-100 flex-gt-sm-50\\">\\n      <small class=\\"pull-left noprint ng-binding\\">© 2026 Tyler Technologies, Inc. | All Rights Reserved</small>\\n      <br>\\n      <small class=\\"pull-left noprint ng-binding\\">Version: 1.0.0.2608</small>\\n    </div>\\n    <div flex-sm=\\"100\\" flex-gt-sm=\\"50\\" class=\\"flex-sm-100 flex-gt-sm-50\\">\\n      <img class=\\"pull-right noprint\\" ng-src=\\"/app/RegisterOfActions/Content/tylerui/images/empowered.png\\" style=\\"width:auto\\" src=\\"/app/RegisterOfActions/Content/tylerui/images/empowered.png\\">\\n    </div>\\n  </div>\\n</footer></ng-include>\\n    </md-content><!-- end ngIf: ::!error.hasError -->\\n\\n    <!-- ngIf: error.hasError -->\\n  </div>\\n  \\n</div>\\n\\n<!-- Small Angular templates that are more efficient to have inline than making separate requests -->\\n\\n<script type=\\"text/ng-template\\" id=\\"IEPrintAllWarning\\" class=\\"ng-scope\\">\\n  <md-dialog class=\\"roa-warning-dialog\\">\\n    <md-toolbar class=\\"roa-section-header\\" tabindex=\\"0\\">\\n      <div class=\\"md-toolbar-tools\\">\\n        <h1>\\n          <span class=\\"header-text\\">Warning</span>\\n        </h1>\\n      </div>\\n    </md-toolbar>\\n    <md-card-content class=\\"roa-section-content\\">\\n      <p class=\\"roa-warning-paragraph\\">\\n        Attempting to {{::print ? 'Print All' : 'Expand'}} on larger cases in Internet Explorer can result in a long processing time or fail to load due to limitations of the browser.\\n      </p>\\n      <input id=\\"chkDoNotShowAgain\\" type=\\"checkbox\\" ng-model=\\"doNotShowAgain\\" class=\\"roa-warning-indent\\" /><label for=\\"chkDoNotShowAgain\\">Do not show me this message again.</label>\\n      <p class=\\"roa-warning-paragraph\\">\\n        Please select one of the following options.\\n      </p>\\n      <div class=\\"roa-text-center\\">\\n        <md-button ng-click=\\"closeDialog(true)\\">{{::print ? 'Print All' : 'Expand'}}</md-button>\\n        <md-button ng-click=\\"closeDialog(false)\\">Cancel</md-button>\\n      </div>\\n    </md-card-content>\\n\\n  </md-dialog>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-section-toolbar.template\\" class=\\"ng-scope\\">\\n  <md-toolbar class=\\"roa-section-header\\">\\n    <div class=\\"md-toolbar-tools\\">\\n      <md-icon ng-if=\\"$scope.selectedSection === $args.id\\"\\n               md-font-icon=\\"mdi-arrow-right-bold\\"\\n               class=\\"mdi roa-selected-section-icon\\"></md-icon>\\n      <h1>\\n        <span class=\\"header-text\\">{{$args.headerText}}</span>\\n      </h1>\\n    </div>\\n  </md-toolbar>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-header-data.template\\" class=\\"ng-scope\\">\\n  <div>\\n    <div class=\\"roa-header-sect-row\\" hide-xs layout=\\"row\\">\\n      <div flex class=\\"roa-label\\">\\n        {{label}}:\\n      </div>\\n      <div flex class=\\"roa-value\\" ng-transclude>\\n      </div>\\n    </div>\\n    <div class=\\"roa-header-sect-row\\" hide-gt-xs layout=\\"row\\">\\n      <div flex style=\\"text-align: left\\" class=\\"roa-label\\">\\n        {{label}}\\n      </div>\\n    </div>\\n    <div class=\\"roa-header-sect-row\\" hide-gt-xs layout=\\"row\\" >\\n      <div flex class=\\"roa-value\\" ng-transclude>\\n      </div>\\n    </div>\\n\\n  </div>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-data.template\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-data\\">\\n    <div class=\\"roa-label roa-inline roa-align-top\\" ng-if=\\"::label\\" ng-bind=\\"::label\\"></div>\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-if=\\"::value\\" ng-bind=\\"::value\\"></div>\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude></div>\\n  </div>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-charge-data-column.template\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-inline\\">\\n    <div class=\\"roa-text-bold\\" hide-gt-sm>\\n      {{$args.label}}\\n    </div>\\n    <div>\\n      {{$args.value}}\\n    </div>\\n  </div>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-event-date.template\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-event-date-col\\">\\n    <div ng-transclude ng-class=\\"::{'roa-text-strike': event.Event.IsDeleted}\\">\\n    </div>\\n  </div>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-event-timestamp-create.template\\" class=\\"ng-scope\\">\\n  <div ng-if=\\"::data.Options.ShowTimestampCreate == '1'\\">\\n    <roa-data  label=\\"Created:\\">\\n      {{::event.TimestampCreateIso8601 | date: $scope.dateFormat.Date + ' h:mm a'}}\\n    </roa-data>\\n  </div>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-event-index.template\\" class=\\"ng-scope\\">\\n  <div class=\\"roa-event-index\\">\\n    <div ng-if=\\"::data.Options.Index == '1'\\">\\n      <span ng-if=\\"::event.Event.EventVolume\\">Vol./Book {{::event.Event.EventVolume}}{{::event.Event.EventPage ? ',' : ''}}</span>\\n      <span ng-if=\\"::event.Event.EventVolume && event.Event.EventPage\\"><br /></span>\\n\\n      <span ng-if=\\"::event.Event.EventPage\\">Page {{::event.Event.EventPage}}{{::event.Event.NumberOfPages ? ', ' : ''}}</span>\\n      <span ng-if=\\"::event.Event.NumberOfPages\\">{{::event.Event.NumberOfPages}} pages</span>\\n\\n      <ng-transclude></ng-transclude>\\n    </div>\\n  </div>\\n</script>\\n\\n<script type=\\"text/ng-template\\" id=\\"roa-party-address.template\\" class=\\"ng-scope\\">\\n  <div ng-class=\\"party.CasePartyConnection.Inactive == 1 ? 'roa-text-italic' : ''\\">\\n    <div ng-if=\\"::address.ConfidentialAddress\\">\\n      ** Confidential Address **\\n    </div>\\n    <div ng-if=\\"::!(address.ConfidentialAddress)\\" ng-switch=\\"address.AddressType\\">\\n\\n      <div ng-switch-when=\\"0\\">\\n        <div ng-if=\\"::address.Block || address.PrefixDirection || address.Street || address.AddressSuffixKey || address.PostfixDirection\\">\\n          <span>{{::address.Block}}</span>\\n          <span>{{::address.PrefixDirection}}</span>\\n          <span>{{::address.Street}}</span>\\n          <span>{{::address.AddressSuffixKey}}</span>\\n          <span>{{::address.PostfixDirection}}</span>\\n        </div>\\n        <div ng-if=\\"::address.UnitKey\\">\\n          <span>{{::address.UnitKey}}</span>\\n          <span>{{::address.UnitNumber}}</span>\\n        </div>\\n        <div>\\n          <span ng-if=\\"::address.City\\">{{::address.City}},</span>\\n          <span>{{::address.State}}</span>\\n          <span>{{::address.PostalCode}}</span>\\n        </div>\\n      </div>\\n\\n      <div ng-switch-when=\\"1\\">\\n        <div ng-if=\\"::address.AddressLine1\\">\\n          {{::address.AddressLine1}}\\n        </div>\\n        <div ng-if=\\"::address.AddressLine2\\">\\n          {{::address.AddressLine2}}\\n        </div>\\n        <div ng-if=\\"::address.AddressLine3\\">\\n          {{::address.AddressLine3}}\\n        </div>\\n        <div>\\n          <span ng-if=\\"::address.City\\">{{::address.City}},</span>\\n          <span>{{::address.State}}</span>\\n          <span>{{::address.PostalCode}}</span>\\n        </div>\\n      </div>\\n\\n      <div ng-switch-when=\\"2\\">\\n        <div ng-if=\\"::address.AddressLine1\\">\\n          {{::address.AddressLine1}}\\n        </div>\\n        <div ng-if=\\"::address.AddressLine2\\">\\n          {{::address.AddressLine2}}\\n        </div>\\n        <div ng-if=\\"::address.AddressLine3\\">\\n          {{::address.AddressLine3}}\\n        </div>\\n        <div ng-if=\\"::address.AddressLine4\\">\\n          {{::address.AddressLine4}}\\n        </div>\\n      </div>\\n    </div>\\n  </div>\\n\\n</script>\\n</div>\\n<div class=\\"cfp-hotkeys-container fade ng-scope\\" ng-class=\\"{in: helpVisible}\\" style=\\"display: none;\\"><div class=\\"cfp-hotkeys\\"><!-- ngIf: !header --><h4 class=\\"cfp-hotkeys-title ng-binding ng-scope\\" ng-if=\\"!header\\">Keyboard Shortcuts:</h4><!-- end ngIf: !header --><!-- ngIf: header --><table><tbody><!-- ngRepeat: hotkey in hotkeys | filter:{ description: '!$$undefined$$' } --><tr ng-repeat=\\"hotkey in hotkeys | filter:{ description: '!$$undefined$$' }\\" class=\\"ng-scope\\"><td class=\\"cfp-hotkeys-keys\\"><!-- ngRepeat: key in hotkey.format() track by $index --><span ng-repeat=\\"key in hotkey.format() track by $index\\" class=\\"cfp-hotkeys-key ng-binding ng-scope\\">?</span><!-- end ngRepeat: key in hotkey.format() track by $index --></td><td class=\\"cfp-hotkeys-text ng-binding\\">Show / hide this help menu</td></tr><!-- end ngRepeat: hotkey in hotkeys | filter:{ description: '!$$undefined$$' } --></tbody></table><!-- ngIf: footer --><div class=\\"cfp-hotkeys-close\\" ng-click=\\"toggleCheatSheet()\\" role=\\"button\\" tabindex=\\"0\\">×</div></div></div></div>\\n\\n\\n  <!-- center for IE9 since it ignores bootstrap 3 -->\\n<center c