246	{"id":"fyUDpdgSKhTWVtCB","name":"NC Court Data Extractor v3 (Fixed)","active":false,"nodes":[{"parameters":{"multipleMethods":false,"httpMethod":"POST","path":"court-data","authentication":"none","responseMode":"responseNode","webhookNotice":"","options":{"rawBody":false}},"id":"2d0ca402-4a72-4f9c-bf8c-ee6098e514bd","name":"Webhook","type":"n8n-nodes-base.webhook","typeVersion":2,"position":[-752,112],"webhookId":"court-data-webhook"},{"parameters":{"mode":"runOnceForAllItems","language":"javaScript","jsCode":"// The webhook wraps everything in a 'body' object.\\n// This node flattens it so the HTML node can find the 'html' property.\\n\\nconst incoming = $input.first().json;\\n\\n// Handle both possible structures n8n might deliver\\nconst body = incoming.body || incoming;\\n\\nconst html = body.html || body.data || '';\\nconst source_url = body.source_url || 'Not provided';\\nconst submitted_at = body.submitted_at || new Date().toISOString();\\n\\nif (!html) {\\n  throw new Error('No HTML content found in request body. Make sure you are sending { html: \\"...\\", source_url: \\"...\\" }');\\n}\\n\\nreturn [{\\n  json: {\\n    html,\\n    source_url,\\n    submitted_at\\n  }\\n}];\\n","notice":""},"id":"57b8cd61-ae51-4edd-af8d-20e017d64d81","name":"Parse Body","type":"n8n-nodes-base.code","typeVersion":2,"position":[-528,112]},{"parameters":{"operation":"extractHtmlContent","sourceData":"json","dataPropertyName":"html","extractionValues":{"values":[{"key":"case_number","cssSelector":"span[ng-bind='::data.roaSections.caseSummary.headerInfo.CaseNumber']","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"court_name","cssSelector":"#roa-header .ng-binding:first-child","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"case_title","cssSelector":".roa-header-columns .roa-text-bold.ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"filed_date","cssSelector":"[label='Filed on'] .roa-value .ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"appear_by_date","cssSelector":"[label='Appear by'] .roa-value .ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"case_type","cssSelector":"tr[ng-if*='CaseType'] td.roa-value","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"case_status","cssSelector":"tr[ng-if*='CaseStatuses'] td.roa-value .roa-text-bold span.ng-binding:last-child","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"defendant_name","cssSelector":"tbody[ng-repeat*='connectionType'] td[ng-class*='roa-text-bold'].ng-binding","returnValue":"text","skipSelectors":"","returnArray":true},{"key":"defendant_address_line1","cssSelector":"div[ng-switch-when='1'] div[ng-if*='AddressLine1'].ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"defendant_city_state_zip","cssSelector":"div[ng-switch-when='1'] div span.ng-binding","returnValue":"text","skipSelectors":"","returnArray":true},{"key":"offense","cssSelector":"tr[hide-gt-sm] td[colspan='5'] div span.ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"citation_number","cssSelector":"roa-charge-data-column[data-value] div.ng-binding:not([hide-gt-sm])","returnValue":"text","skipSelectors":"","returnArray":true},{"key":"statute","cssSelector":"[label='Statute'] div.ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"offense_date","cssSelector":"[label='Offense Date'] div.ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"filing_agency","cssSelector":"div[label='Agency:'] .roa-value .ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"filing_agency_address","cssSelector":"div[ng-if*='FilingAgencyAddress'].ng-binding","returnValue":"text","skipSelectors":"","returnArray":true},{"key":"race","cssSelector":"div[ng-if*='party.Race'].ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"gender","cssSelector":"div[ng-if*='party.Gender'].ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"hearing_date","cssSelector":".roa-event-info-hearing-event .roa-event-date-col span.ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"hearing_type","cssSelector":".roa-event-info-hearing-event .roa-text-bold.ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"hearing_time","cssSelector":".roa-event-info-hearing-event .roa-indent span.ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"hearing_location","cssSelector":".roa-event-info-hearing-event .roa-indent-2.ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"financial_balance_due","cssSelector":".roa-finance-row.roa-text-bold .roa-text-right span.ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"financial_total_assessment","cssSelector":".roa-finance-row:nth-child(2) .roa-text-right.ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"assignment_court","cssSelector":"[label='Court'] .roa-value span.ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"assignment_date","cssSelector":"[label='Date Assigned'] .roa-value span.ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"source_url","cssSelector":"body","returnValue":"text","skipSelectors":"","returnArray":false}]},"options":{"trimValues":true,"cleanUpText":true}},"id":"06c5c7d6-7be7-4068-863f-a97668c28db1","name":"HTML Extract","type":"n8n-nodes-base.html","typeVersion":1.2,"position":[-320,112]},{"parameters":{"mode":"runOnceForAllItems","language":"javaScript","jsCode":"const d = $input.first().json;\\n\\n// Also pull source_url from the Parse Body node (2 nodes back)\\nlet source_url = 'Not provided';\\ntry {\\n  source_url = $('Parse Body').first().json.source_url || 'Not provided';\\n} catch(e) {}\\n\\n// Helper to clean whitespace\\nconst clean = (v) => {\\n  if (Array.isArray(v)) v = v[0];\\n  return (v || '').replace(/\\\\s+/g, ' ').trim();\\n};\\n\\n// These fields return arrays because multiple parties exist on the page\\n// Party order: [0]=State, [1]=Defendant, [2]=Complainant\\nconst names   = Array.isArray(d.defendant_name)         ? d.defendant_name         : [d.defendant_name];\\nconst cityArr = Array.isArray(d.defendant_city_state_zip) ? d.defendant_city_state_zip : [];\\nconst agencyAddrArr = Array.isArray(d.filing_agency_address) ? d.filing_agency_address : [];\\nconst citations = Array.isArray(d.citation_number)      ? d.citation_number        : [d.citation_number];\\n\\nconst defendant  = (names[1] || names[0] || '').replace(/\\\\s+/g,' ').trim();\\nconst complainant = (names[2] || '').replace(/\\\\s+/g,' ').trim();\\n\\n// City/State/ZIP — filter blanks, join\\nconst cityStateZip = cityArr\\n  .filter(v => v && v.trim())\\n  .map(v => v.trim())\\n  .join(' ')\\n  .replace(/\\\\s+/g,' ')\\n  .trim();\\n\\nconst agencyAddr = agencyAddrArr\\n  .filter(v => v && v.trim())\\n  .map(v => v.trim())\\n  .join(', ');\\n\\nconst citationStr = citations\\n  .filter(v => v && v.trim())\\n  .map(v => v.trim())\\n  .join(', ');\\n\\nreturn [{\\n  json: {\\n    'Case Number':           clean(d.case_number),\\n    'Court':                 clean(d.court_name),\\n    'Case Title':            clean(d.case_title),\\n    'Filed Date':            clean(d.filed_date),\\n    'Appear By Date':        clean(d.appear_by_date),\\n    'Case Type':             clean(d.case_type),\\n    'Case Status':           clean(d.case_status),\\n    'Defendant Name':        defendant,\\n    'Complainant':           complainant,\\n    'Address Line 1':        clean(d.defendant_address_line1),\\n    'City / State / ZIP':    cityStateZip,\\n    'Offense':               clean(d.offense),\\n    'Citation Number':       citationStr,\\n    'Statute':               clean(d.statute),\\n    'Offense Date':          clean(d.offense_date),\\n    'Filing Agency':         clean(d.filing_agency),\\n    'Filing Agency Address': agencyAddr,\\n    'Race':                  clean(d.race),\\n    'Gender':                clean(d.gender),\\n    'Hearing Date':          clean(d.hearing_date),\\n    'Hearing Type':          clean(d.hearing_type),\\n    'Hearing Time':          clean(d.hearing_time),\\n    'Hearing Location':      clean(d.hearing_location),\\n    'Balance Due':           clean(d.financial_balance_due),\\n    'Total Assessment':      clean(d.financial_total_assessment),\\n    'Assignment Court':      clean(d.assignment_court),\\n    'Assignment Date':       clean(d.assignment_date),\\n    'Source URL':            source_url,\\n    'Date Collected':        new Date().toISOString().replace('T',' ').substring(0,19)\\n  }\\n}];\\n","notice":""},"id":"466f3efd-061e-4bdc-a8cf-cf47c1743c68","name":"Clean & Structure","type":"n8n-nodes-base.code","typeVersion":2,"position":[-96,112]},{"parameters":{"generalNotice":"","respondWith":"json","webhookNotice":"","responseBody":"={{ JSON.stringify({ success: true, message: 'Data extracted and saved!', data: $json }) }}","options":{}},"id":"6a16bcb3-65df-49ce-a224-59a5d8ad3aa6","name":"Respond to Webhook","type":"n8n-nodes-base.respondToWebhook","typeVersion":1.1,"position":[128,-32]},{"parameters":{"preBuiltAgentsCalloutGoogleSheets":"","authentication":"oAuth2","resource":"sheet","operation":"append","documentId":{"__rl":true,"value":"1-uq5Wai-7Zct49uc5a88Tf_s5gZsA3nUHdDV3e7PW3w","mode":"list","cachedResultName":"NC_Court_Data_Log","cachedResultUrl":"https://docs.google.com/spreadsheets/d/1-uq5Wai-7Zct49uc5a88Tf_s5gZsA3nUHdDV3e7PW3w/edit?usp=drivesdk"},"sheetName":{"__rl":true,"value":1524302678,"mode":"list","cachedResultName":"Case Data","cachedResultUrl":"https://docs.google.com/spreadsheets/d/1-uq5Wai-7Zct49uc5a88Tf_s5gZsA3nUHdDV3e7PW3w/edit#gid=1524302678"},"columns":{"mappingMode":"autoM