ngIf: roaSection.showSection --><section ng-if=\\"roaSection.showSection\\" class=\\"ng-scope\\">\\n  <md-card class=\\"no-print-section-border md-tyler-default-theme-theme\\">\\n    <md-toolbar class=\\"roa-section-header md-tyler-default-theme-theme\\" data-header-text=\\"Assignment Information\\" id=\\"assignment-info\\" ng-class=\\"::{'no-print-section-header': skipHeader}\\">\\n    <div class=\\"md-toolbar-tools\\">\\n      <!-- ngIf: $scope.selectedSection === $args.id -->\\n      <h1>\\n        <span class=\\"header-text ng-binding\\">Assignment Information</span>\\n      </h1>\\n    </div>\\n  </md-toolbar>\\n    <md-card-content class=\\"roa-section-content\\">\\n      <!-- In general, the sections will work like this:\\n      - Initial load: showSection = false. nothing shows (exception - basic case info always has showSection = true and sets loading = true to show an indicator)\\n      - Error on load: showSection = true, loading = false, error = error text. Section is shown with error text.\\n      - Load success, but no data: showSection = false. nothing shows\\n      - Data exists: showSection = true, loading = false, error = null.\\n      -->\\n      <!-- ngIf: roaSection.loading -->\\n      <!-- ngIf: roaSection.error -->\\n      <!-- ngInclude: undefined --><ng-include ng-show=\\"!roaSection.loading &amp;&amp; !roaSection.error\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + roaSection.template\\" class=\\"ng-scope\\" aria-hidden=\\"false\\" style=\\"\\"><div class=\\"ng-scope\\">\\n  <div layout-gt-sm=\\"row\\" class=\\"layout-gt-sm-row\\">\\n    <div flex=\\"10\\" class=\\"flex-10\\"></div>\\n    <div flex=\\"90\\" class=\\"flex-90\\">\\n\\n      <div class=\\"roa-text-bold\\">Current Case Assignment</div>\\n\\n\\n      <div class=\\"roa-data-table roa-pad-bottom\\">\\n        <div class=\\"roa-data ng-isolate-scope\\" label=\\"Case Number\\">\\n    <!-- ngIf: ::label --><div class=\\"roa-label roa-inline roa-align-top ng-binding ng-scope\\" ng-if=\\"::label\\" ng-bind=\\"::label\\">Case Number</div><!-- end ngIf: ::label -->\\n    <!-- ngIf: ::value -->\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude=\\"\\"><span class=\\"ng-binding ng-scope\\">\\n          25IF012559-590\\n        </span></div>\\n  </div>\\n\\n        <div class=\\"roa-data ng-isolate-scope\\" label=\\"Court\\">\\n    <!-- ngIf: ::label --><div class=\\"roa-label roa-inline roa-align-top ng-binding ng-scope\\" ng-if=\\"::label\\" ng-bind=\\"::label\\">Court</div><!-- end ngIf: ::label -->\\n    <!-- ngIf: ::value -->\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude=\\"\\"><span class=\\"ng-binding ng-scope\\">\\n          Mecklenburg District Court\\n        </span></div>\\n  </div>\\n\\n        <!-- ngIf: ::data.Options.CaseAssignmentTimestamp == '1' -->\\n\\n        <!-- ngIf: ::data.Options.CaseAssignmentTimestamp != '1' --><div class=\\"roa-data ng-scope ng-isolate-scope\\" label=\\"Date Assigned\\" ng-if=\\"::data.Options.CaseAssignmentTimestamp != '1'\\">\\n    <!-- ngIf: ::label --><div class=\\"roa-label roa-inline roa-align-top ng-binding ng-scope\\" ng-if=\\"::label\\" ng-bind=\\"::label\\">Date Assigned</div><!-- end ngIf: ::label -->\\n    <!-- ngIf: ::value -->\\n    <div class=\\"roa-value roa-inline roa-indent\\" ng-transclude=\\"\\"><span class=\\"ng-binding ng-scope\\">\\n          10/14/2025\\n        </span></div>\\n  </div><!-- end ngIf: ::data.Options.CaseAssignmentTimestamp != '1' -->\\n\\n        <!-- ngIf: ::roaSection.assignmentInfo.CurrentCaseAssignment.JudicialOfficer -->\\n\\n        <!-- ngIf: ::roaSection.assignmentInfo.CurrentMagistrateAssignment.Description -->\\n      </div>\\n\\n      <!-- ngRepeat: assignment in ::roaSection.assignmentInfo.CaseAssignmentHistory -->\\n\\n    </div>\\n  </div>\\n\\n  <!-- ngRepeat: assignment in ::roaSection.assignmentInfo.MagistrateAssignmentHistory -->\\n\\n\\n  <!-- ngRepeat: officer in ::roaSection