247	{"id":"fyUDpdgSKhTWVtCB","name":"NC Court Data Extractor v3 (Fixed)","active":false,"nodes":[{"parameters":{"multipleMethods":false,"httpMethod":"POST","path":"court-data","authentication":"none","responseMode":"responseNode","webhookNotice":"","options":{"rawBody":false}},"id":"2d0ca402-4a72-4f9c-bf8c-ee6098e514bd","name":"Webhook","type":"n8n-nodes-base.webhook","typeVersion":2,"position":[-752,112],"webhookId":"court-data-webhook"},{"parameters":{"mode":"runOnceForAllItems","language":"javaScript","jsCode":"// The webhook wraps everything in a 'body' object.\\n// This node flattens it so the HTML node can find the 'html' property.\\n\\nconst incoming = $input.first().json;\\n\\n// Handle both possible structures n8n might deliver\\nconst body = incoming.body || incoming;\\n\\nconst html = body.html || body.data || '';\\nconst source_url = body.source_url || 'Not provided';\\nconst submitted_at = body.submitted_at || new Date().toISOString();\\n\\nif (!html) {\\n  throw new Error('No HTML content found in request body. Make sure you are sending { html: \\"...\\", source_url: \\"...\\" }');\\n}\\n\\nreturn [{\\n  json: {\\n    html,\\n    source_url,\\n    submitted_at\\n  }\\n}];\\n","notice":""},"id":"57b8cd61-ae51-4edd-af8d-20e017d64d81","name":"Parse Body","type":"n8n-nodes-base.code","typeVersion":2,"position":[-528,112]},{"parameters":{"operation":"extractHtmlContent","sourceData":"json","dataPropertyName":"html","extractionValues":{"values":[{"key":"case_number","cssSelector":"span[ng-bind='::data.roaSections.caseSummary.headerInfo.CaseNumber']","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"court_name","cssSelector":"#roa-header .ng-binding:first-child","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"case_title","cssSelector":".roa-header-columns .roa-text-bold.ng-binding","returnValue":"text","skipSelectors":"","returnArray":false},{"key":"filed_date","cssSelector":"[label='Filed on'] .roa-value .ng-binding","