de><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: ::roaSection.dispositionInfo.ShowDispositions -->\\n</ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: ::roaSection.warrantInfo.ShowWarrants -->\\n</ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: ::roaSection.bondInfo.ShowBonds --></ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates --><!-- ngInclude: undefined --><ng-include ng-repeat=\\"templateName in roaSection.subSectionTemplates\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + templateName\\" class=\\"ng-scope\\"><!-- ngIf: data.Options.ShowGroundsForDivorce == '1' && roaSection.divorceInfo != null && roaSection.divorceInfo != undefined && roaSection.divorceInfo.GroundsForDivorce.length > 0 --></ng-include><!-- end ngRepeat: templateName in roaSection.subSectionTemplates -->\\n</div>\\n\\n</ng-include>\\n    </md-card-content>\\n  </md-card>\\n</section><!-- end ngIf: roaSection.showSection --></div><!-- end ngIf: ::data.roaSections.caseInformation -->\\n      <!-- ngIf: ::data.roaSections.assignmentInformation --><div ng-include-template=\\"Areas/RegisterOfActions/Views/ROA/Templates/RoA_Section_Template.html\\" ng-include-variables=\\"{roaSection: data.roaSections.assignmentInformation, data: data, $scope: this}\\" ng-if=\\"::data.roaSections.assignmentInformation\\" class=\\"ng-scope ng-isolate-scope\\" style=\\"\\"><!-- ngIf: roaSection.showSection --><section ng-if=\\"roaSection.showSection\\" class=\\"ng-scope\\">\\n  <md-card class=\\"no-print-section-border md-tyler-default-theme-theme\\">\\n    <md-toolbar class=\\"roa-section-header md-tyler-default-theme-theme\\" data-header-text=\\"Assignment Information\\" id=\\"assignment-info\\" ng-class=\\"::{'no-print-section-header': skipHeader}\\">\\n    <div class=\\"md-toolbar-tools\\">\\n      <!-- ngIf: $scope.selectedSection === $args.id -->\\n      <h1>\\n        <span class=\\"header-text ng-binding\\">Assignment Information</span>\\n      </h1>\\n    </div>\\n  </md-toolbar>\\n    <md-card-content class=\\"roa-section-content\\">\\n      <!-- In general, the sections will work like this:\\n      - Initial load: showSection = false. nothing shows (exception - basic case info always has showSection = true and sets loading = true to show an indicator)\\n      - Error on load: showSection = true, loading = false, error = error text. Section is shown with error text.\\n      - Load success, but no data: showSection = false. nothing shows\\n      - Data exists: showSection = true, loading = false, error = null.\\n      -->\\n      <!-- ngIf: roaSection.loading -->\\n      <!-- ngIf: roaSection.error -->\\n      <!-- ngInclude: undefined --><ng-include ng-show=\\"!roaSection.loading &amp;&amp; !roaSection.error\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + roaSection.template\\" class=\\"ng-scope\\" aria-hidden=\\"false\\" style=\\"\\"><div class=\\"ng-scope\\">\\n  <div layout-gt-sm=\\"row\\" class=\\"layout-gt-sm-row\\">\\n    <div flex=\\"10\\" class=\\"flex-10\\"></div>\\n    <div flex=\\"90\\" class=\\"flex-90\\">\\n\\n      <div class=\\"roa-text-bold\\">Current Case Assignment</div>\\n\\n\\n      <div class=\\"roa-