ull.\\n      -->\\n      <!-- ngIf: roaSection.loading -->\\n      <!-- ngIf: roaSection.error -->\\n      <!-- ngInclude: undefined --><ng-include ng-show=\\"!roaSection.loading &amp;&amp; !roaSection.error\\" src=\\"::virtualDirectory + 'Areas/RegisterOfActions/Views/ROA/Templates/' + roaSection.template\\" class=\\"ng-scope\\" aria-hidden=\\"false\\" style=\\"\\"><table class=\\"roa-table td-pad-5 ng-scope\\">\\n  <colgroup>\\n    <col style=\\"width:80px\\"> <!-- connection type -->\\n    <col> <!-- party info -->\\n    <col> <!-- attorney info -->\\n  </colgroup>\\n  <!-- ngRepeat: connectionType in roaSection.casePartyConnectionsTypes --><tbody ng-repeat=\\"connectionType in roaSection.casePartyConnectionsTypes\\" class=\\"ng-scope\\">\\n\\n  <!-- ngIf: ::$first && roaSection.partyInfo.ShowAttorneyHeader && roaSection.partyInfo.ShowOnlyLeadAttornies -->\\n  \\n  <!-- ngRepeat: party in ::roaSection.getPartiesByConnectionTypeId(connectionType.codeId) --><tr ng-repeat=\\"party in ::roaSection.getPartiesByConnectionTypeId(connectionType.codeId)\\" class=\\"roa-party-row roa-pad-b-10 ng-scope\\">\\n\\n    <td class=\\"roa-text-bold\\">\\n      <!-- ngIf: ::$first --><div ng-if=\\"::$first\\" class=\\"ng-binding ng-scope\\">State</div><!-- end ngIf: ::$first -->\\n    </td>\\n    <!-- ngIf: ::!(roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount)) -->\\n    <!-- ngIf: ::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount) --><td ng-if=\\"::roaSection.maxPartyCount == -1 || $scope.lessThan($index, roaSection.maxPartyCount)\\" class=\\"ng-scope\\">\\n      <table class=\\"roa-table roa-inline\\">\\n        <tbody><tr>\\n          <!-- ngIf: ::party.PriorJailings -->\\n          <!-- ngIf: ::party.InJail -->\\n          <!-- ngIf: ::party.JailWeekenderIn -->\\n          <!-- ngIf: ::party.JailWeekenderOut -->\\n          <!-- ngIf: ::party.HasActiveWarrants && data.WarrantInformation.ShowWarrantHeaderIcon -->\\n          <td ng-class=\\"::roaSection.isInactive(party, connectionType.codeId) ? 'roa-text-italic' : 'roa-text-bold'\\" class=\\"ng-binding roa-text-bold\\">\\n            STATE OF NORTH CAROLINA \\n          </td>\\n        </tr>\\n      </tbody></table>\\n\\n      <!-- ngIf: ::party.AdditionalNames.length -->\\n\\n\\n      <!-- ngIf: ::party.PartyStyle -->\\n\\n      <!-- ngRepeat: address in ::party.Addresses --><!-- ngIf: ::party.Addresses.length --><div ng-if=\\"::party.Addresses.length\\" class=\\"roa-indent ng-scope\\" ng-repeat=\\"address in ::party.Addresses\\">\\n        <div ng-class=\\"party.CasePartyConnection.Inactive == 1 ? 'roa-text-italic' : ''\\">\\n    <!-- ngIf: ::address.ConfidentialAddress -->\\n    <!-- ngIf: ::!(address.ConfidentialAddress) --><div ng-if=\\"::!(address.ConfidentialAddress)\\" ng-switch=\\"address.AddressType\\" class=\\"ng-scope\\">\\n\\n      <!-- ngSwitchWhen: 0 -->\\n\\n      <!-- ngSwitchWhen: 1 -->\\n\\n      <!-- ngSwitchWhen: 2 --><div ng-switch-when=\\"2\\" class=\\"ng-scope\\">\\n        <!-- ngIf: ::address.AddressLine1 --><div ng-if=\\"::address.AddressLine1\\" class=\\"ng-binding ng-scope\\">\\n          State of North Carolina\\n        </div><!-- end ngIf: ::address.AddressLine1 -->\\n        <!-- ngIf: ::address.AddressLine2 -->\\n        <!-- ngIf: ::address.AddressLine3 -->\\n        <!-- ngIf: ::address.AddressLine4 -->\\n      </div><!-- end ngSwitchWhen: -->\\n    </div><!-- end ngIf: ::!(address.ConfidentialAddress) -->\\n  </div>\\n      </div><!-- end ngIf: ::party.Addresses.length --><!-- end ngRepeat: address in ::party.Addresses -->\\n\\n      <div class=\\"roa-indent\\" ng-class=\\"::roaSection.isInactive(party, connectionType.codeId) ? 'roa-text-italic' : ''\\">\\n        <!-- ngIf: ::party.Race --><div ng-if=\\"::party.Race\\" class=\\"ng-binding ng-scope\\">\\n          Other\\n        </div><!-- end ngIf: ::party.Race -->\\n\\n        <!-- ngIf: ::party.Gender -->\\n\\n        <div>\\n    