80daf1e9-1c56-42ba-8287-d794b9c04a63	w1gXNIGwt0RwjuTC	Fernan Bambico	2026-05-10 19:30:12.523+00	2026-05-10 19:30:12.523+00	[{"parameters":{"httpMethod":"POST","path":"cold-call-trigger","responseMode":"responseNode","options":{}},"id":"d2feb480-2812-43e1-8fa5-45085b6bbbcf","name":"Webhook — UI Trigger","type":"n8n-nodes-base.webhook","typeVersion":1,"position":[-512,16],"webhookId":"abebecdf-922b-4fa7-b4a3-f44dcf00bdb6","notes":"TRIGGER A: Manual UI or front-end form. Accepts: { phone, name?, address?, leadSource?, tags? }"},{"parameters":{"jsCode":"// Normalize to E.164 format and basic validation\\nconst raw = $input.first().json.body.phone || $input.first().json.phone || '';\\n\\n// Strip all non-digit characters except leading +\\nlet phone = raw.toString().trim();\\nlet digits = phone.replace(/\\\\D/g, '');\\n\\n// Handle US numbers without country code\\nif (digits.length === 10) digits = '1' + digits;\\n\\n// Validate length (E.164 max 15 digits)\\nif (digits.length < 7 || digits.length > 15) {\\n  throw new Error(`Invalid phone number: ${raw}`);\\n}\\n\\nconst normalized = '+' + digits;\\nconst name = $input.first().json.body.name || $input.first().json.name || 'Unknown';\\nconst address = $input.first().json.body.address || $input.first().json.address || '';\\nconst leadSource = $input.first().json.body.leadSource || 'AI Cold Caller';\\nconst tags = $input.first().json.body.tags || [];\\n\\nreturn [{\\n  json: {\\n    phone: normalized,\\n    name,\\n    firstName: name.split(' ')[0] || name,\\n    lastName: name.split(' ').slice(1).join(' ') || '',\\n    address,\\n    leadSource,\\n    tags,\\n    rawInput: $input.first().json.body\\n  }\\n}];"},"id":"2a6b2303-3953-4fc0-bf8d-6bd873e56c35","name":"Code — Validate & Normalize Phone","type":"n8n-nodes-base.code","typeVersion":2,"position":[-256,16],"notes":"Normalizes phone to E.164 (+1XXXXXXXXXX). Throws on invalid input which routes to the error handler."},{"parameters":{"method":"POST","url":"https://services.leadconnectorhq.com/contacts/upsert","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Authorization","value":"Bearer YOUR_GHL_PRIVATE_TOKEN"},{"name":"Version","value":"2021-07-28"},{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"specifyBody":"json","jsonBody":"={\\n  \\"locationId\\": \\"YOUR_GHL_LOCATION_ID\\",\\n  \\"phone\\": \\"{{ $json.phone }}\\",\\n  \\"firstName\\": \\"{{ $json.firstName }}\\",\\n  \\"lastName\\": \\"{{ $json.lastName }}\\",\\n  \\"address1\\": \\"{{ $json.address }}\\",\\n  \\"source\\": \\"{{ $json.leadSource }}\\",\\n  \\"tags\\": {{ JSON.stringify([...$json.tags, 'cold-call-queue', 'ai-dialer']) }}\\n}","options":{"timeout":10000}},"id":"c7598faa-29f1-4949-8aa2-4270cbf976f5","name":"GHL — Upsert Contact","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[0,16],"notes":"GHL Upsert: creates contact if phone doesn't exist, updates if it does. Returns contact.id for all downstream nodes."},{"parameters":{"conditions":{"conditions":[{"leftValue":"={{ $json.contact.id }}","rightValue":"","operator":{"type":"string","operation":"notEmpty"}}]},"options":{}},"id":"733c3b20-07a4-43f6-98d9-2fdab1a0ce52","name":"IF — Contact Valid?","type":"n8n-nodes-base.if","typeVersion":2,"position":[224,16],"notes":"TRUE: GHL returned a valid contact ID → proceed. FALSE: GHL error → route to error handler."},{"parameters":{"method":"POST","url":"https://api.retellai.com/v2/create-phone-call","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Authorization","value":"Bearer YOUR_RETELL_API_KEY"},{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"specifyBody":"json","jsonBody":"={\\n  \\"from_number\\": \\"+1YOUR_TWILIO_NUMBER\\",\\n  \\"to_number\\": \\"{{ $('Code — Validate & Normalize Phone').item.json.phone }}\\",\\n  \\"agent_id\\": \\"YOUR_RETELL_AGENT_ID\\",\\n  \\"retell_llm_dynamic_variables\\": {\\n    \\"lead_name\\": \\"{{ $('Code — Validate & Normalize Phone').item.json.firstName }}\\",\\n    \\"lead_address\\": \\"{{ $('Code — Validate & Normalize Phone').item.json.address }}\\",\\n    \\"lead_source\\": \\"{{ $('Code — Validate & Normalize Phone').item.json.leadSource }}\\"\\n  },\\n  \\"metadata\\": {\\n    \\"ghl_contact_id\\": \\"{{ $('GHL — Upsert Contact').item.json.contact.id }}\\",\\n    \\"ghl_location_id\\": \\"YOUR_GHL_LOCATION_ID\\",\\n    \\"lead_name\\": \\"{{ $('Code — Validate & Normalize Phone').item.json.name }}\\",\\n    \\"lead_phone\\": \\"{{ $('Code — Validate & Normalize Phone').item.json.phone }}\\",\\n    \\"lead_address\\": \\"{{ $('Code — Validate & Normalize Phone').item.json.address }}\\",\\n    \\"attempt_number\\": 1\\n  }\\n}","options":{"timeout":15000}},"id":"bcf541bc-e947-479d-b98f-92f435e8affb","name":"Retell AI — Create Outbound Call","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[464,16],"notes":"Fires the outbound call. retell_llm_dynamic_variables are injected into your Retell prompt template so the AI can use the lead's name and address naturally."},{"parameters":{"respondWith":"json","responseBody":"={\\n  \\"status\\": \\"ok\\",\\n  \\"message\\": \\"Call initiated\\",\\n  \\"ghl_contact_id\\": \\"{{ $('GHL — Upsert Contact').item.json.contact.id }}\\",\\n  \\"phone\\": \\"{{ $('Code — Validate & Normalize Phone').item.json.phone }}\\"\\n}","options":{}},"id":"ee91b824-a662-4a98-83c2-e56b7950ce87","name":"Respond — Call Initiated","type":"n8n-nodes-base.respondToWebhook","typeVersion":1,"position":[688,16]},{"parameters":{"method":"POST","url":"https://hooks.slack.com/services/YOUR_SLACK_WEBHOOK_URL","sendBody":true,"specifyBody":"json","jsonBody":"={\\n  \\"text\\": \\":x: *Cold Call Error*\\\\nPhone: {{ $('Code — Validate & Normalize Phone').item?.json?.phone || 'unknown' }}\\\\nError: {{ $json.message || 'GHL contact creation failed' }}\\\\nTime: {{ $now.toISO() }}\\"\\n}","options":{}},"id":"927db699-8312-4597-b56a-60aa6eff538e","name":"Error Handler — Log & Notify","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[160,336],"notes":"Catches all errors: invalid phone, GHL API failures, Retell timeouts. Sends Slack alert. Expand this to write to an error log Google Sheet if needed."},{"parameters":{"httpMethod":"POST","path":"retell-call-result","responseMode":"lastNode","options":{}},"id":"da2f5efd-2d8f-462b-8fec-24e62ddc0a13","name":"Webhook — Retell Call Result","type":"n8n-nodes-base.webhook","typeVersion":1,"position":[1216,-112],"webhookId":"67cb7c25-b34a-453b-bd75-5ff37cbadf35","notes":"SECOND WEBHOOK — set this URL as post_call_webhook in Retell agent settings.\\nURL: https://YOUR-N8N-DOMAIN/webhook/retell-call-result\\n\\nRetell sends: call_id, call_status, call_analysis, transcript, start_timestamp, end_timestamp, metadata (your lead data), custom_analysis_data"},{"parameters":{"jsCode":"// Parse Retell webhook payload and normalize outcome\\nconst payload = $input.first().json.body || $input.first().json;\\n\\nconst callId = payload.call_id || '';\\nconst callStatus = payload.call_status || 'unknown'; // ended, error, registered\\nconst analysis = payload.call_analysis || {};\\nconst transcript = payload.transcript || '';\\nconst transcriptObject = payload.transcript_object || [];\\nconst durationMs = payload.end_timestamp - payload.start_timestamp || 0;\\nconst durationSec = Math.round(durationMs / 1000);\\nconst metadata = payload.metadata || {};\\nconst customData = payload.custom_analysis_data || {};\\n\\n// Normalize outcome to one of: interested | not_interested | voicemail | no_answer | error\\nlet outcome = 'unknown';\\nif (analysis.call_successful === true) {\\n  outcome = 'interested';\\n} else if (callStatus === 'error') {\\n  outcome = 'error';\\n} else if (transcript.toLowerCase().includes('voicemail') || transcript.toLowerCase().includes('leave a message')) {\\n  outcome = 'voicemail';\\n} else if (durationSec < 8) {\\n  outcome = 'no_answer';\\n} else {\\n  outcome = 'not_interested';\\n}\\n\\nconst summary = analysis.call_summary || customData.summary || transcript.slice(0, 300);\\n\\nreturn [{\\n  json: {\\n    callId,\\n    callStatus,\\n    outcome,\\n    summary,\\n    transcript,\\n    transcriptObject,\\n    durationSec,\\n    ghlContactId: metadata.ghl_contact_id || '',\\n    ghlLocationId: metadata.ghl_location_id || 'YOUR_GHL_LOCATION_ID',\\n    leadName: metadata.lead_name || '',\\n    leadPhone: metadata.lead_phone || '',\\n    leadAddress: metadata.lead_address || '',\\n    attemptNumber: metadata.attempt_number || 1,\\n    customData,\\n    rawPayload: payload\\n  }\\n}];"},"id":"ff321d40-c5a8-4953-bd1a-550b270705e9","name":"Code — Parse Retell Outcome","type":"n8n-nodes-base.code","typeVersion":2,"position":[1216,112],"notes":"Parses Retell webhook. Normalizes outcome into: interested | not_interested | voicemail | no_answer | error. Extracts all metadata needed for GHL updates."},{"parameters":{"mode":"expression","output":"={{ $json.outcome }}"},"id":"6b4a3360-74fa-45d4-80cd-4e774a8d54a5","name":"Switch — Route by Outcome","type":"n8n-nodes-base.switch","typeVersion":3,"position":[1232,400],"notes":"Routes to different GHL update paths based on normalized outcome."},{"parameters":{"method":"PUT","url":"=https://services.leadconnectorhq.com/contacts/{{ $json.ghlContactId }}","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Authorization","value":"Bearer YOUR_GHL_PRIVATE_TOKEN"},{"name":"Version","value":"2021-07-28"},{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"specifyBody":"json","jsonBody":"={\\n  \\"tags\\": [\\"hot-lead\\", \\"ai-called\\", \\"interested\\", \\"needs-followup\\"],\\n  \\"customFields\\": [\\n    { \\"id\\": \\"call_outcome\\", \\"value\\": \\"Interested\\" },\\n    { \\"id\\": \\"last_call_date\\", \\"value\\": \\"{{ $now.toISO() }}\\" },\\n    { \\"id\\": \\"call_duration_sec\\", \\"value\\": \\"{{ $json.durationSec }}\\" },\\n    { \\"id\\": \\"call_summary\\", \\"value\\": \\"{{ $json.summary }}\\" }\\n  ]\\n}","options":{}},"id":"4fbae84f-e885-4557-b0a5-8735f7b66fcb","name":"GHL — Update Contact (Interested)","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[1008,592]},{"parameters":{"method":"PUT","url":"=https://services.leadconnectorhq.com/contacts/{{ $json.ghlContactId }}","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Authorization","value":"Bearer YOUR_GHL_PRIVATE_TOKEN"},{"name":"Version","value":"2021-07-28"},{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"specifyBody":"json","jsonBody":"={\\n  \\"tags\\": [\\"ai-called\\", \\"not-interested\\", \\"cold-lead\\"],\\n  \\"customFields\\": [\\n    { \\"id\\": \\"call_outcome\\", \\"value\\": \\"Not Interested\\" },\\n    { \\"id\\": \\"last_call_date\\", \\"value\\": \\"{{ $now.toISO() }}\\" },\\n    { \\"id\\": \\"call_duration_sec\\", \\"value\\": \\"{{ $json.durationSec }}\\" }\\n  ]\\n}","options":{}},"id":"d442c10d-8e66-4b42-b5e5-50fc9aa7b313","name":"GHL — Update Contact (Not Interested)","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[1776,144]},{"parameters":{"method":"PUT","url":"=https://services.leadconnectorhq.com/contacts/{{ $json.ghlContactId }}","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Authorization","value":"Bearer YOUR_GHL_PRIVATE_TOKEN"},{"name":"Version","value":"2021-07-28"},{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"specifyBody":"json","jsonBody":"={\\n  \\"tags\\": [\\"ai-called\\", \\"voicemail-left\\", \\"retry-pending\\"],\\n  \\"customFields\\": [\\n    { \\"id\\": \\"call_outcome\\", \\"value\\": \\"Voicemail\\" },\\n    { \\"id\\": \\"last_call_date\\", \\"value\\": \\"{{ $now.toISO() }}\\" },\\n    { \\"id\\": \\"call_attempts\\", \\"value\\": \\"{{ $json.attemptNumber }}\\" }\\n  ]\\n}","options":{}},"id":"cd5dd699-4f18-4c30-903d-2f90d5370c18","name":"GHL — Update Contact (Voicemail)","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[1520,560]},{"parameters":{"method":"PUT","url":"=https://services.leadconnectorhq.com/contacts/{{ $json.ghlContactId }}","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Authorization","value":"Bearer YOUR_GHL_PRIVATE_TOKEN"},{"name":"Version","value":"2021-07-28"},{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"specifyBody":"json","jsonBody":"={\\n  \\"tags\\": [\\"ai-called\\", \\"no-answer\\", \\"retry-pending\\"],\\n  \\"customFields\\": [\\n    { \\"id\\": \\"call_outcome\\", \\"value\\": \\"No Answer\\" },\\n    { \\"id\\": \\"last_call_date\\", \\"value\\": \\"{{ $now.toISO() }}\\" },\\n    { \\"id\\": \\"call_attempts\\", \\"value\\": \\"{{ $json.attemptNumber }}\\" }\\n  ]\\n}","options":{}},"id":"bc367b26-1d9e-4dfc-a5c7-d4b0b45250ff","name":"GHL — Update Contact (No Answer)","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[1744,336]},{"parameters":{"method":"POST","url":"https://services.leadconnectorhq.com/opportunities/","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Authorization","value":"Bearer YOUR_GHL_PRIVATE_TOKEN"},{"name":"Version","value":"2021-07-28"},{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"specifyBody":"json","jsonBody":"={\\n  \\"pipelineId\\": \\"YOUR_GHL_PIPELINE_ID\\",\\n  \\"locationId\\": \\"YOUR_GHL_LOCATION_ID\\",\\n  \\"name\\": \\"AI Call — {{ $json.leadName }} — {{ $now.toFormat('yyyy-MM-dd') }}\\",\\n  \\"pipelineStageId\\": \\"YOUR_STAGE_ID_INTERESTED\\",\\n  \\"contactId\\": \\"{{ $json.ghlContactId }}\\",\\n  \\"status\\": \\"open\\",\\n  \\"monetaryValue\\": 0,\\n  \\"assignedTo\\": \\"YOUR_GHL_USER_ID\\"\\n}","options":{}},"id":"4ece3f4e-86d5-4e65-8bbc-4f423b54947a","name":"GHL — Create Opportunity (Interested only)","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[1008,784],"notes":"Creates an Opportunity in your pipeline only for interested leads. Maps to 'AI Interested' stage."},{"parameters":{"method":"P